export enum UserRole {
  ADMIN = 'ADMIN',
  AGENT = 'AGENT',
}

export enum UserStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  BLOCKED = 'BLOCKED',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  area?: string;
  phone?: string;
  password?: string; // In a real app, this would be hashed
}

export interface Patient {
  id: string;
  familyId: string;
  name: string;
  birthDate: string;
  susNumber: string;
  isPregnant: boolean;
  isBedridden: boolean;
  isDiabetic: boolean;
  isHypertensive: boolean;
  hasPsychologicalIssues: boolean;
  medications: string[];
  addictions: string[];
}

export interface Family {
  id: string;
  agentId: string;
  address: string;
  number: string;
  neighborhood: string;
  membersCount: number;
  lastVisit: string | null; // ISO Date
  nextVisit: string; // ISO Date calculated
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
}

export interface Visit {
  id: string;
  familyId: string;
  agentId: string;
  date: string;
  notes: string;
  outcome: string;
  measurements: {
    bloodPressure?: string;
    glucose?: string;
    weight?: string;
  }[];
}

export interface DashboardStats {
  totalFamilies: number;
  totalPatients: number;
  pendingVisits: number;
  highRiskFamilies: number;
}

