import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { Users, AlertTriangle, CalendarClock, Home, Baby, Activity } from 'lucide-react';

export const Dashboard: React.FC = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    families: 0,
    patients: 0,
    pending: 0,
    urgent: 0,
    pregnant: 0,
    children: 0
  });

  useEffect(() => {
    if (!user) return;

    // Filter logic: Admin sees all, Agent sees theirs
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);
    const familyIds = families.map(f => f.id);

    // Get all patients but filter by relevant families
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));

    const now = new Date();
    const pendingVisits = families.filter(f => new Date(f.nextVisit) <= now).length;
    const urgent = families.filter(f => f.riskLevel === 'URGENT' || f.riskLevel === 'HIGH').length;
    const pregnant = myPatients.filter(p => p.isPregnant).length;

    // Children under 5
    const children = myPatients.filter(p => {
        const year = new Date(p.birthDate).getFullYear();
        return (now.getFullYear() - year) < 5;
    }).length;

    setStats({
      families: families.length,
      patients: myPatients.length,
      pending: pendingVisits,
      urgent: urgent,
      pregnant,
      children
    });
  }, [user]);

  const StatCard = ({ title, value, icon: Icon, color, subtext }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-start justify-between">
      <div>
        <p className="text-slate-500 text-sm font-medium mb-1">{title}</p>
        <h3 className="text-3xl font-bold text-slate-800">{value}</h3>
        {subtext && <p className="text-xs text-slate-400 mt-2">{subtext}</p>}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon size={24} className="text-white" />
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-slate-800">Visão Geral</h1>
        <p className="text-slate-500">Bem-vindo(a) de volta, {user?.name}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Famílias Cadastradas" 
          value={stats.families} 
          icon={Home} 
          color="bg-blue-500" 
        />
        <StatCard 
          title="Visitas Pendentes" 
          value={stats.pending} 
          icon={CalendarClock} 
          color="bg-amber-500" 
          subtext="Necessitam atenção imediata"
        />
        <StatCard 
          title="Alta Prioridade" 
          value={stats.urgent} 
          icon={AlertTriangle} 
          color="bg-red-500" 
        />
        <StatCard 
          title="Total de Pacientes" 
          value={stats.patients} 
          icon={Users} 
          color="bg-emerald-500" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h2 className="font-bold text-lg mb-4 text-slate-800">Grupos de Atenção</h2>
          <div className="space-y-4">
            <div className="flex items-center justify-between p-4 bg-pink-50 rounded-lg">
              <div className="flex items-center space-x-3">
                <Baby className="text-pink-500" />
                <span className="font-medium text-pink-700">Gestantes</span>
              </div>
              <span className="text-xl font-bold text-pink-700">{stats.pregnant}</span>
            </div>
            <div className="flex items-center justify-between p-4 bg-indigo-50 rounded-lg">
              <div className="flex items-center space-x-3">
                <Users className="text-indigo-500" />
                <span className="font-medium text-indigo-700">Crianças &lt; 5 anos</span>
              </div>
              <span className="text-xl font-bold text-indigo-700">{stats.children}</span>
            </div>
          </div>
        </div>

        <div className="bg-gradient-to-br from-blue-600 to-blue-800 p-6 rounded-xl shadow-lg text-white">
          <h2 className="font-bold text-lg mb-2">Área de Atuação</h2>
          <p className="text-blue-100 mb-6">{user?.area || 'Geral'}</p>
          <div className="flex items-center space-x-2 bg-white/10 p-4 rounded-lg backdrop-blur-sm">
            <Activity className="text-blue-200" />
            <div>
              <p className="text-sm font-medium">Status do Agente</p>
              <p className="text-xs text-blue-200">Ativo e operante</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed } from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [visitNotes, setVisitNotes] = useState('');
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && <span className="px-2 py-0.5 bg-pink-100 text-pink-700 text-xs rounded-full flex items-center"><Baby size={10} className="mr-1"/>Gestante</span>}
        {patient.isBedridden && <span className="px-2 py-0.5 bg-purple-100 text-purple-700 text-xs rounded-full flex items-center"><Bed size={10} className="mr-1"/>Acamado</span>}
        {(patient.isDiabetic || patient.isHypertensive) && <span className="px-2 py-0.5 bg-red-100 text-red-700 text-xs rounded-full flex items-center"><HeartPulse size={10} className="mr-1"/>Crônico</span>}
        {patient.hasPsychologicalIssues && <span className="px-2 py-0.5 bg-yellow-100 text-yellow-700 text-xs rounded-full flex items-center"><Brain size={10} className="mr-1"/>Psico</span>}
      </div>
    );
  };

  return (
    <div>
      <h1 className="text-2xl font-bold text-slate-800 mb-6">Controle de Visitas</h1>

      <div className="grid gap-4">
        {pendingFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
