import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { Visits } from './pages/Visits';
import { Families } from './pages/Families';
import { Admin } from './pages/Admin';
import { Login } from './pages/Login';
import { UserRole, UserStatus } from './types';
import { Clock, Ban } from 'lucide-react';

const ProtectedRoute = ({ children, requiredRole }: { children: React.ReactNode, requiredRole?: UserRole }) => {
  const { user, refreshUser } = useAuth();

  // Refresh user data on navigation to ensure status is up to date
  React.useEffect(() => {
    refreshUser();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  if (user.status === UserStatus.PENDING) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Clock size={64} className="text-yellow-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Aguardando Aprovação</h1>
        <p className="text-slate-500 max-w-md">
          Seu cadastro foi realizado com sucesso. Aguarde a aprovação do administrador para acessar o sistema.
        </p>
        <button onClick={() => window.location.reload()} className="mt-6 text-blue-600 hover:underline">Verificar novamente</button>
      </div>
    );
  }

  if (user.status === UserStatus.BLOCKED) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Ban size={64} className="text-red-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Acesso Bloqueado</h1>
        <p className="text-slate-500">Entre em contato com o administrador.</p>
      </div>
    );
  }

  if (requiredRole && user.role !== requiredRole) {
    return <Navigate to="/" replace />;
  }

  return <Layout>{children}</Layout>;
};

const AppRoutes = () => {
  const { user } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/" replace /> : <Login />} />

      <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
      <Route path="/visits" element={<ProtectedRoute><Visits /></ProtectedRoute>} />
      <Route path="/families" element={<ProtectedRoute><Families /></ProtectedRoute>} />

      <Route path="/admin" element={
        <ProtectedRoute requiredRole={UserRole.ADMIN}>
          <Admin />
        </ProtectedRoute>
      } />
    </Routes>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <AppRoutes />
      </HashRouter>
    </AuthProvider>
  );
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, UserRole, UserStatus } from '../types';
import { storageService } from '../services/storage';

interface AuthContextType {
  user: User | null;
  login: (email: string, password?: string) => Promise<boolean>;
  register: (user: Omit<User, 'id' | 'status'>) => Promise<void>;
  logout: () => void;
  refreshUser: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const storedUserId = localStorage.getItem('acs_current_user_id');
    if (storedUserId) {
      const users = storageService.getUsers();
      const foundUser = users.find(u => u.id === storedUserId);
      if (foundUser) setUser(foundUser);
    }
  }, []);

  const login = async (email: string, password?: string) => {
    const users = storageService.getUsers();
    const foundUser = users.find(u => u.email === email);

    // Check if user exists and password matches (simple check for demo)
    if (foundUser && (!password || foundUser.password === password)) {
      localStorage.setItem('acs_current_user_id', foundUser.id);
      setUser(foundUser);
      return true;
    }
    return false;
  };

  const register = async (newUser: Omit<User, 'id' | 'status'>) => {
    const user: User = {
      ...newUser,
      id: crypto.randomUUID(),
      status: UserStatus.PENDING
    };
    storageService.saveUser(user);
    localStorage.setItem('acs_current_user_id', user.id);
    setUser(user);
  };

  const logout = () => {
    localStorage.removeItem('acs_current_user_id');
    setUser(null);
  };

  const refreshUser = () => {
    if (user) {
        const users = storageService.getUsers();
        const foundUser = users.find(u => u.id === user.id);
        if (foundUser) setUser(foundUser);
    }
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, refreshUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

