import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, Search, X } from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [visitNotes, setVisitNotes] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && <span className="px-2 py-0.5 bg-pink-100 text-pink-700 text-xs rounded-full flex items-center"><Baby size={10} className="mr-1"/>Gestante</span>}
        {patient.isBedridden && <span className="px-2 py-0.5 bg-purple-100 text-purple-700 text-xs rounded-full flex items-center"><Bed size={10} className="mr-1"/>Acamado</span>}
        {(patient.isDiabetic || patient.isHypertensive) && <span className="px-2 py-0.5 bg-red-100 text-red-700 text-xs rounded-full flex items-center"><HeartPulse size={10} className="mr-1"/>Crônico</span>}
        {patient.hasPsychologicalIssues && <span className="px-2 py-0.5 bg-yellow-100 text-yellow-700 text-xs rounded-full flex items-center"><Brain size={10} className="mr-1"/>Psico</span>}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  return (
    <div>
      <h1 className="text-2xl font-bold text-slate-800 mb-6">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text"
          placeholder="Buscar por rua, número ou bairro..."
          className="w-full pl-10 pr-10 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {filteredFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
                <p className="text-slate-500 text-sm">{family.neighborhood} • {family.membersCount} integrantes</p>
                <div className="mt-2 text-xs text-slate-400">
                  Última visita: {family.lastVisit ? new Date(family.lastVisit).toLocaleDateString() : 'Nunca'}
                </div>
              </div>
              <div className="text-right">
                <div className="mb-1">{getUrgencyText(family.nextVisit)}</div>
                <div className="text-xs text-slate-400">Meta: {new Date(family.nextVisit).toLocaleDateString()}</div>
              </div>
            </div>
            {/* Quick indicators of family health profile */}
            <div className="mt-3 flex gap-2">
                {family.riskLevel === 'URGENT' && <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded">Prioridade Máxima</span>}
                {family.riskLevel === 'HIGH' && <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded">Prioridade Alta</span>}
            </div>
          </div>
        ))}

        {filteredFamilies.length === 0 && (
          <div className="text-center py-12 bg-white rounded-lg">
            {searchTerm ? (
              <>
                <Search className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Nenhum resultado encontrado</h3>
                <p className="text-slate-500">Tente buscar por outro termo.</p>
              </>
            ) : (
              <>
                <CheckCircle className="mx-auto text-green-500 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Tudo em dia!</h3>
                <p className="text-slate-500">Nenhuma visita pendente para sua área.</p>
              </>
            )}
          </div>
        )}
      </div>

      {/* Modal for Visit Execution */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-slate-100">
              <h2 className="text-xl font-bold text-slate-800">Registrar Visita</h2>
              <p className="text-slate-500">{selectedFamily.address}, {selectedFamily.number}</p>
            </div>

            <div className="p-6 space-y-6">
              {/* Member Summary */}
              <div>
                <h3 className="font-semibold text-slate-700 mb-3">Integrantes da Família</h3>
                <div className="space-y-2">
                  {familyMembers.map(member => (
                    <div key={member.id} className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                      <div className="flex justify-between items-center">
                        <span className="font-medium">{member.name}</span>
                        <span className="text-xs text-slate-400">{new Date().getFullYear() - new Date(member.birthDate).getFullYear()} anos</span>
                      </div>
                      <PatientBadge patient={member} />
                      {(member.medications.length > 0) && (
                        <p className="text-xs text-slate-500 mt-1">Meds: {member.medications.join(', ')}</p>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              {/* Visit Form */}
              <form onSubmit={handleCompleteVisit}>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Anotações da Visita</label>
                    <textarea 
                      required
                      className="w-full rounded-lg border-slate-300 border p-3 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                      rows={4}
                      placeholder="Descreva as aferições, orientações dadas e observações gerais..."
                      value={visitNotes}
                      onChange={(e) => setVisitNotes(e.target.value)}
                    ></textarea>
                  </div>
                </div>

                <div className="mt-8 flex gap-3 justify-end">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
                  >
                    Cancelar
                  </button>
                  <button 
                    type="submit"
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                  >
                    Concluir Visita
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

