import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, Search, X, User, Activity, Droplets, ChevronLeft } from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [visitNotes, setVisitNotes] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = patient.isPregnant || patient.isBedridden || patient.isDiabetic || patient.isHypertensive || patient.hasPsychologicalIssues;

    if (!hasConditions) {
        return <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-full flex items-center w-fit">Sem queixas registradas</span>;
    }

    return (
      <div className="flex flex-wrap gap-2 mt-2">
        {patient.isPregnant && (
            <span className="px-2 py-1 bg-pink-100 text-pink-700 text-xs font-medium rounded-md flex items-center border border-pink-200">
                <Baby size={12} className="mr-1.5"/>Gestante
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-medium rounded-md flex items-center border border-purple-200">
                <Bed size={12} className="mr-1.5"/>Acamado(a)
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-md flex items-center border border-blue-200">
                <Droplets size={12} className="mr-1.5"/>Diabético(a)
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-medium rounded-md flex items-center border border-red-200">
                <HeartPulse size={12} className="mr-1.5"/>Hipertenso(a)
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs font-medium rounded-md flex items-center border border-yellow-200">
                <Brain size={12} className="mr-1.5"/>Saúde Mental
            </span>
        )}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  return (
    <div className="pb-20 md:pb-0"> {/* Add padding bottom for mobile if needed */}
      <h1 className="text-2xl font-bold text-slate-800 mb-6 px-1">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative mx-1">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search" // Optimized for mobile keyboards
          placeholder="Buscar por rua, número ou bairro..."
          className="w-full pl-10 pr-10 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all text-base bg-white" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {filteredFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md active:scale-[0.99] touch-manipulation ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
                <p className="text-slate-500 text-sm">{family.neighborhood} • {family.membersCount} integrantes</p>
                <div className="mt-2 text-xs text-slate-400">
                  Última visita: {family.lastVisit ? new Date(family.lastVisit).toLocaleDateString() : 'Nunca'}
                </div>
              </div>
              <div className="text-right">
                <div className="mb-1">{getUrgencyText(family.nextVisit)}</div>
                <div className="text-xs text-slate-400">Meta: {new Date(family.nextVisit).toLocaleDateString()}</div>
              </div>
            </div>
            {/* Quick indicators of family health profile */}
            <div className="mt-3 flex gap-2">
                {family.riskLevel === 'URGENT' && <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded">Prioridade Máxima</span>}
                {family.riskLevel === 'HIGH' && <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded">Prioridade Alta</span>}
            </div>
          </div>
        ))}

        {filteredFamilies.length === 0 && (
          <div className="text-center py-12 bg-white rounded-lg mx-1">
            {searchTerm ? (
              <>
                <Search className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Nenhum resultado encontrado</h3>
                <p className="text-slate-500">Tente buscar por outro termo.</p>
              </>
            ) : (
              <>
                <CheckCircle className="mx-auto text-green-500 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Tudo em dia!</h3>
                <p className="text-slate-500">Nenhuma visita pendente para sua área.</p>
              </>
            )}
          </div>
        )}
      </div>

      {/* Responsive Modal for Visit Execution */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
          {/* Mobile: Full Screen (h-[100dvh]), Desktop: Modal Card */}
          <div className="bg-white w-full h-[100dvh] sm:h-auto sm:max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden transition-all transform animate-in slide-in-from-bottom duration-200">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setShowModal(false)} 
                    className="sm:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-200 rounded-full"
                  >
                    <ChevronLeft size={24} />
                  </button>
                  <div>
                    <h2 className="text-lg sm:text-xl font-bold text-slate-800 leading-tight">Registrar Visita</h2>
                    <p className="text-xs sm:text-sm text-slate-500 flex items-center mt-0.5">
                        <User size={12} className="mr-1"/> {selectedFamily.address}, {selectedFamily.number}
                    </p>
                  </div>
              </div>
              <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full">
                  <X size={24} />
              </button>
            </div>

            {/* Content - Scrollable */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30">
              {/* Detailed Member Summary */}
              <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                <h3 className="font-bold text-blue-900 mb-4 flex items-center">
                    <Activity size={18} className="mr-2"/> 
                    Prontuário da Família
                </h3>
                <div className="space-y-3">
                  {familyMembers.map(member => (
                    <div key={member.id} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                      <div className="flex justify-between items-start mb-2">
                        <div className="flex items-center">
                            <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 shrink-0">
                                <User size={16} />
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos</span>
                            </div>
                        </div>
                        <div className="text-right">
                             <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">SUS: {member.susNumber}</span>
                        </div>
                      </div>

                      <div className="pl-11">
                          <PatientBadge patient={member} />
                          {(member.medications.length > 0) && (
                            <div className="mt-3 text-xs bg-slate-50 p-2 rounded border border-slate-100 text-slate-600">
                                <span className="font-semibold text-slate-700">Medicamentos:</span> {member.medications.join(', ')}
                            </div>
                          )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Visit Form */}
              <div className="bg-white p-1 rounded-lg">
                <label className="block text-sm font-bold text-slate-700 mb-2 px-1">Relatório da Visita</label>
                <textarea 
                  required
                  className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                  rows={6}
                  placeholder="Descreva detalhadamente as aferições realizadas (PA, Glicemia), orientações fornecidas e observações sobre o estado dos pacientes..."
                  value={visitNotes}
                  onChange={(e) => setVisitNotes(e.target.value)}
                ></textarea>
              </div>
            </div>

            {/* Footer - Sticky at bottom */}
            <div className="p-4 border-t border-slate-100 bg-white shrink-0 safe-area-bottom">
                <div className="flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={handleCompleteVisit}
                    disabled={!visitNotes.trim()}
                    className={`flex-1 px-6 py-3 sm:py-2 rounded-lg transition-colors font-bold shadow-sm text-center
                        ${!visitNotes.trim() 
                            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
                  >
                    Confirmar Visita
                  </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export enum UserRole {
  ADMIN = 'ADMIN',
  AGENT = 'AGENT',
}

export enum UserStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  BLOCKED = 'BLOCKED',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  area?: string;
  phone?: string;
  password?: string; // In a real app, this would be hashed
  subscriptionExpiresAt?: string; // ISO Date string for access expiration
}

export interface Patient {
  id: string;
  familyId: string;
  name: string;
  birthDate: string;
  susNumber: string;
  isPregnant: boolean;
  isBedridden: boolean;
  isDiabetic: boolean;
  isHypertensive: boolean;
  hasPsychologicalIssues: boolean;
  medications: string[];
  addictions: string[];
}

export interface Family {
  id: string;
  agentId: string;
  address: string;
  number: string;
  neighborhood: string;
  membersCount: number;
  lastVisit: string | null; // ISO Date
  nextVisit: string; // ISO Date calculated
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
}

export interface Visit {
  id: string;
  familyId: string;
  agentId: string;
  date: string;
  notes: string;
  outcome: string;
  measurements: {
    bloodPressure?: string;
    glucose?: string;
    weight?: string;
  }[];
}

export interface DashboardStats {
  totalFamilies: number;
  totalPatients: number;
  pendingVisits: number;
  highRiskFamilies: number;
}

