// Storage Service Methods
export const storageService = {
  // Users
  getUsers: (): User[] => JSON.parse(localStorage.getItem('acs_users') || '[]'),

  saveUser: (user: User) => {
    const users = storageService.getUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index >= 0) {
      users[index] = user;
    } else {
      users.push(user);
    }
    localStorage.setItem('acs_users', JSON.stringify(users));
  },

  currentUser: null as User | null,

  // Families
  getFamilies: (agentId?: string): Family[] => {
    const families: Family[] = JSON.parse(localStorage.getItem('acs_families') || '[]');
    if (agentId) {
      return families.filter(f => f.agentId === agentId);
    }
    return families;
  },

  saveFamily: (family: Family) => {
    const families = JSON.parse(localStorage.getItem('acs_families') || '[]');
    const index = families.findIndex((f: Family) => f.id === family.id);
    if (index >= 0) families[index] = family;
    else families.push(family);
    localStorage.setItem('acs_families', JSON.stringify(families));
  },

  // Patients
  getPatients: (familyId?: string): Patient[] => {
    const patients: Patient[] = JSON.parse(localStorage.getItem('acs_patients') || '[]');
    if (familyId) {
      return patients.filter(p => p.familyId === familyId);
    }
    return patients;
  },

  savePatient: (patient: Patient) => {
    const patients = JSON.parse(localStorage.getItem('acs_patients') || '[]');
    const index = patients.findIndex((p: Patient) => p.id === patient.id);
    if (index >= 0) patients[index] = patient;
    else patients.push(patient);
    localStorage.setItem('acs_patients', JSON.stringify(patients));
  },

  // Visits
  getVisits: (familyId?: string): Visit[] => {
    const visits: Visit[] = JSON.parse(localStorage.getItem('acs_visits') || '[]');
    if (familyId) return visits.filter(v => v.familyId === familyId);
    return visits;
  },

  addVisit: (visit: Visit) => {
    const visits = JSON.parse(localStorage.getItem('acs_visits') || '[]');
    visits.push(visit);
    localStorage.setItem('acs_visits', JSON.stringify(visits));

    // Update Family Last/Next Visit Logic
    const family = storageService.getFamilies().find(f => f.id === visit.familyId);
    if (family) {
      const patients = storageService.getPatients(family.id);

      let minMonths = 12; // Default 1 year

      // Calculate logic based on requirements
      patients.forEach(p => {
        // Gestante: 1 month
        if (p.isPregnant) minMonths = Math.min(minMonths, 1);

        // Acamado or Psychological: 3 months
        if (p.isBedridden || p.hasPsychologicalIssues) minMonths = Math.min(minMonths, 3);

        // Child < 5, Hypertension, Diabetes: 6 months
        const age = new Date().getFullYear() - new Date(p.birthDate).getFullYear();
        if (age < 5 || p.isDiabetic || p.isHypertensive) minMonths = Math.min(minMonths, 6);
      });

      const nextDate = new Date();
      nextDate.setMonth(nextDate.getMonth() + minMonths);

      family.lastVisit = visit.date;
      family.nextVisit = nextDate.toISOString();

      // Update risk level visually
      if (minMonths === 1) family.riskLevel = 'URGENT';
      else if (minMonths === 3) family.riskLevel = 'HIGH';
      else if (minMonths === 6) family.riskLevel = 'MEDIUM';
      else family.riskLevel = 'LOW';

      storageService.saveFamily(family);
    }
  }
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { Visits } from './pages/Visits';
import { Families } from './pages/Families';
import { Admin } from './pages/Admin';
import { Login } from './pages/Login';
import { UserRole, UserStatus } from './types';
import { Clock, Ban, CreditCard } from 'lucide-react';

const ProtectedRoute = ({ children, requiredRole }: { children: React.ReactNode, requiredRole?: UserRole }) => {
  const { user, refreshUser } = useAuth();

  // Refresh user data on navigation to ensure status is up to date
  React.useEffect(() => {
    refreshUser();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // 1. Check if user is PENDING approval
  if (user.status === UserStatus.PENDING) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Clock size={64} className="text-yellow-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Aguardando Aprovação</h1>
        <p className="text-slate-500 max-w-md">
          Seu cadastro foi realizado com sucesso. Aguarde a aprovação e ativação do plano pelo administrador.
        </p>
        <button onClick={() => window.location.reload()} className="mt-6 text-blue-600 hover:underline">Verificar novamente</button>
      </div>
    );
  }

  // 2. Check if user is BLOCKED manually
  if (user.status === UserStatus.BLOCKED) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Ban size={64} className="text-red-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Acesso Bloqueado</h1>
        <p className="text-slate-500">Entre em contato com o administrador para regularizar seu acesso.</p>
      </div>
    );
  }

  // 3. Check Subscription Expiration (Only for Agents, Admins bypass)
  if (user.role !== UserRole.ADMIN && user.subscriptionExpiresAt) {
    const expirationDate = new Date(user.subscriptionExpiresAt);
    const today = new Date();

    if (today > expirationDate) {
      return (
        <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
          <div className="bg-red-100 p-6 rounded-full mb-6">
            <CreditCard size={48} className="text-red-600" />
          </div>
          <h1 className="text-2xl font-bold text-slate-800 mb-2">Assinatura Expirada</h1>
          <p className="text-slate-500 max-w-md mb-6">
            O período de validade do seu acesso encerrou em <b>{expirationDate.toLocaleDateString()}</b>.
          </p>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 w-full max-w-sm">
            <p className="text-sm text-slate-600 mb-4">Para continuar utilizando o sistema e acessar seus dados, renove sua mensalidade ou anuidade.</p>
            <button className="w-full bg-blue-600 text-white font-bold py-3 rounded-lg hover:bg-blue-700 transition-colors">
              Falar com o Administrador
            </button>
          </div>
          <button onClick={refreshUser} className="mt-8 text-slate-400 text-sm hover:text-slate-600">
            Já paguei? Clique para atualizar
          </button>
        </div>
      );
    }
  }

  if (requiredRole && user.role !== requiredRole) {
    return <Navigate to="/" replace />;
  }

  return <Layout>{children}</Layout>;
};

const AppRoutes = () => {
  const { user } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/" replace /> : <Login />} />

      <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
      <Route path="/visits" element={<ProtectedRoute><Visits /></ProtectedRoute>} />
      <Route path="/families" element={<ProtectedRoute><Families /></ProtectedRoute>} />

      <Route path="/admin" element={
        <ProtectedRoute requiredRole={UserRole.ADMIN}>
          <Admin />
        </ProtectedRoute>
      } />
    </Routes>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <AppRoutes />
      </HashRouter>
    </AuthProvider>
  );
}

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { User, UserStatus } from '../types';
import { ShieldCheck, Ban, CheckCircle, Mail, MapPin, MoreVertical, Calendar, DollarSign, X } from 'lucide-react';

export const Admin: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [showRenewModal, setShowRenewModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);

  useEffect(() => {
    setUsers(storageService.getUsers());
  }, []);

  const handleStatusChange = (userId: string, newStatus: UserStatus) => {
    const user = users.find(u => u.id === userId);
    if (user) {
      // When approving, if no expiration set, give 30 days trial by default or handle in renew modal
      let updatedUser = { ...user, status: newStatus };

      if (newStatus === UserStatus.APPROVED && !user.subscriptionExpiresAt) {
         const trialDate = new Date();
         trialDate.setDate(trialDate.getDate() + 30); // 30 days initial access
         updatedUser.subscriptionExpiresAt = trialDate.toISOString();
      }

      storageService.saveUser(updatedUser);
      setUsers(storageService.getUsers());
    }
  };

  const openRenewModal = (user: User) => {
    setSelectedUser(user);
    setShowRenewModal(true);
  };

  const handleExtendSubscription = (months: number) => {
    if (!selectedUser) return;

    const currentExpiry = selectedUser.subscriptionExpiresAt 
        ? new Date(selectedUser.subscriptionExpiresAt) 
        : new Date();

    // If expired, start from today. If active, add to existing date.
    const baseDate = currentExpiry < new Date() ? new Date() : currentExpiry;

    baseDate.setMonth(baseDate.getMonth() + months);

    const updatedUser = { 
        ...selectedUser, 
        subscriptionExpiresAt: baseDate.toISOString(),
        status: UserStatus.APPROVED // Ensure they are unblocked if they pay
    };

    storageService.saveUser(updatedUser);
    setUsers(storageService.getUsers());
    setShowRenewModal(false);
  };

  const getStatusBadge = (user: User) => {
    if (user.status === UserStatus.BLOCKED) {
        return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">Bloqueado</span>;
    }
    if (user.status === UserStatus.PENDING) {
        return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">Pendente</span>;
    }

    // Check expiration
    if (user.subscriptionExpiresAt) {
        const daysLeft = Math.ceil((new Date(user.subscriptionExpiresAt).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
        if (daysLeft < 0) {
            return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800 border border-gray-300">Expirado</span>;
        }
        if (daysLeft <= 7) {
            return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-orange-100 text-orange-800">Expira em {daysLeft} dias</span>;
        }
    }

    return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">Ativo</span>;
  };

  const ActionButtons = ({ user }: { user: User }) => (
    <div className="flex items-center gap-1">
      {user.status === UserStatus.PENDING && (
        <button 
          onClick={() => handleStatusChange(user.id, UserStatus.APPROVED)}
          className="flex items-center justify-center p-2 text-green-600 hover:bg-green-50 rounded-lg transition-colors" 
          title="Aprovar Cadastro"
        >
          <CheckCircle size={20} />
          <span className="md:hidden ml-2 font-medium">Aprovar</span>
        </button>
      )}

      {/* Subscription Renewal Button */}
      {user.status !== UserStatus.PENDING && (
        <button 
            onClick={() => openRenewModal(user)}
            className="flex items-center justify-center p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" 
            title="Gerenciar Assinatura"
        >
            <DollarSign size={20} />
            <span className="md:hidden ml-2 font-medium">Assinatura</span>
        </button>
      )}

      {user.status !== UserStatus.BLOCKED && user.status !== UserStatus.PENDING && (
        <button 
          onClick={() => handleStatusChange(user.id, UserStatus.BLOCKED)}
          className="flex items-center justify-center p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors" 
          title="Bloquear Acesso"
        >
          <Ban size={20} />
          <span className="md:hidden ml-2 font-medium">Bloquear</span>
        </button>
      )}

      {user.status === UserStatus.BLOCKED && (
        <button 
          onClick={() => handleStatusChange(user.id, UserStatus.APPROVED)}
          className="flex items-center justify-center p-2 text-green-600 hover:bg-green-50 rounded-lg transition-colors" 
          title="Desbloquear"
        >
          <ShieldCheck size={20} />
          <span className="md:hidden ml-2 font-medium">Desbloquear</span>
        </button>
      )}
    </div>
  );

  return (
    <div className="pb-20 md:pb-0">
      <h1 className="text-2xl font-bold text-slate-800 mb-6">Gerenciar Agentes</h1>

      {/* Mobile Card View */}
      <div className="md:hidden space-y-4">
        {users.map(user => (
          <div key={user.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-start mb-3">
              <div>
                <h3 className="font-bold text-slate-900 text-lg">{user.name}</h3>
                <div className="flex items-center text-slate-500 text-sm mt-1">
                  <Mail size={14} className="mr-1.5" />
                  {user.email}
                </div>
              </div>
              {getStatusBadge(user)}
            </div>

            <div className="bg-slate-50 p-3 rounded-lg text-sm text-slate-600 mb-4 space-y-2">
               <div className="flex items-center">
                  <MapPin size={14} className="mr-1.5" />
                  Área: <span className="font-medium ml-1">{user.area || 'Não definida'}</span>
               </div>
               {user.subscriptionExpiresAt && (
                   <div className="flex items-center text-slate-600">
                       <Calendar size={14} className="mr-1.5" />
                       Validade: <span className="font-medium ml-1">{new Date(user.subscriptionExpiresAt).toLocaleDateString()}</span>
                   </div>
               )}
            </div>

            <div className="border-t border-slate-100 pt-3 flex justify-end">
              <ActionButtons user={user} />
            </div>
          </div>
        ))}
      </div>

      {/* Desktop Table View */}
      <div className="hidden md:block bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-600 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 font-semibold">Nome</th>
                <th className="px-6 py-4 font-semibold">Email</th>
                <th className="px-6 py-4 font-semibold">Validade do Acesso</th>
                <th className="px-6 py-4 font-semibold">Status</th>
                <th className="px-6 py-4 font-semibold text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 font-medium text-slate-900">{user.name}</td>
                  <td className="px-6 py-4 text-slate-500">{user.email}</td>
                  <td className="px-6 py-4 text-slate-500">
                    {user.subscriptionExpiresAt 
                        ? new Date(user.subscriptionExpiresAt).toLocaleDateString() 
                        : <span className="text-slate-400">-</span>}
                  </td>
                  <td className="px-6 py-4">
                    {getStatusBadge(user)}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end space-x-2">
                        <ActionButtons user={user} />
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Subscription Renewal Modal */}
      {showRenewModal && selectedUser && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                <h3 className="font-bold text-lg text-slate-800">Renovar Acesso</h3>
                <button onClick={() => setShowRenewModal(false)} className="text-slate-400 hover:text-slate-600">
                    <X size={24} />
                </button>
            </div>

            <div className="p-6">
                <div className="mb-6 text-center">
                    <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-3">
                        <Calendar size={32} />
                    </div>
                    <h4 className="font-bold text-slate-800 text-lg">{selectedUser.name}</h4>
                    <p className="text-sm text-slate-500">
                        Vencimento atual: {selectedUser.subscriptionExpiresAt ? new Date(selectedUser.subscriptionExpiresAt).toLocaleDateString() : 'Não definido'}
                    </p>
                </div>

                <div className="space-y-3">
                    <p className="text-sm font-medium text-slate-700 mb-2">Adicionar tempo de acesso:</p>
                    <button 
                        onClick={() => handleExtendSubscription(1)}
