                    <button 
                        onClick={() => handleExtendSubscription(6)}
                        className="w-full flex items-center justify-between p-4 border border-slate-200 rounded-xl hover:border-blue-500 hover:bg-blue-50 transition-all group"
                    >
                        <span className="font-bold text-slate-700 group-hover:text-blue-700">Semestral (+6 Meses)</span>
                        <span className="text-xs bg-slate-100 px-2 py-1 rounded text-slate-500 group-hover:bg-blue-100 group-hover:text-blue-600">Selecionar</span>
                    </button>

                    <button 
                        onClick={() => handleExtendSubscription(12)}
