                    <p className="text-xs sm:text-sm text-slate-500 flex items-center mt-0.5">
                        <User size={12} className="mr-1"/> {selectedFamily.address}, {selectedFamily.number}
                    </p>
                  </div>
              </div>
              <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full">
                  <X size={24} />
