// Storage Service Methods
export const storageService = {
  // Users
  getUsers: (): User[] => JSON.parse(localStorage.getItem('acs_users') || '[]'),

  saveUser: (user: User) => {
    const users = storageService.getUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index >= 0) {
      users[index] = user;
    } else {
      users.push(user);
    }
    localStorage.setItem('acs_users', JSON.stringify(users));
  },

  currentUser: null as User | null,

  // Families
  getFamilies: (agentId?: string): Family[] => {
    const families: Family[] = JSON.parse(localStorage.getItem('acs_families') || '[]');
    if (agentId) {
      return families.filter(f => f.agentId === agentId);
    }
    return families;
  },

  saveFamily: (family: Family) => {
    const families = JSON.parse(localStorage.getItem('acs_families') || '[]');
    const index = families.findIndex((f: Family) => f.id === family.id);
    if (index >= 0) families[index] = family;
    else families.push(family);
    localStorage.setItem('acs_families', JSON.stringify(families));
  },

  // Patients
  getPatients: (familyId?: string): Patient[] => {
    const patients: Patient[] = JSON.parse(localStorage.getItem('acs_patients') || '[]');
    if (familyId) {
      return patients.filter(p => p.familyId === familyId);
    }
    return patients;
  },

  savePatient: (patient: Patient) => {
    const patients = JSON.parse(localStorage.getItem('acs_patients') || '[]');
    const index = patients.findIndex((p: Patient) => p.id === patient.id);
    if (index >= 0) patients[index] = patient;
    else patients.push(patient);
    localStorage.setItem('acs_patients', JSON.stringify(patients));
  },

  // Visits
  getVisits: (familyId?: string): Visit[] => {
    const visits: Visit[] = JSON.parse(localStorage.getItem('acs_visits') || '[]');
    if (familyId) return visits.filter(v => v.familyId === familyId);
    return visits;
  },

  addVisit: (visit: Visit) => {
    const visits = JSON.parse(localStorage.getItem('acs_visits') || '[]');
    visits.push(visit);
    localStorage.setItem('acs_visits', JSON.stringify(visits));

    // Update Family Last/Next Visit Logic
    const family = storageService.getFamilies().find(f => f.id === visit.familyId);
    if (family) {
      const patients = storageService.getPatients(family.id);

      let minMonths = 12; // Default 1 year

      // Calculate logic based on requirements
      patients.forEach(p => {
        // Gestante: 1 month
        if (p.isPregnant) minMonths = Math.min(minMonths, 1);

        // Acamado or Psychological: 3 months
        if (p.isBedridden || p.hasPsychologicalIssues) minMonths = Math.min(minMonths, 3);

        // Child < 5, Hypertension, Diabetes: 6 months
        const age = new Date().getFullYear() - new Date(p.birthDate).getFullYear();
        if (age < 5 || p.isDiabetic || p.isHypertensive) minMonths = Math.min(minMonths, 6);
      });

      const nextDate = new Date();
      nextDate.setMonth(nextDate.getMonth() + minMonths);

      family.lastVisit = visit.date;
      family.nextVisit = nextDate.toISOString();

      // Update risk level visually
      if (minMonths === 1) family.riskLevel = 'URGENT';
      else if (minMonths === 3) family.riskLevel = 'HIGH';
      else if (minMonths === 6) family.riskLevel = 'MEDIUM';
      else family.riskLevel = 'LOW';

      storageService.saveFamily(family);
    }
  }
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
