import { UserRole } from '../types';
import { 
  Users, AlertTriangle, CalendarClock, Home, Baby, Activity, 
  UserPlus, Accessibility, HeartPulse, Droplets, Bed, Armchair, Syringe, FilePlus
} from 'lucide-react';

export const Dashboard: React.FC = () => {
  const { user } = useAuth();

  // Basic Stats
  const [basicStats, setBasicStats] = useState({
    families: 0,
    patients: 0,
    pending: 0,
    urgent: 0,
  });

  // Detailed Attention Groups
  const [groups, setGroups] = useState({
    // Age Groups
    child0: 0,      // 0 years
    child1to5: 0,   // 1 to 4 years
    child5to9: 0,   // 5 to 8 years
    child9to13: 0,  // 9 to 13 years
    over14: 0,      // 14+ years
    elderly60: 0,   // 60+ years (Subset)

    // Conditions
    pregnant: 0,
    postpartum: 0,
    bedridden: 0,
    mobilityIssues: 0,
    hypertensive: 0,
    diabetic: 0,
    insulinUser: 0,
    otherComorbidities: 0
  });

  useEffect(() => {
    if (!user) return;

    // Filter logic: Admin sees all, Agent sees theirs
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);
    const familyIds = families.map(f => f.id);

    // Get all patients but filter by relevant families
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));

    const now = new Date();
    const pendingVisits = families.filter(f => new Date(f.nextVisit) <= now).length;
    const urgent = families.filter(f => f.riskLevel === 'URGENT' || f.riskLevel === 'HIGH').length;

    // Calculate Groups
    const groupStats = {
      child0: 0, child1to5: 0, child5to9: 0, child9to13: 0, over14: 0, elderly60: 0,
      pregnant: 0, postpartum: 0, bedridden: 0, mobilityIssues: 0,
      hypertensive: 0, diabetic: 0, insulinUser: 0, otherComorbidities: 0
    };

    myPatients.forEach(p => {
      // Age Calculation
      const birth = new Date(p.birthDate);
      let age = now.getFullYear() - birth.getFullYear();
      const m = now.getMonth() - birth.getMonth();
      if (m < 0 || (m === 0 && now.getDate() < birth.getDate())) {
        age--;
      }

      // Age Buckets
      if (age < 1) groupStats.child0++;
      else if (age >= 1 && age < 5) groupStats.child1to5++;
      else if (age >= 5 && age < 9) groupStats.child5to9++;
      else if (age >= 9 && age < 14) groupStats.child9to13++;
      else if (age >= 14) groupStats.over14++;

      // Elderly (Subset)
      if (age >= 60) groupStats.elderly60++;

      // Conditions
      if (p.isPregnant) groupStats.pregnant++;
      if (p.isPostpartum) groupStats.postpartum++;
      if (p.isBedridden) groupStats.bedridden++;
      if (p.hasMobilityIssues) groupStats.mobilityIssues++;
      if (p.isHypertensive) groupStats.hypertensive++;
      if (p.isDiabetic) groupStats.diabetic++;
      if (p.usesInsulin) groupStats.insulinUser++;
      if (p.hasOtherComorbidities) groupStats.otherComorbidities++;
    });

    setBasicStats({
      families: families.length,
      patients: myPatients.length,
      pending: pendingVisits,
      urgent: urgent,
    });

    setGroups(groupStats);

  }, [user]);

  const StatCard = ({ title, value, icon: Icon, color, subtext }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-start justify-between">
      <div>
        <p className="text-slate-500 text-sm font-medium mb-1">{title}</p>
        <h3 className="text-3xl font-bold text-slate-800">{value}</h3>
        {subtext && <p className="text-xs text-slate-400 mt-2">{subtext}</p>}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon size={24} className="text-white" />
      </div>
    </div>
  );

  const GroupItem = ({ label, value, colorClass }: any) => (
    <div className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-lg shadow-sm hover:shadow-md transition-shadow">
      <span className="text-sm font-medium text-slate-600">{label}</span>
      <span className={`text-sm font-bold px-2.5 py-0.5 rounded-full ${colorClass}`}>
        {value}
      </span>
    </div>
  );

  return (
    <div className="space-y-6 pb-20">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-slate-800">Visão Geral</h1>
        <p className="text-slate-500">Bem-vindo(a) de volta, {user?.name}</p>
      </div>

      {/* Main Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Famílias Cadastradas" 
          value={basicStats.families} 
          icon={Home} 
          color="bg-blue-500" 
        />
        <StatCard 
          title="Visitas Pendentes" 
          value={basicStats.pending} 
          icon={CalendarClock} 
          color="bg-amber-500" 
          subtext="Necessitam atenção imediata"
        />
        <StatCard 
          title="Alta Prioridade" 
          value={basicStats.urgent} 
          icon={AlertTriangle} 
          color="bg-red-500" 
        />
        <StatCard 
          title="Total de Pacientes" 
          value={basicStats.patients} 
          icon={Users} 
          color="bg-emerald-500" 
        />
      </div>

      {/* Detailed Attention Groups Section */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h2 className="font-bold text-lg mb-6 text-slate-800 flex items-center">
            <Activity className="mr-2 text-blue-600" />
            Grupos de Atenção
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Column 1: Age Groups */}
            <div>
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
                    Faixa Etária
                </h3>
                <div className="space-y-3">
                    <GroupItem 
                        label="Crianças 0 anos" 
                        value={groups.child0} 
                        colorClass="bg-blue-100 text-blue-700" 
                    />
                    <GroupItem 
                        label="Crianças 1 a 5 anos" 
                        value={groups.child1to5} 
                        colorClass="bg-indigo-100 text-indigo-700" 
                    />
                    <GroupItem 
                        label="Crianças 5 a 9 anos" 
