                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={handleCompleteVisit}
                    disabled={!visitNotes.trim()}
                    className={`flex-1 px-6 py-3 sm:py-2 rounded-lg transition-colors font-bold shadow-sm text-center
                        ${!visitNotes.trim() 
                            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
                  >
                    Confirmar Visita
                  </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { storageService } from './storage';
import { User, UserRole } from '../types';

class NotificationService {
  private hasNotifiedSession = false;

  public isSupported(): boolean {
    return 'Notification' in window;
  }

  public getPermissionStatus(): NotificationPermission {
    if (!this.isSupported()) return 'denied';
    return Notification.permission;
  }

  public async requestPermission(): Promise<boolean> {
    if (!this.isSupported()) return false;
    if (Notification.permission === 'granted') return true;

    try {
      const result = await Notification.requestPermission();
      return result === 'granted';
    } catch (error) {
      console.error('Error requesting notification permission:', error);
      return false;
    }
  }

  public checkForNotifications(user: User) {
    if (!this.isSupported() || Notification.permission !== 'granted') return;

    // Admin typically doesn't have visits assigned personally in this model, 
    // but if they did, we'd check via ID.
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    const now = new Date();
    // Normalize "now" to start of day for accurate comparison
    now.setHours(0, 0, 0, 0);

    const threeDaysFromNow = new Date(now);
    threeDaysFromNow.setDate(now.getDate() + 3);

    let overdueCount = 0;
    let upcomingCount = 0;

    families.forEach(fam => {
      const visitDate = new Date(fam.nextVisit);
      // Normalize visit date
      visitDate.setHours(0, 0, 0, 0);

      if (visitDate < now) {
        overdueCount++;
      } else if (visitDate <= threeDaysFromNow) {
        upcomingCount++;
      }
    });

    const totalAlerts = overdueCount + upcomingCount;

    // Only notify if there are alerts and we haven't spammed the user this session
    // Or if the count is significant
    if (totalAlerts > 0 && !this.hasNotifiedSession) {
      this.sendNotification(overdueCount, upcomingCount);
      this.hasNotifiedSession = true;
    }

    return { overdueCount, upcomingCount };
  }

  private sendNotification(overdue: number, upcoming: number) {
    const title = "Alerta ACS - Visitas Pendentes";
    let body = "";

    if (overdue > 0) body += `⚠️ ${overdue} visita(s) atrasada(s). `;
    if (upcoming > 0) body += `📅 ${upcoming} visita(s) vencem em breve.`;

    // Create the notification
    const notification = new Notification(title, {
      body: body.trim(),
      icon: 'https://cdn-icons-png.flaticon.com/512/2966/2966327.png', // Generic health icon or app logo URL
      tag: 'acs-visit-alert', // Prevents stacking multiple notifications
      requireInteraction: true // Keeps notification on screen until user interacts
    });

    notification.onclick = () => {
      window.focus();
      window.location.hash = '#/visits'; // Navigate to visits page
      notification.close();
    };
  }
}

