  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');
  const [alerts, setAlerts] = useState({ overdue: 0, upcoming: 0 });

  const isActive = (path: string) => location.pathname === path;

  // Initialize Notifications
  useEffect(() => {
    if (!user) return;

    const initNotifications = async () => {
      // Check current permission status
      const status = notificationService.getPermissionStatus();
      setNotificationPermission(status);

      // Run initial check
      runNotificationCheck();
    };

    initNotifications();

    // Check periodically (e.g., every 5 minutes)
    const intervalId = setInterval(runNotificationCheck, 5 * 60 * 1000);

    return () => clearInterval(intervalId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const runNotificationCheck = () => {
    if (user) {
      const result = notificationService.checkForNotifications(user);
      if (result) {
        setAlerts({ overdue: result.overdueCount, upcoming: result.upcomingCount });
      }
    }
  };

