    return matchesName && matchesFilter;
  });

  const FilterButton = ({ id, label, icon: Icon, colorClass, activeColorClass }: any) => {
    const isActive = activeFilters.includes(id);
    return (
      <button
        onClick={() => toggleFilter(id)}
