import { storageService } from './storage';
import { User, UserRole } from '../types';

class NotificationService {
  private lastNotificationTime = 0;
  private lastAlertCount = 0;
  private readonly NOTIFICATION_COOLDOWN = 60 * 60 * 1000; // 1 hour

  public isSupported(): boolean {
    return 'Notification' in window;
  }

  public getPermissionStatus(): NotificationPermission {
    if (!this.isSupported()) return 'denied';
    return Notification.permission;
  }

  public async requestPermission(): Promise<boolean> {
    if (!this.isSupported()) return false;
    if (Notification.permission === 'granted') return true;

    try {
      const result = await Notification.requestPermission();
      return result === 'granted';
    } catch (error) {
      console.error('Error requesting notification permission:', error);
      return false;
    }
  }

  public checkForNotifications(user: User) {
    if (!this.isSupported() || Notification.permission !== 'granted') return;

    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    const now = new Date();
    // Normalize "now" to start of day for accurate comparison
    const todayStart = new Date(now);
    todayStart.setHours(0, 0, 0, 0);

    const threeDaysFromNow = new Date(todayStart);
    threeDaysFromNow.setDate(todayStart.getDate() + 3);

    let overdueCount = 0;
    let upcomingCount = 0;

    families.forEach(fam => {
      const visitDate = new Date(fam.nextVisit);
      // Normalize visit date to comparison
      const visitDateNorm = new Date(visitDate);
      visitDateNorm.setHours(0, 0, 0, 0);

      if (visitDateNorm < todayStart) {
        overdueCount++;
      } else if (visitDateNorm <= threeDaysFromNow) {
        upcomingCount++;
      }
    });

    const totalAlerts = overdueCount + upcomingCount;
    const currentTime = Date.now();

    // Logic: Notify if there are alerts AND (alerts increased OR cooldown passed)
    const shouldNotify = totalAlerts > 0 && (
        totalAlerts > this.lastAlertCount || // Something new happened
        (currentTime - this.lastNotificationTime > this.NOTIFICATION_COOLDOWN) // Reminder time
    );

    if (shouldNotify) {
      this.sendNotification(overdueCount, upcomingCount);
      this.lastNotificationTime = currentTime;
      this.lastAlertCount = totalAlerts;
    }

    return { overdueCount, upcomingCount };
  }

  private sendNotification(overdue: number, upcoming: number) {
    const title = "Alerta ACS - Atenção Necessária";
    let body = "";

    if (overdue > 0) {
        body = `⚠️ Você tem ${overdue} visita(s) atrasada(s)!`;
    } else if (upcoming > 0) {
        body = `📅 ${upcoming} visita(s) vencem nos próximos 3 dias.`;
    }

    if (overdue > 0 && upcoming > 0) {
        body = `⚠️ ${overdue} atrasada(s) e 📅 ${upcoming} próxima(s).`;
    }

    // Create the notification
    const notification = new Notification(title, {
      body: body,
      icon: 'https://cdn-icons-png.flaticon.com/512/2966/2966327.png', // Generic health icon
      tag: 'acs-visit-alert', // Prevents stacking multiple notifications
      requireInteraction: true // Keeps notification on screen until user interacts
    });

    notification.onclick = () => {
      window.focus();
      // Simple hash navigation since we don't have full router access here easily
      window.location.hash = '#/visits'; 
      notification.close();
    };
  }
}

