              <div className="bg-blue-100 p-2 rounded-full mr-3 text-blue-600">
                  <BellRing size={20} />
              </div>
              <div>
                  <h3 className="font-bold text-blue-900">Não perca os prazos!</h3>
                  <p className="text-sm text-blue-700">Ative as notificações para receber alertas automáticos de visitas atrasadas e urgentes.</p>
              </div>
           </div>
           <button 
             onClick={requestNotificationAccess}
             className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold text-sm hover:bg-blue-700 transition-colors shadow-sm whitespace-nowrap"
