  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentFamily, setCurrentFamily] = useState<Partial<Family>>({});

  // Patient Management States
  const [activeTab, setActiveTab] = useState<'details' | 'members'>('details');
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [currentMember, setCurrentMember] = useState<Partial<Patient>>({});

  useEffect(() => {
    loadFamilies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadFamilies = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    setFamilies(storageService.getFamilies(agentFilter));
  };

  const loadMembers = (familyId: string) => {
    setFamilyMembers(storageService.getPatients(familyId));
  };

  // --- Family Handlers ---

  const handleOpenModal = (family?: Family) => {
    if (family) {
      setCurrentFamily({ ...family });
      setIsEditing(true);
      loadMembers(family.id);
      setActiveTab('details');
    } else {
      setCurrentFamily({
        address: '',
        number: '',
        neighborhood: '',
        phone: '',
        email: '',
        riskLevel: 'LOW',
        membersCount: 0
      });
      setIsEditing(false);
      setFamilyMembers([]);
      setActiveTab('details');
    }
    setShowModal(true);
    setShowMemberForm(false);
  };

  const handleSaveFamily = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    const familyToSave: Family = {
      id: currentFamily.id || crypto.randomUUID(),
      agentId: currentFamily.agentId || user.id,
      address: currentFamily.address!,
      number: currentFamily.number!,
      neighborhood: currentFamily.neighborhood!,
      membersCount: currentFamily.membersCount || 0,
      riskLevel: currentFamily.riskLevel || 'LOW',
      phone: currentFamily.phone,
      email: currentFamily.email,
      lastVisit: currentFamily.lastVisit || null,
      nextVisit: currentFamily.nextVisit || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), // Default 1 year if new
    };

    storageService.saveFamily(familyToSave);
    loadFamilies();

    // If it was a new family, we need to set the ID to allow adding members immediately without closing modal
    if (!isEditing) {
      setCurrentFamily(familyToSave);
      setIsEditing(true);
    } else {
      setShowModal(false);
    }
  };

  const handleDeleteFamily = () => {
    if (currentFamily.id && confirm('Tem certeza? Isso apagará também todos os pacientes e histórico desta família.')) {
      storageService.deleteFamily(currentFamily.id);
      loadFamilies();
      setShowModal(false);
    }
  };

  // --- Member Handlers ---

  const handleOpenMemberForm = (member?: Patient) => {
    if (member) {
      setCurrentMember({ ...member });
    } else {
      setCurrentMember({
        name: '',
        susNumber: '',
        birthDate: '',
        isPregnant: false,
        isPostpartum: false,
        isBedridden: false,
        hasMobilityIssues: false,
        isDiabetic: false,
        isHypertensive: false,
        usesInsulin: false,
        hasPsychologicalIssues: false,
        hasOtherComorbidities: false,
        medications: [],
        addictions: []
      });
    }
    setShowMemberForm(true);
  };

