    e.preventDefault();
    if (!currentFamily.id) return;

    const memberToSave: Patient = {
        id: currentMember.id || crypto.randomUUID(),
        familyId: currentFamily.id,
        name: currentMember.name!,
        susNumber: currentMember.susNumber!,
