        <div>
            <h1 className="text-2xl font-bold text-slate-800">Famílias Acompanhadas</h1>
            <p className="text-slate-500 text-sm">Gerencie os cadastros e integrantes</p>
        </div>
        <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-4 py-2.5 rounded-lg flex items-center hover:bg-blue-700 transition-colors shadow-sm shadow-blue-200 font-medium w-full md:w-auto justify-center"
        >
            <Plus size={20} className="mr-2" /> Nova Família
        </button>
      </div>

      {/* Search Bar */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search"
          placeholder="Buscar por rua, bairro ou número..."
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredFamilies.map(family => {
          const riskConfig = getRiskConfig(family.riskLevel);

          return (
            <div 
                key={family.id} 
                onClick={() => handleOpenModal(family)}
                className="bg-white p-5 rounded-xl border border-slate-200 hover:shadow-lg transition-all duration-200 group cursor-pointer active:scale-[0.98]"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="bg-blue-50 p-2.5 rounded-full group-hover:bg-blue-100 transition-colors">
                  <MapPin className="text-blue-500" size={20} />
                </div>
                <span className={`text-xs font-bold px-2.5 py-1 rounded-full border ${riskConfig.className} flex items-center`}>
                  {family.riskLevel !== 'LOW' && <AlertTriangle size={10} className="mr-1" />}
                  {riskConfig.label}
                </span>
              </div>

              <h3 className="font-bold text-lg text-slate-800 leading-tight mb-1">{family.address}, {family.number}</h3>
              <p className="text-sm text-slate-500 mb-5">{family.neighborhood}</p>

              <div className="flex items-center justify-between text-xs font-medium text-slate-500 border-t border-slate-100 pt-4">
                <span className="bg-slate-50 px-2 py-1 rounded text-slate-600 flex items-center">
                  <User size={12} className="mr-1"/>
                  {family.membersCount} Integrante{family.membersCount !== 1 ? 's' : ''}
                </span>
                <span className="text-blue-600 group-hover:underline flex items-center">
                  Gerenciar <ChevronRight size={12} className="ml-1" />
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {filteredFamilies.length === 0 && (
          <div className="text-center py-12 text-slate-400">
              <Home size={48} className="mx-auto mb-4 opacity-50" />
              <p>Nenhuma família encontrada.</p>
          </div>
      )}

      {/* Main Family Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <h2 className="text-lg font-bold text-slate-800">
                    {isEditing ? 'Gerenciar Família' : 'Nova Família'}
                </h2>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-1">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs */}
            {isEditing && (
                <div className="flex border-b border-slate-100 shrink-0">
                    <button 
                        onClick={() => setActiveTab('details')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Dados Cadastrais
                    </button>
                    <button 
                        onClick={() => setActiveTab('members')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'members' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Integrantes ({familyMembers.length})
                    </button>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-6 overflow-y-auto">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Logradouro / Rua</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.address || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Bairro / Comunidade</label>
                            <input 
                                required
                                className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                value={currentFamily.neighborhood || ''}
                                onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone Principal</label>
                                <div className="relative">
                                    <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-between items-center border-t border-slate-100 mt-6">
                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-medium flex items-center transition-colors"
                                >
                                    <Trash2 size={16} className="mr-2" /> Excluir Família
                                </button>
                             )}
                             <button 
                                type="submit" 
                                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold hover:bg-blue-700 shadow-sm ml-auto flex items-center"
                             >
                                <Save size={18} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>
                        </div>
                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-4">
                        {!showMemberForm ? (
                            <>
                                <button 
                                    onClick={() => handleOpenMemberForm()}
                                    className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-blue-600 font-medium hover:bg-blue-50 hover:border-blue-300 transition-colors flex items-center justify-center"
                                >
                                    <UserPlus size={20} className="mr-2" /> Adicionar Integrante
                                </button>

                                <div className="space-y-3 mt-4">
                                    {familyMembers.map(member => (
                                        <div key={member.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg border border-slate-200">
                                            <div className="flex items-center">
                                                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-400 border border-slate-200 mr-3">
                                                    <User size={20} />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                                    <div className="flex gap-2 text-xs text-slate-500">
                                                        <span>SUS: {member.susNumber}</span>
                                                        <span>•</span>
                                                        <span>{new Date(member.birthDate).toLocaleDateString()}</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => handleOpenMemberForm(member)}
                                                    className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                                                >
                                                    <Edit size={16} />
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteMember(member.id)}
                                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                    {familyMembers.length === 0 && (
                                        <div className="text-center text-slate-400 py-4 text-sm">
                                            Nenhum integrante cadastrado nesta família.
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            // Member Form
                            <form onSubmit={handleSaveMember} className="space-y-4 animate-in slide-in-from-right duration-200">
                                <div className="flex items-center text-slate-500 mb-2">
                                    <button type="button" onClick={() => setShowMemberForm(false)} className="hover:text-blue-600 text-sm flex items-center">
                                        <ChevronRight size={16} className="rotate-180 mr-1" /> Voltar
                                    </button>
                                    <span className="mx-2 text-slate-300">|</span>
                                    <span className="text-sm font-medium text-slate-800">{currentMember.id ? 'Editar Paciente' : 'Novo Paciente'}</span>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
                                    <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.name || ''} onChange={e => setCurrentMember(prev => ({ ...prev, name: e.target.value }))} />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Cartão SUS</label>
                                        <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.susNumber || ''} onChange={e => setCurrentMember(prev => ({ ...prev, susNumber: e.target.value }))} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                                        <input type="date" required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.birthDate?.split('T')[0] || ''} onChange={e => setCurrentMember(prev => ({ ...prev, birthDate: e.target.value }))} />
                                    </div>
                                </div>

                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-4">
                                    <h4 className="font-bold text-slate-800 text-sm mb-3">Condições de Saúde</h4>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                        <ConditionCheckbox label="Gestante" field="isPregnant" icon={Baby} />
                                        <ConditionCheckbox label="Diabético(a)" field="isDiabetic" icon={Droplets} />
                                        <ConditionCheckbox label="Hipertenso(a)" field="isHypertensive" icon={HeartPulse} />
                                        <ConditionCheckbox label="Acamado(a)" field="isBedridden" icon={Bed} />
                                        <ConditionCheckbox label="Saúde Mental" field="hasPsychologicalIssues" icon={Brain} />
                                        <ConditionCheckbox label="Outras" field="hasOtherComorbidities" icon={Activity} />
                                    </div>
                                </div>

                                <button type="submit" className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-bold hover:bg-blue-700 mt-4 shadow-sm">
                                    Salvar Integrante
                                </button>
                            </form>
                        )}
                    </div>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { 
  Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, 
  Search, X, User, Activity, Droplets, ChevronLeft, Filter, Phone, Mail, Save,
  UserPlus, Accessibility, Syringe, FilePlus, Clipboard, RotateCcw, Paperclip
} from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);

  // Visit Form States
  const [visitNotes, setVisitNotes] = useState('');
  const [visitObservations, setVisitObservations] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New state for patient search inside modal
  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  // New state for health status filters
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  // State for contact saving feedback
  const [contactSaved, setContactSaved] = useState(false);

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
    setVisitObservations('');
    setPatientSearchTerm(''); // Reset patient search when opening a family
    setActiveFilters([]); // Reset filters
    setContactSaved(false);
  };

  const handleFamilyUpdate = (field: 'phone' | 'email', value: string) => {
    if (selectedFamily) {
        setSelectedFamily({ ...selectedFamily, [field]: value });
        setContactSaved(false);
    }
  };

  const saveFamilyContact = () => {
    if (selectedFamily) {
        storageService.saveFamily(selectedFamily);
        setContactSaved(true);
        loadVisits(); // Update the main list in background
        setTimeout(() => setContactSaved(false), 3000);
    }
  };

  const toggleFilter = (filter: string) => {
    setActiveFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    // Save contact info implicitly when completing visit
    storageService.saveFamily(selectedFamily);

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      generalObservations: visitObservations,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const getDaysUntilVisit = (dateString: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const visitDate = new Date(dateString);
    visitDate.setHours(0,0,0,0);
    const diffTime = visitDate.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) {
        return <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-full flex items-center w-fit">Sem queixas registradas</span>;
    }

    return (
      <div className="flex flex-wrap gap-2 mt-2">
        {patient.isPregnant && (
            <span className="px-2 py-1 bg-pink-100 text-pink-700 text-xs font-medium rounded-md flex items-center border border-pink-200">
                <Baby size={12} className="mr-1.5"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-2 py-1 bg-rose-100 text-rose-700 text-xs font-medium rounded-md flex items-center border border-rose-200">
                <UserPlus size={12} className="mr-1.5"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-medium rounded-md flex items-center border border-purple-200">
                <Bed size={12} className="mr-1.5"/>Acamado(a)
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-2 py-1 bg-orange-100 text-orange-700 text-xs font-medium rounded-md flex items-center border border-orange-200">
                <Accessibility size={12} className="mr-1.5"/>Dif. Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-md flex items-center border border-blue-200">
                <Droplets size={12} className="mr-1.5"/>Diabético(a)
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-2 py-1 bg-sky-100 text-sky-700 text-xs font-medium rounded-md flex items-center border border-sky-200">
                <Syringe size={12} className="mr-1.5"/>Uso de Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-medium rounded-md flex items-center border border-red-200">
                <HeartPulse size={12} className="mr-1.5"/>Hipertenso(a)
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs font-medium rounded-md flex items-center border border-yellow-200">
                <Brain size={12} className="mr-1.5"/>Saúde Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-2 py-1 bg-slate-100 text-slate-700 text-xs font-medium rounded-md flex items-center border border-slate-200">
                <FilePlus size={12} className="mr-1.5"/>Outras
            </span>
        )}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  // Filter patients based on patient search term AND active status filters
  const filteredPatients = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(patientSearchTerm.toLowerCase());

    if (activeFilters.length === 0) return matchesName;

    // Filter Logic: OR (If patient has AT LEAST one of the selected conditions)
    const matchesFilter = activeFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  const FilterButton = ({ id, label, icon: Icon, colorClass, activeColorClass }: any) => {
    const isActive = activeFilters.includes(id);
    return (
      <button
        onClick={() => toggleFilter(id)}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isActive ? activeColorClass : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
      >
        <Icon size={12} className="mr-1.5" />
        {label}
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0"> {/* Add padding bottom for mobile if needed */}
      <h1 className="text-2xl font-bold text-slate-800 mb-6 px-1">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative mx-1">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search" // Optimized for mobile keyboards
          placeholder="Buscar por rua, número ou bairro..."
          className="w-full pl-10 pr-10 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all text-base bg-white" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {filteredFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md active:scale-[0.99] touch-manipulation ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
                <p className="text-slate-500 text-sm">{family.neighborhood} • {family.membersCount} integrantes</p>
                <div className="mt-2 text-xs text-slate-400">
                  Última visita: {family.lastVisit ? new Date(family.lastVisit).toLocaleDateString() : 'Nunca'}
                </div>
              </div>
              <div className="text-right">
                <div className="mb-1">{getUrgencyText(family.nextVisit)}</div>
                <div className="text-xs text-slate-400">Meta: {new Date(family.nextVisit).toLocaleDateString()}</div>
              </div>
            </div>
            {/* Quick indicators of family health profile */}
            <div className="mt-3 flex gap-2">
                {family.riskLevel === 'URGENT' && <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded">Prioridade Máxima</span>}
                {family.riskLevel === 'HIGH' && <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded">Prioridade Alta</span>}
            </div>
          </div>
        ))}

        {filteredFamilies.length === 0 && (
          <div className="text-center py-12 bg-white rounded-lg mx-1">
            {searchTerm ? (
              <>
                <Search className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Nenhum resultado encontrado</h3>
                <p className="text-slate-500">Tente buscar por outro termo.</p>
              </>
            ) : (
              <>
                <CheckCircle className="mx-auto text-green-500 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Tudo em dia!</h3>
                <p className="text-slate-500">Nenhuma visita pendente para sua área.</p>
              </>
            )}
          </div>
        )}
      </div>

      {/* Responsive Modal for Visit Execution */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
          {/* Mobile: Full Screen (h-[100dvh]), Desktop: Modal Card */}
          <div className="bg-white w-full h-[100dvh] sm:h-auto sm:max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden transition-all transform animate-in slide-in-from-bottom duration-200">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setShowModal(false)} 
                    className="sm:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-200 rounded-full"
                  >
                    <ChevronLeft size={24} />
                  </button>
                  <div>
                    <h2 className="text-lg sm:text-xl font-bold text-slate-800 leading-tight">Registrar Visita</h2>
                    <p className="text-xs sm:text-sm text-slate-500 flex items-center mt-0.5">
                        <User size={12} className="mr-1"/> {selectedFamily.address}, {selectedFamily.number}
                    </p>
                  </div>
              </div>
              <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full">
                  <X size={24} />
              </button>
            </div>

            {/* Content - Scrollable */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30">

              {/* Alert Banner for Visit Deadline */}
              {(() => {
                const diffDays = getDaysUntilVisit(selectedFamily.nextVisit);
                if (diffDays <= 7) {
                    return (
                        <div className={`p-4 rounded-lg border-l-4 shadow-sm flex items-start animate-in slide-in-from-top duration-300 ${
                            diffDays < 0 ? 'bg-red-50 border-red-500 text-red-900' : 'bg-orange-50 border-orange-500 text-orange-900'
                        }`}>
                            {diffDays < 0 ? (
                                <AlertCircle className="shrink-0 mr-3 text-red-600" size={24} />
                            ) : (
                                <Clock className="shrink-0 mr-3 text-orange-600" size={24} />
                            )}
                            <div>
                                <h4 className="font-bold text-sm uppercase tracking-wide mb-1">
                                    {diffDays < 0 ? 'Visita Atrasada' : 'Prazo Próximo'}
                                </h4>
                                <p className="text-sm opacity-90 leading-relaxed">
                                    {diffDays < 0 
                                        ? `O prazo para esta visita expirou há ${Math.abs(diffDays)} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                        : diffDays === 0 
                                            ? 'O prazo para realizar esta visita é HOJE.'
                                            : `Esta visita vence em ${diffDays} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                    }
                                </p>
                            </div>
                        </div>
                    );
                }
                return null;
              })()}

              {/* Family Contact Editable Section */}
              <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                 <div className="flex justify-between items-center mb-3">
                     <h3 className="font-bold text-slate-700 text-sm flex items-center">
                         <Phone size={14} className="mr-2 text-blue-500" />
                         Contatos do Responsável
                     </h3>
                     {contactSaved && <span className="text-xs text-green-600 font-bold flex items-center animate-in fade-in"><CheckCircle size={12} className="mr-1"/> Salvo</span>}
                 </div>

                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <div className="relative">
                        <Phone size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="tel" 
                            placeholder="Telefone"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.phone || ''}
                            onChange={(e) => handleFamilyUpdate('phone', e.target.value)}
                        />
                    </div>
                    <div className="relative">
                        <Mail size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="email" 
                            placeholder="Email"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.email || ''}
                            onChange={(e) => handleFamilyUpdate('email', e.target.value)}
                        />
                    </div>
                 </div>
                 <div className="mt-3 flex justify-end">
                    <button 
                        onClick={saveFamilyContact}
                        className="text-xs font-medium text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors flex items-center border border-blue-100 shadow-sm"
                    >
                        <Save size={12} className="mr-1.5" />
                        Salvar Contatos
                    </button>
                 </div>
              </div>

              {/* Detailed Member Summary */}
              <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                <h3 className="font-bold text-blue-900 mb-4 flex items-center">
                    <Activity size={18} className="mr-2"/> 
                    Prontuário da Família
                </h3>

                {/* Patient Search Input inside Modal */}
                <div className="relative mb-3">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                  <input 
                    type="text"
                    placeholder="Buscar paciente pelo nome..."
                    className="w-full pl-9 pr-9 py-2.5 rounded-lg border border-blue-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white shadow-sm"
                    value={patientSearchTerm}
                    onChange={(e) => setPatientSearchTerm(e.target.value)}
                  />
                  {patientSearchTerm && (
                    <button 
                      onClick={() => setPatientSearchTerm('')}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                    >
                      <X size={14} />
                    </button>
                  )}
                </div>

                {/* Filter Chips */}
                <div className="flex flex-wrap gap-2 mb-4 items-center">
                    <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                        <Filter size={14} className="mr-1" />
                        Filtros:
                    </div>
                    <FilterButton 
                        id="pregnant" 
                        label="Gestante" 
                        icon={Baby} 
                        colorClass="" 
                        activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                    />
                    <FilterButton 
                        id="bedridden" 
                        label="Acamado" 
                        icon={Bed} 
                        colorClass="" 
                        activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                    />
                    <FilterButton 
                        id="diabetic" 
                        label="Diabético" 
                        icon={Droplets} 
                        colorClass="" 
                        activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                    />
                    <FilterButton 
                        id="hypertensive" 
                        label="Hipertenso" 
                        icon={HeartPulse} 
                        colorClass="" 
                        activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                    />
                    <FilterButton 
                        id="psychological" 
                        label="Saúde Mental" 
                        icon={Brain} 
                        colorClass="" 
                        activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                    />

                    {activeFilters.length > 0 && (
                        <button 
                            onClick={() => setActiveFilters([])}
                            className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                        >
                            <RotateCcw size={10} className="mr-1" /> Limpar
                        </button>
                    )}
                </div>

                <div className="space-y-3">
                  {filteredPatients.length > 0 ? (
                    filteredPatients.map(member => (
                      <div key={member.id} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm animate-in fade-in duration-200">
                        <div className="flex justify-between items-start mb-2">
                          <div className="flex items-center">
                              <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 shrink-0">
                                  <User size={16} />
                              </div>
                              <div>
                                  <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                  <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos</span>
                              </div>
                          </div>
                          <div className="text-right">
                              <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">SUS: {member.susNumber}</span>
                          </div>
                        </div>

                        <div className="pl-11">
                            <PatientBadge patient={member} />
                            {(member.medications.length > 0) && (
                              <div className="mt-3 text-xs bg-slate-50 p-2 rounded border border-slate-100 text-slate-600">
                                  <span className="font-semibold text-slate-700">Medicamentos:</span> {member.medications.join(', ')}
                              </div>
                            )}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-6 text-slate-500 bg-white/50 rounded-lg border border-blue-100 border-dashed">
                      <p>Nenhum paciente encontrado com os filtros selecionados.</p>
                      {activeFilters.length > 0 && (
                          <button 
                            onClick={() => setActiveFilters([])}
                            className="text-xs text-blue-600 font-medium mt-2 hover:underline"
                          >
                              Limpar Filtros
                          </button>
                      )}
                    </div>
                  )}
                </div>
              </div>

              {/* Visit Form */}
              <div className="bg-white p-1 rounded-lg space-y-4">
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2 px-1 flex items-center">
                        <Activity size={16} className="mr-1.5 text-blue-600" />
                        Relatório Técnico / Procedimentos
                    </label>
                    <textarea 
                      required
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={4}
                      placeholder="Descreva detalhadamente as aferições realizadas (PA, Glicemia), orientações fornecidas e observações técnicas..."
                      value={visitNotes}
                      onChange={(e) => setVisitNotes(e.target.value)}
                    ></textarea>
                </div>

                <div>
                    <div className="flex items-center justify-between mb-2">
                        <label className="block text-sm font-bold text-slate-700 px-1 flex items-center">
                            <Clipboard size={16} className="mr-1.5 text-orange-500" />
                            Observações Gerais da Visita
                        </label>
                        <button 
                            type="button" 
                            className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded-full transition-colors"
                            title="Anexar arquivo"
                        >
                            <Paperclip size={18} />
                        </button>
                    </div>
                    <textarea 
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={3}
                      placeholder="Registre detalhes adicionais, contexto social, observações do ambiente ou outras informações relevantes não técnicas..."
                      value={visitObservations}
                      onChange={(e) => setVisitObservations(e.target.value)}
                    ></textarea>
                </div>
              </div>
            </div>

            {/* Footer - Sticky at bottom */}
            <div className="p-4 border-t border-slate-100 bg-white shrink-0 safe-area-bottom">
                <div className="flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={handleCompleteVisit}
                    disabled={!visitNotes.trim()}
                    className={`flex-1 px-6 py-3 sm:py-2 rounded-lg transition-colors font-bold shadow-sm text-center
                        ${!visitNotes.trim() 
                            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
                  >
                    Confirmar Visita
                  </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { 
  Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, 
  Search, X, User, Activity, Droplets, ChevronLeft, Filter, Phone, Mail, Save,
  UserPlus, Accessibility, Syringe, FilePlus, Clipboard, RotateCcw, Paperclip
} from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);

  // Visit Form States
  const [visitNotes, setVisitNotes] = useState('');
  const [visitObservations, setVisitObservations] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New state for patient search inside modal
  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  // New state for health status filters
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  // State for contact saving feedback
  const [contactSaved, setContactSaved] = useState(false);

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
    setVisitObservations('');
    setPatientSearchTerm(''); // Reset patient search when opening a family
    setActiveFilters([]); // Reset filters
    setContactSaved(false);
  };

  const handleFamilyUpdate = (field: 'phone' | 'email', value: string) => {
    if (selectedFamily) {
        setSelectedFamily({ ...selectedFamily, [field]: value });
        setContactSaved(false);
    }
  };

  const saveFamilyContact = () => {
    if (selectedFamily) {
        storageService.saveFamily(selectedFamily);
        setContactSaved(true);
        loadVisits(); // Update the main list in background
        setTimeout(() => setContactSaved(false), 3000);
    }
  };

  const toggleFilter = (filter: string) => {
    setActiveFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    // Save contact info implicitly when completing visit
    storageService.saveFamily(selectedFamily);

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      generalObservations: visitObservations,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const getDaysUntilVisit = (dateString: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const visitDate = new Date(dateString);
    visitDate.setHours(0,0,0,0);
    const diffTime = visitDate.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) {
        return <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-full flex items-center w-fit">Sem queixas registradas</span>;
    }

    return (
      <div className="flex flex-wrap gap-2 mt-2">
        {patient.isPregnant && (
            <span className="px-2 py-1 bg-pink-100 text-pink-700 text-xs font-medium rounded-md flex items-center border border-pink-200">
                <Baby size={12} className="mr-1.5"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-2 py-1 bg-rose-100 text-rose-700 text-xs font-medium rounded-md flex items-center border border-rose-200">
                <UserPlus size={12} className="mr-1.5"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-medium rounded-md flex items-center border border-purple-200">
                <Bed size={12} className="mr-1.5"/>Acamado(a)
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-2 py-1 bg-orange-100 text-orange-700 text-xs font-medium rounded-md flex items-center border border-orange-200">
                <Accessibility size={12} className="mr-1.5"/>Dif. Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-md flex items-center border border-blue-200">
                <Droplets size={12} className="mr-1.5"/>Diabético(a)
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-2 py-1 bg-sky-100 text-sky-700 text-xs font-medium rounded-md flex items-center border border-sky-200">
                <Syringe size={12} className="mr-1.5"/>Uso de Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-medium rounded-md flex items-center border border-red-200">
                <HeartPulse size={12} className="mr-1.5"/>Hipertenso(a)
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs font-medium rounded-md flex items-center border border-yellow-200">
                <Brain size={12} className="mr-1.5"/>Saúde Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-2 py-1 bg-slate-100 text-slate-700 text-xs font-medium rounded-md flex items-center border border-slate-200">
                <FilePlus size={12} className="mr-1.5"/>Outras
            </span>
        )}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  // Filter patients based on patient search term AND active status filters
  const filteredPatients = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(patientSearchTerm.toLowerCase());

    if (activeFilters.length === 0) return matchesName;

    // Filter Logic: OR (If patient has AT LEAST one of the selected conditions)
    const matchesFilter = activeFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Count available conditions in the family
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeFilters.includes(id);
    const isDisabled = count === 0;

    return (
      <button
        onClick={() => !isDisabled && toggleFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0"> {/* Add padding bottom for mobile if needed */}
      <h1 className="text-2xl font-bold text-slate-800 mb-6 px-1">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative mx-1">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search" // Optimized for mobile keyboards
          placeholder="Buscar por rua, número ou bairro..."
          className="w-full pl-10 pr-10 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all text-base bg-white" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {filteredFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md active:scale-[0.99] touch-manipulation ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
                <p className="text-slate-500 text-sm">{family.neighborhood} • {family.membersCount} integrantes</p>
                <div className="mt-2 text-xs text-slate-400">
                  Última visita: {family.lastVisit ? new Date(family.lastVisit).toLocaleDateString() : 'Nunca'}
                </div>
              </div>
              <div className="text-right">
                <div className="mb-1">{getUrgencyText(family.nextVisit)}</div>
                <div className="text-xs text-slate-400">Meta: {new Date(family.nextVisit).toLocaleDateString()}</div>
              </div>
            </div>
            {/* Quick indicators of family health profile */}
            <div className="mt-3 flex gap-2">
                {family.riskLevel === 'URGENT' && <span className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded">Prioridade Máxima</span>}
                {family.riskLevel === 'HIGH' && <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded">Prioridade Alta</span>}
            </div>
          </div>
        ))}

        {filteredFamilies.length === 0 && (
          <div className="text-center py-12 bg-white rounded-lg mx-1">
            {searchTerm ? (
              <>
                <Search className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Nenhum resultado encontrado</h3>
                <p className="text-slate-500">Tente buscar por outro termo.</p>
              </>
            ) : (
              <>
                <CheckCircle className="mx-auto text-green-500 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Tudo em dia!</h3>
                <p className="text-slate-500">Nenhuma visita pendente para sua área.</p>
              </>
            )}
          </div>
        )}
      </div>

      {/* Responsive Modal for Visit Execution */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
          {/* Mobile: Full Screen (h-[100dvh]), Desktop: Modal Card */}
          <div className="bg-white w-full h-[100dvh] sm:h-auto sm:max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden transition-all transform animate-in slide-in-from-bottom duration-200">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setShowModal(false)} 
                    className="sm:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-200 rounded-full"
                  >
                    <ChevronLeft size={24} />
                  </button>
                  <div>
                    <h2 className="text-lg sm:text-xl font-bold text-slate-800 leading-tight">Registrar Visita</h2>
                    <p className="text-xs sm:text-sm text-slate-500 flex items-center mt-0.5">
                        <User size={12} className="mr-1"/> {selectedFamily.address}, {selectedFamily.number}
                    </p>
                  </div>
              </div>
              <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full">
                  <X size={24} />
              </button>
            </div>

            {/* Content - Scrollable */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30">

              {/* Alert Banner for Visit Deadline */}
              {(() => {
                const diffDays = getDaysUntilVisit(selectedFamily.nextVisit);
                if (diffDays <= 7) {
                    return (
                        <div className={`p-4 rounded-lg border-l-4 shadow-sm flex items-start animate-in slide-in-from-top duration-300 ${
                            diffDays < 0 ? 'bg-red-50 border-red-500 text-red-900' : 'bg-orange-50 border-orange-500 text-orange-900'
                        }`}>
                            {diffDays < 0 ? (
                                <AlertCircle className="shrink-0 mr-3 text-red-600" size={24} />
                            ) : (
                                <Clock className="shrink-0 mr-3 text-orange-600" size={24} />
                            )}
                            <div>
                                <h4 className="font-bold text-sm uppercase tracking-wide mb-1">
                                    {diffDays < 0 ? 'Visita Atrasada' : 'Prazo Próximo'}
                                </h4>
                                <p className="text-sm opacity-90 leading-relaxed">
                                    {diffDays < 0 
                                        ? `O prazo para esta visita expirou há ${Math.abs(diffDays)} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                        : diffDays === 0 
                                            ? 'O prazo para realizar esta visita é HOJE.'
                                            : `Esta visita vence em ${diffDays} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                    }
                                </p>
                            </div>
                        </div>
                    );
                }
                return null;
              })()}

              {/* Family Contact Editable Section */}
              <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                 <div className="flex justify-between items-center mb-3">
                     <h3 className="font-bold text-slate-700 text-sm flex items-center">
                         <Phone size={14} className="mr-2 text-blue-500" />
                         Contatos do Responsável
                     </h3>
                     {contactSaved && <span className="text-xs text-green-600 font-bold flex items-center animate-in fade-in"><CheckCircle size={12} className="mr-1"/> Salvo</span>}
                 </div>

                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <div className="relative">
                        <Phone size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="tel" 
                            placeholder="Telefone"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.phone || ''}
                            onChange={(e) => handleFamilyUpdate('phone', e.target.value)}
                        />
                    </div>
                    <div className="relative">
                        <Mail size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="email" 
                            placeholder="Email"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.email || ''}
                            onChange={(e) => handleFamilyUpdate('email', e.target.value)}
                        />
                    </div>
                 </div>
                 <div className="mt-3 flex justify-end">
                    <button 
                        onClick={saveFamilyContact}
                        className="text-xs font-medium text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors flex items-center border border-blue-100 shadow-sm"
                    >
                        <Save size={12} className="mr-1.5" />
                        Salvar Contatos
                    </button>
                 </div>
              </div>

              {/* Detailed Member Summary */}
              <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                <h3 className="font-bold text-blue-900 mb-4 flex items-center">
                    <Activity size={18} className="mr-2"/> 
                    Prontuário da Família
                </h3>

                {/* Patient Search Input inside Modal */}
                <div className="relative mb-3">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                  <input 
                    type="text"
                    placeholder="Buscar paciente pelo nome..."
                    className="w-full pl-9 pr-9 py-2.5 rounded-lg border border-blue-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white shadow-sm"
                    value={patientSearchTerm}
                    onChange={(e) => setPatientSearchTerm(e.target.value)}
                  />
                  {patientSearchTerm && (
                    <button 
                      onClick={() => setPatientSearchTerm('')}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                    >
                      <X size={14} />
                    </button>
                  )}
                </div>

                {/* Filter Chips */}
                <div className="flex flex-wrap gap-2 mb-4 items-center">
                    <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                        <Filter size={14} className="mr-1" />
                        Filtros:
                    </div>
                    <FilterButton 
                        id="pregnant" 
                        label="Gestante"
                        count={conditionCounts.pregnant}
                        icon={Baby} 
                        activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                    />
                    <FilterButton 
                        id="bedridden" 
                        label="Acamado" 
                        count={conditionCounts.bedridden}
                        icon={Bed} 
                        activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                    />
                    <FilterButton 
                        id="diabetic" 
                        label="Diabético" 
                        count={conditionCounts.diabetic}
                        icon={Droplets} 
                        activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                    />
                    <FilterButton 
                        id="hypertensive" 
                        label="Hipertenso" 
                        count={conditionCounts.hypertensive}
                        icon={HeartPulse} 
                        activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                    />
                    <FilterButton 
                        id="psychological" 
                        label="Saúde Mental" 
                        count={conditionCounts.psychological}
                        icon={Brain} 
                        activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                    />

                    {activeFilters.length > 0 && (
                        <button 
                            onClick={() => setActiveFilters([])}
                            className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                        >
                            <RotateCcw size={10} className="mr-1" /> Limpar
                        </button>
                    )}
                </div>

                <div className="space-y-3">
                  {filteredPatients.length > 0 ? (
                    filteredPatients.map(member => (
                      <div key={member.id} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm animate-in fade-in duration-200">
                        <div className="flex justify-between items-start mb-2">
                          <div className="flex items-center">
                              <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 shrink-0">
                                  <User size={16} />
                              </div>
                              <div>
                                  <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                  <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos</span>
                              </div>
                          </div>
                          <div className="text-right">
                              <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">SUS: {member.susNumber}</span>
                          </div>
                        </div>

                        <div className="pl-11">
                            <PatientBadge patient={member} />
                            {(member.medications.length > 0) && (
                              <div className="mt-3 text-xs bg-slate-50 p-2 rounded border border-slate-100 text-slate-600">
                                  <span className="font-semibold text-slate-700">Medicamentos:</span> {member.medications.join(', ')}
                              </div>
                            )}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-6 text-slate-500 bg-white/50 rounded-lg border border-blue-100 border-dashed">
                      <p>Nenhum paciente encontrado com os filtros selecionados.</p>
                      {activeFilters.length > 0 && (
                          <button 
                            onClick={() => setActiveFilters([])}
                            className="text-xs text-blue-600 font-medium mt-2 hover:underline"
                          >
                              Limpar Filtros
                          </button>
                      )}
                    </div>
                  )}
                </div>
              </div>

              {/* Visit Form */}
              <div className="bg-white p-1 rounded-lg space-y-4">
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2 px-1 flex items-center">
                        <Activity size={16} className="mr-1.5 text-blue-600" />
                        Relatório Técnico / Procedimentos
                    </label>
                    <textarea 
                      required
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={4}
                      placeholder="Descreva detalhadamente as aferições realizadas (PA, Glicemia), orientações fornecidas e observações técnicas..."
                      value={visitNotes}
                      onChange={(e) => setVisitNotes(e.target.value)}
                    ></textarea>
                </div>

                <div>
                    <div className="flex items-center justify-between mb-2">
                        <label className="block text-sm font-bold text-slate-700 px-1 flex items-center">
                            <Clipboard size={16} className="mr-1.5 text-orange-500" />
                            Observações Gerais da Visita
                        </label>
                        <button 
                            type="button" 
                            className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded-full transition-colors"
                            title="Anexar arquivo"
                        >
                            <Paperclip size={18} />
                        </button>
                    </div>
                    <textarea 
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={3}
                      placeholder="Registre detalhes adicionais, contexto social, observações do ambiente ou outras informações relevantes não técnicas..."
                      value={visitObservations}
                      onChange={(e) => setVisitObservations(e.target.value)}
                    ></textarea>
                </div>
              </div>
            </div>

            {/* Footer - Sticky at bottom */}
            <div className="p-4 border-t border-slate-100 bg-white shrink-0 safe-area-bottom">
                <div className="flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={handleCompleteVisit}
                    disabled={!visitNotes.trim()}
                    className={`flex-1 px-6 py-3 sm:py-2 rounded-lg transition-colors font-bold shadow-sm text-center
                        ${!visitNotes.trim() 
                            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
                  >
                    Confirmar Visita
                  </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { 
  Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, 
  Search, X, User, Activity, Droplets, ChevronLeft, Filter, Phone, Mail, Save,
  UserPlus, Accessibility, Syringe, FilePlus, Clipboard, RotateCcw, Paperclip
} from 'lucide-react';

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [allPatients, setAllPatients] = useState<Patient[]>([]); // New state for list view badges
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);

  // Visit Form States
  const [visitNotes, setVisitNotes] = useState('');
  const [visitObservations, setVisitObservations] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New state for patient search inside modal
  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  // New state for health status filters
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  // State for contact saving feedback
  const [contactSaved, setContactSaved] = useState(false);

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);

    // Load all patients to display badges in the list view
    const patients = storageService.getPatients();
    setAllPatients(patients);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    setVisitNotes('');
    setVisitObservations('');
    setPatientSearchTerm(''); // Reset patient search when opening a family
    setActiveFilters([]); // Reset filters
    setContactSaved(false);
  };

  const handleFamilyUpdate = (field: 'phone' | 'email', value: string) => {
    if (selectedFamily) {
        setSelectedFamily({ ...selectedFamily, [field]: value });
        setContactSaved(false);
    }
  };

  const saveFamilyContact = () => {
    if (selectedFamily) {
        storageService.saveFamily(selectedFamily);
        setContactSaved(true);
        loadVisits(); // Update the main list in background
        setTimeout(() => setContactSaved(false), 3000);
    }
  };

  const toggleFilter = (filter: string) => {
    setActiveFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    // Save contact info implicitly when completing visit
    storageService.saveFamily(selectedFamily);

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      generalObservations: visitObservations,
      outcome: 'Realizada',
      measurements: [] // In a full app, we would capture measurements here
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const getDaysUntilVisit = (dateString: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const visitDate = new Date(dateString);
    visitDate.setHours(0,0,0,0);
    const diffTime = visitDate.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  // Helper to render badges inside the family card list
  const FamilyConditionsBadges = ({ familyId }: { familyId: string }) => {
    const patients = allPatients.filter(p => p.familyId === familyId);

    // Aggregate conditions
    const counts = {
        pregnant: patients.filter(p => p.isPregnant).length,
        bedridden: patients.filter(p => p.isBedridden).length,
        diabetic: patients.filter(p => p.isDiabetic).length,
        hypertensive: patients.filter(p => p.isHypertensive).length,
        psychological: patients.filter(p => p.hasPsychologicalIssues).length,
        postpartum: patients.filter(p => p.isPostpartum).length,
    };

    const hasConditions = Object.values(counts).some(c => c > 0);

    if (!hasConditions) return null;

    return (
        <div className="mt-3 flex flex-wrap gap-2 border-t border-slate-100 pt-3">
            {counts.pregnant > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-pink-100 text-pink-700 border border-pink-200">
                    <Baby size={10} className="mr-1" /> Gestante {counts.pregnant > 1 && `(${counts.pregnant})`}
                </span>
            )}
            {counts.postpartum > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-rose-100 text-rose-700 border border-rose-200">
                    <UserPlus size={10} className="mr-1" /> Puérpera
                </span>
            )}
            {counts.bedridden > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-purple-100 text-purple-700 border border-purple-200">
                    <Bed size={10} className="mr-1" /> Acamado {counts.bedridden > 1 && `(${counts.bedridden})`}
                </span>
            )}
            {counts.diabetic > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-blue-100 text-blue-700 border border-blue-200">
                    <Droplets size={10} className="mr-1" /> Diabético {counts.diabetic > 1 && `(${counts.diabetic})`}
                </span>
            )}
            {counts.hypertensive > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700 border border-red-200">
                    <HeartPulse size={10} className="mr-1" /> Hipertenso {counts.hypertensive > 1 && `(${counts.hypertensive})`}
                </span>
            )}
            {counts.psychological > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-yellow-100 text-yellow-700 border border-yellow-200">
                    <Brain size={10} className="mr-1" /> Saúde Mental
                </span>
            )}
        </div>
    );
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) {
        return <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-full flex items-center w-fit">Sem queixas registradas</span>;
    }

    return (
      <div className="flex flex-wrap gap-2 mt-2">
        {patient.isPregnant && (
            <span className="px-2 py-1 bg-pink-100 text-pink-700 text-xs font-medium rounded-md flex items-center border border-pink-200">
                <Baby size={12} className="mr-1.5"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-2 py-1 bg-rose-100 text-rose-700 text-xs font-medium rounded-md flex items-center border border-rose-200">
                <UserPlus size={12} className="mr-1.5"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-medium rounded-md flex items-center border border-purple-200">
                <Bed size={12} className="mr-1.5"/>Acamado(a)
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-2 py-1 bg-orange-100 text-orange-700 text-xs font-medium rounded-md flex items-center border border-orange-200">
                <Accessibility size={12} className="mr-1.5"/>Dif. Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-md flex items-center border border-blue-200">
                <Droplets size={12} className="mr-1.5"/>Diabético(a)
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-2 py-1 bg-sky-100 text-sky-700 text-xs font-medium rounded-md flex items-center border border-sky-200">
                <Syringe size={12} className="mr-1.5"/>Uso de Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-medium rounded-md flex items-center border border-red-200">
                <HeartPulse size={12} className="mr-1.5"/>Hipertenso(a)
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs font-medium rounded-md flex items-center border border-yellow-200">
                <Brain size={12} className="mr-1.5"/>Saúde Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-2 py-1 bg-slate-100 text-slate-700 text-xs font-medium rounded-md flex items-center border border-slate-200">
                <FilePlus size={12} className="mr-1.5"/>Outras
            </span>
        )}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  // Filter patients based on patient search term AND active status filters
  const filteredPatients = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(patientSearchTerm.toLowerCase());

    if (activeFilters.length === 0) return matchesName;

    // Filter Logic: OR (If patient has AT LEAST one of the selected conditions)
    const matchesFilter = activeFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Count available conditions in the family
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeFilters.includes(id);
    const isDisabled = count === 0;

    return (
      <button
        onClick={() => !isDisabled && toggleFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0"> {/* Add padding bottom for mobile if needed */}
      <h1 className="text-2xl font-bold text-slate-800 mb-6 px-1">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative mx-1">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
