            {/* Content - Scrollable */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30">

              {/* Alert Banner for Visit Deadline */}
              {(() => {
                const diffDays = getDaysUntilVisit(selectedFamily.nextVisit);
                if (diffDays <= 7) {
                    return (
                        <div className={`p-4 rounded-lg border-l-4 shadow-sm flex items-start animate-in slide-in-from-top duration-300 ${
                            diffDays < 0 ? 'bg-red-50 border-red-500 text-red-900' : 'bg-orange-50 border-orange-500 text-orange-900'
                        }`}>
