                            value={selectedFamily.phone || ''}
                            onChange={(e) => handleFamilyUpdate('phone', e.target.value)}
                        />
                    </div>
                    <div className="relative">
                        <Mail size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="email" 
                            placeholder="Email"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.email || ''}
                            onChange={(e) => handleFamilyUpdate('email', e.target.value)}
                        />
