import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { Visits } from './pages/Visits';
import { Families } from './pages/Families';
import { Admin } from './pages/Admin';
import { Login } from './pages/Login';
import { Reports } from './pages/Reports';
import { UserRole, UserStatus } from './types';
import { Clock, Ban, CreditCard } from 'lucide-react';

const ProtectedRoute = ({ children, requiredRole }: { children: React.ReactNode, requiredRole?: UserRole }) => {
  const { user, refreshUser } = useAuth();

  // Refresh user data on navigation to ensure status is up to date
  React.useEffect(() => {
    refreshUser();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // 1. Check if user is PENDING approval
  if (user.status === UserStatus.PENDING) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Clock size={64} className="text-yellow-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Aguardando Aprovação</h1>
        <p className="text-slate-500 max-w-md">
          Seu cadastro foi realizado com sucesso. Aguarde a aprovação e ativação do plano pelo administrador.
        </p>
        <button onClick={() => window.location.reload()} className="mt-6 text-blue-600 hover:underline">Verificar novamente</button>
      </div>
    );
  }

  // 2. Check if user is BLOCKED manually
  if (user.status === UserStatus.BLOCKED) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Ban size={64} className="text-red-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Acesso Bloqueado</h1>
        <p className="text-slate-500">Entre em contato com o administrador para regularizar seu acesso.</p>
      </div>
    );
  }

  // 3. Check Subscription Expiration (Only for Agents, Admins bypass)
  if (user.role !== UserRole.ADMIN && user.subscriptionExpiresAt) {
    const expirationDate = new Date(user.subscriptionExpiresAt);
    const today = new Date();

    if (today > expirationDate) {
      return (
        <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
          <div className="bg-red-100 p-6 rounded-full mb-6">
            <CreditCard size={48} className="text-red-600" />
          </div>
          <h1 className="text-2xl font-bold text-slate-800 mb-2">Assinatura Expirada</h1>
          <p className="text-slate-500 max-w-md mb-6">
            O período de validade do seu acesso encerrou em <b>{expirationDate.toLocaleDateString()}</b>.
          </p>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 w-full max-w-sm">
            <p className="text-sm text-slate-600 mb-4">Para continuar utilizando o sistema e acessar seus dados, renove sua mensalidade ou anuidade.</p>
            <button className="w-full bg-blue-600 text-white font-bold py-3 rounded-lg hover:bg-blue-700 transition-colors">
              Falar com o Administrador
            </button>
          </div>
          <button onClick={refreshUser} className="mt-8 text-slate-400 text-sm hover:text-slate-600">
            Já paguei? Clique para atualizar
          </button>
        </div>
      );
    }
  }

  if (requiredRole && user.role !== requiredRole) {
    return <Navigate to="/" replace />;
  }

  return <Layout>{children}</Layout>;
};

const AppRoutes = () => {
  const { user } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/" replace /> : <Login />} />

      <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
      <Route path="/reports" element={<ProtectedRoute><Reports /></ProtectedRoute>} />
      <Route path="/visits" element={<ProtectedRoute><Visits /></ProtectedRoute>} />
      <Route path="/families" element={<ProtectedRoute><Families /></ProtectedRoute>} />

      <Route path="/admin" element={
        <ProtectedRoute requiredRole={UserRole.ADMIN}>
          <Admin />
        </ProtectedRoute>
      } />
    </Routes>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <AppRoutes />
      </HashRouter>
    </AuthProvider>
  );
}

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, ChevronDown, Check
} from 'lucide-react';

// Definitions for filters to make the code cleaner and scalable
const FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-700 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-700 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-700 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-700 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-700 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-700 border-sky-200' },
  { id: 'child_0_5', label: 'Crianças (0-5 anos)', icon: Baby, color: 'bg-indigo-100 text-indigo-700 border-indigo-200' },
  { id: 'elderly', label: 'Idosos (60+)', icon: User, color: 'bg-slate-200 text-slate-700 border-slate-300' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter
    const newCounts: Record<string, number> = {};
    FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });
    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      case 'child_0_5': return age <= 5;
      case 'elderly': return age >= 60;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const results = getFilteredResults();
  const currentFilterLabel = FILTERS.find(f => f.id === activeFilter)?.label;

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Selecione um card para filtrar famílias por condição de saúde.</p>
      </div>

      {/* Interactive Cards Grid */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
        {FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>

              {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-100 border-2 border-dashed border-slate-300 rounded-xl p-12 text-center">
             <Filter size={48} className="mx-auto text-slate-400 mb-4" />
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500">Clique em um dos cards acima para ver a lista de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className="bg-blue-600 text-white w-8 h-8 rounded-full flex items-center justify-center text-sm mr-3 font-bold">
                        {results.length}
                    </span>
                    Pacientes encontrados: {currentFilterLabel}
                </h2>
                <button 
                    onClick={() => setActiveFilter(null)}
                    className="text-sm text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-1 rounded-lg transition-colors"
                >
                    Limpar Filtro
                </button>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-8 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {results.map(({ patient, family }) => (
                        <div key={patient.id} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow flex flex-col md:flex-row md:items-center justify-between gap-4">
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 shrink-0">
                                    <User size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center">
                                            <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                        </span>
                                        <span className="flex items-center">
                                            <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                        </span>
                                    </div>

                                    {/* Address Display */}
                                    <div className="mt-3 flex items-start text-sm bg-blue-50 text-blue-800 p-2 rounded-lg">
                                        <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                        <div>
                                            <span className="font-bold block">Residência:</span>
                                            {family ? (
                                                <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                            ) : (
                                                <span className="text-red-500 italic">Endereço não vinculado</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Action Button */}
                            <div className="md:text-right shrink-0">
                                <div className="mb-2">
                                    {patient.isPregnant && <span className="inline-block px-2 py-1 bg-pink-100 text-pink-800 text-xs rounded-full mr-1 mb-1">Gestante</span>}
                                    {patient.isDiabetic && <span className="inline-block px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full mr-1 mb-1">Diabético</span>}
                                    {patient.isHypertensive && <span className="inline-block px-2 py-1 bg-red-100 text-red-800 text-xs rounded-full mr-1 mb-1">Hipertenso</span>}
                                </div>

                                {/* We link to Families page but purely visual here as we don't have deep link state logic set up in this iteration */}
                                <div className="text-xs text-slate-400 italic">
                                    Localizado na lista de Famílias
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

