export const Families: React.FC = () => {
  const { user } = useAuth();
  const [families, setFamilies] = useState<Family[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentFamily, setCurrentFamily] = useState<Partial<Family>>({});

  // Patient Management States
  const [activeTab, setActiveTab] = useState<'details' | 'members'>('details');
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [currentMember, setCurrentMember] = useState<Partial<Patient>>({});

  useEffect(() => {
    loadFamilies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadFamilies = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    setFamilies(storageService.getFamilies(agentFilter));
  };

  const loadMembers = (familyId: string) => {
    setFamilyMembers(storageService.getPatients(familyId));
  };

  // --- Family Handlers ---

  const handleOpenModal = (family?: Family, initialTab: 'details' | 'members' = 'details') => {
    if (family) {
      setCurrentFamily({ ...family });
      setIsEditing(true);
      loadMembers(family.id);
      setActiveTab(initialTab); // Open specific tab based on button clicked
    } else {
      setCurrentFamily({
        address: '',
        number: '',
        neighborhood: '',
        phone: '',
        email: '',
        riskLevel: 'LOW',
        membersCount: 0
      });
      setIsEditing(false);
      setFamilyMembers([]);
      setActiveTab('details');
    }
    setShowModal(true);
    setShowMemberForm(false);
  };

  const handleSaveFamily = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    const familyToSave: Family = {
      id: currentFamily.id || crypto.randomUUID(),
      agentId: currentFamily.agentId || user.id,
      address: currentFamily.address!,
      number: currentFamily.number!,
      neighborhood: currentFamily.neighborhood!,
      membersCount: currentFamily.membersCount || 0,
      riskLevel: currentFamily.riskLevel || 'LOW',
      phone: currentFamily.phone,
      email: currentFamily.email,
      lastVisit: currentFamily.lastVisit || null,
      nextVisit: currentFamily.nextVisit || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), // Default 1 year if new
    };

    storageService.saveFamily(familyToSave);
    loadFamilies();

    // If it was a new family, we need to set the ID to allow adding members immediately without closing modal
    if (!isEditing) {
      setCurrentFamily(familyToSave);
      setIsEditing(true);
    } else {
      setShowModal(false);
    }
  };

  const handleDeleteFamily = () => {
    if (currentFamily.id && confirm('Tem certeza? Isso apagará também todos os pacientes e histórico desta família.')) {
      storageService.deleteFamily(currentFamily.id);
      loadFamilies();
      setShowModal(false);
    }
  };

  // --- Member Handlers ---

  const handleOpenMemberForm = (member?: Patient) => {
    if (member) {
      setCurrentMember({ ...member });
    } else {
      setCurrentMember({
        name: '',
        susNumber: '',
        birthDate: '',
        isPregnant: false,
        isPostpartum: false,
        isBedridden: false,
        hasMobilityIssues: false,
        isDiabetic: false,
        isHypertensive: false,
        usesInsulin: false,
        hasPsychologicalIssues: false,
        hasOtherComorbidities: false,
        medications: [],
        addictions: []
      });
    }
    setShowMemberForm(true);
  };

  const handleSaveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentFamily.id) return;

    const memberToSave: Patient = {
        id: currentMember.id || crypto.randomUUID(),
        familyId: currentFamily.id,
        name: currentMember.name!,
        susNumber: currentMember.susNumber!,
        birthDate: currentMember.birthDate!,
        isPregnant: !!currentMember.isPregnant,
        isPostpartum: !!currentMember.isPostpartum,
        isBedridden: !!currentMember.isBedridden,
        hasMobilityIssues: !!currentMember.hasMobilityIssues,
        isDiabetic: !!currentMember.isDiabetic,
        isHypertensive: !!currentMember.isHypertensive,
        usesInsulin: !!currentMember.usesInsulin,
        hasPsychologicalIssues: !!currentMember.hasPsychologicalIssues,
        hasOtherComorbidities: !!currentMember.hasOtherComorbidities,
        medications: currentMember.medications || [],
        addictions: currentMember.addictions || []
    };

    storageService.savePatient(memberToSave);
    loadMembers(currentFamily.id);
    loadFamilies(); // Update grid counts/risks
    setShowMemberForm(false);
  };

  const handleDeleteMember = (memberId: string) => {
    if (confirm('Remover este integrante da família?')) {
      storageService.deletePatient(memberId);
      if (currentFamily.id) loadMembers(currentFamily.id);
      loadFamilies(); // Update grid counts/risks
    }
  };

  // --- Helpers ---

  const filteredFamilies = families.filter(f => 
    f.address.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.number.includes(searchTerm)
  );

  const getRiskConfig = (level: string) => {
    switch (level) {
      case 'URGENT':
        return { className: 'bg-red-100 text-red-700 border-red-200', label: 'Risco Urgente' };
      case 'HIGH':
        return { className: 'bg-orange-100 text-orange-700 border-orange-200', label: 'Risco Alto' };
      case 'MEDIUM':
        return { className: 'bg-yellow-100 text-yellow-800 border-yellow-200', label: 'Risco Médio' };
      case 'LOW':
        return { className: 'bg-green-100 text-green-700 border-green-200', label: 'Risco Baixo' };
      default:
        return { className: 'bg-slate-100 text-slate-700 border-slate-200', label: 'Sem Classificação' };
    }
  };

  const ConditionCheckbox = ({ label, field, icon: Icon }: { label: string, field: keyof Patient, icon: any }) => (
    <label className={`flex items-center p-3 rounded-lg border cursor-pointer transition-all ${currentMember[field] ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
        <input 
            type="checkbox" 
            className="hidden"
            checked={!!currentMember[field]}
            onChange={(e) => setCurrentMember(prev => ({ ...prev, [field]: e.target.checked }))}
        />
        <div className={`p-2 rounded-full mr-3 ${currentMember[field] ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
            <Icon size={18} />
        </div>
        <span className={`font-medium text-sm ${currentMember[field] ? 'text-blue-900' : 'text-slate-600'}`}>{label}</span>
    </label>
  );

  return (
    <div className="pb-20 md:pb-0">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-800">Famílias Acompanhadas</h1>
            <p className="text-slate-500 text-sm">Gerencie os cadastros e integrantes</p>
        </div>
        <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-4 py-2.5 rounded-lg flex items-center hover:bg-blue-700 transition-colors shadow-sm shadow-blue-200 font-medium w-full md:w-auto justify-center"
        >
            <Plus size={20} className="mr-2" /> Nova Família
        </button>
      </div>

      {/* Search Bar */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search"
          placeholder="Buscar por rua, bairro ou número..."
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredFamilies.map(family => {
          const riskConfig = getRiskConfig(family.riskLevel);

          return (
            <div 
                key={family.id} 
                className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="bg-blue-50 p-2.5 rounded-full">
                  <MapPin className="text-blue-500" size={20} />
                </div>
                <span className={`text-xs font-bold px-2.5 py-1 rounded-full border ${riskConfig.className} flex items-center`}>
                  {family.riskLevel !== 'LOW' && <AlertTriangle size={10} className="mr-1" />}
                  {riskConfig.label}
                </span>
              </div>

              <div className="flex-1">
                <h3 className="font-bold text-lg text-slate-800 leading-tight mb-1">{family.address}, {family.number}</h3>
                <p className="text-sm text-slate-500 mb-2">{family.neighborhood}</p>

                {family.phone && (
                    <div className="flex items-center text-xs text-slate-500 mb-1">
                        <Phone size={12} className="mr-1" /> {family.phone}
                    </div>
                )}
              </div>

              <div className="flex gap-2 mt-5 pt-4 border-t border-slate-100">
                <button
                    onClick={() => handleOpenModal(family, 'members')}
                    className="flex-1 bg-blue-50 text-blue-700 py-2.5 rounded-lg text-sm font-bold flex items-center justify-center hover:bg-blue-100 transition-colors border border-blue-100"
                >
                    <Users size={16} className="mr-2"/>
                    Ver Integrantes ({family.membersCount})
                </button>

                <button
                    onClick={() => handleOpenModal(family, 'details')}
                    className="w-10 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors border border-slate-100"
                    title="Editar Dados da Família"
                >
                    <Edit size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {filteredFamilies.length === 0 && (
          <div className="text-center py-12 text-slate-400">
              <Home size={48} className="mx-auto mb-4 opacity-50" />
              <p>Nenhuma família encontrada.</p>
          </div>
      )}

      {/* Main Family Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <h2 className="text-lg font-bold text-slate-800">
                    {isEditing ? 'Gerenciar Família' : 'Nova Família'}
                </h2>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-1">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs */}
            {isEditing && (
                <div className="flex border-b border-slate-100 shrink-0">
                    <button 
                        onClick={() => setActiveTab('details')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Dados Cadastrais
                    </button>
                    <button 
                        onClick={() => setActiveTab('members')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'members' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Integrantes ({familyMembers.length})
                    </button>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-6 overflow-y-auto">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Logradouro / Rua</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.address || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Bairro / Comunidade</label>
                            <input 
                                required
                                className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                value={currentFamily.neighborhood || ''}
                                onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone Principal</label>
                                <div className="relative">
                                    <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-between items-center border-t border-slate-100 mt-6">
                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-medium flex items-center transition-colors"
                                >
                                    <Trash2 size={16} className="mr-2" /> Excluir Família
                                </button>
                             )}
                             <button 
                                type="submit" 
                                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold hover:bg-blue-700 shadow-sm ml-auto flex items-center"
                             >
                                <Save size={18} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>
                        </div>
                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-4">
                        {!showMemberForm ? (
                            <>
                                <button 
                                    onClick={() => handleOpenMemberForm()}
                                    className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-blue-600 font-medium hover:bg-blue-50 hover:border-blue-300 transition-colors flex items-center justify-center"
                                >
                                    <UserPlus size={20} className="mr-2" /> Adicionar Integrante
                                </button>

                                <div className="space-y-3 mt-4">
                                    {familyMembers.map(member => (
                                        <div key={member.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg border border-slate-200">
                                            <div className="flex items-center">
                                                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-400 border border-slate-200 mr-3">
                                                    <User size={20} />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                                    <div className="flex gap-2 text-xs text-slate-500">
                                                        <span>SUS: {member.susNumber}</span>
                                                        <span>•</span>
                                                        <span>{new Date(member.birthDate).toLocaleDateString()}</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => handleOpenMemberForm(member)}
                                                    className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                                                >
                                                    <Edit size={16} />
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteMember(member.id)}
                                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                    {familyMembers.length === 0 && (
                                        <div className="text-center text-slate-400 py-4 text-sm">
                                            Nenhum integrante cadastrado nesta família.
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            // Member Form
                            <form onSubmit={handleSaveMember} className="space-y-4 animate-in slide-in-from-right duration-200">
                                <div className="flex items-center text-slate-500 mb-2">
                                    <button type="button" onClick={() => setShowMemberForm(false)} className="hover:text-blue-600 text-sm flex items-center">
                                        <ChevronRight size={16} className="rotate-180 mr-1" /> Voltar
                                    </button>
                                    <span className="mx-2 text-slate-300">|</span>
                                    <span className="text-sm font-medium text-slate-800">{currentMember.id ? 'Editar Paciente' : 'Novo Paciente'}</span>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
                                    <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.name || ''} onChange={e => setCurrentMember(prev => ({ ...prev, name: e.target.value }))} />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Cartão SUS</label>
                                        <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.susNumber || ''} onChange={e => setCurrentMember(prev => ({ ...prev, susNumber: e.target.value }))} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                                        <input type="date" required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.birthDate?.split('T')[0] || ''} onChange={e => setCurrentMember(prev => ({ ...prev, birthDate: e.target.value }))} />
                                    </div>
                                </div>

                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-4">
                                    <h4 className="font-bold text-slate-800 text-sm mb-3">Condições de Saúde</h4>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                        <ConditionCheckbox label="Gestante" field="isPregnant" icon={Baby} />
                                        <ConditionCheckbox label="Diabético(a)" field="isDiabetic" icon={Droplets} />
                                        <ConditionCheckbox label="Hipertenso(a)" field="isHypertensive" icon={HeartPulse} />
                                        <ConditionCheckbox label="Acamado(a)" field="isBedridden" icon={Bed} />
                                        <ConditionCheckbox label="Saúde Mental" field="hasPsychologicalIssues" icon={Brain} />
                                        <ConditionCheckbox label="Outras" field="hasOtherComorbidities" icon={Activity} />
                                    </div>
                                </div>

                                <button type="submit" className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-bold hover:bg-blue-700 mt-4 shadow-sm">
                                    Salvar Integrante
                                </button>
                            </form>
                        )}
                    </div>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole } from '../types';
import { 
  MapPin, Plus, AlertTriangle, Search, X, Home, Phone, Mail, 
  Save, Trash2, UserPlus, User, Baby, Bed, Activity, Brain, 
  HeartPulse, Droplets, Edit, ChevronRight, Users, Eye, Filter, RotateCcw
} from 'lucide-react';

export const Families: React.FC = () => {
  const { user } = useAuth();
  const [families, setFamilies] = useState<Family[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentFamily, setCurrentFamily] = useState<Partial<Family>>({});

  // Patient Management States
  const [activeTab, setActiveTab] = useState<'details' | 'members'>('details');
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [currentMember, setCurrentMember] = useState<Partial<Patient>>({});

  // Patient Filters in Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadFamilies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadFamilies = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    setFamilies(storageService.getFamilies(agentFilter));
  };

  const loadMembers = (familyId: string) => {
    setFamilyMembers(storageService.getPatients(familyId));
  };

  // --- Family Handlers ---

  const handleOpenModal = (family?: Family, initialTab: 'details' | 'members' = 'details') => {
    if (family) {
      setCurrentFamily({ ...family });
      setIsEditing(true);
      loadMembers(family.id);
      setActiveTab(initialTab); // Open specific tab based on button clicked
    } else {
      setCurrentFamily({
        address: '',
        number: '',
        neighborhood: '',
        phone: '',
        email: '',
        riskLevel: 'LOW',
        membersCount: 0
      });
      setIsEditing(false);
      setFamilyMembers([]);
      setActiveTab('details');
    }
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
    setShowMemberForm(false);
  };

  const handleSaveFamily = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    const familyToSave: Family = {
      id: currentFamily.id || crypto.randomUUID(),
      agentId: currentFamily.agentId || user.id,
      address: currentFamily.address!,
      number: currentFamily.number!,
      neighborhood: currentFamily.neighborhood!,
      membersCount: currentFamily.membersCount || 0,
      riskLevel: currentFamily.riskLevel || 'LOW',
      phone: currentFamily.phone,
      email: currentFamily.email,
      lastVisit: currentFamily.lastVisit || null,
      nextVisit: currentFamily.nextVisit || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), // Default 1 year if new
    };

    storageService.saveFamily(familyToSave);
    loadFamilies();

    // If it was a new family, we need to set the ID to allow adding members immediately without closing modal
    if (!isEditing) {
      setCurrentFamily(familyToSave);
      setIsEditing(true);
    } else {
      setShowModal(false);
    }
  };

  const handleDeleteFamily = () => {
    if (currentFamily.id && confirm('Tem certeza? Isso apagará também todos os pacientes e histórico desta família.')) {
      storageService.deleteFamily(currentFamily.id);
      loadFamilies();
      setShowModal(false);
    }
  };

  // --- Member Handlers ---

  const handleOpenMemberForm = (member?: Patient) => {
    if (member) {
      setCurrentMember({ ...member });
    } else {
      setCurrentMember({
        name: '',
        susNumber: '',
        birthDate: '',
        isPregnant: false,
        isPostpartum: false,
        isBedridden: false,
        hasMobilityIssues: false,
        isDiabetic: false,
        isHypertensive: false,
        usesInsulin: false,
        hasPsychologicalIssues: false,
        hasOtherComorbidities: false,
        medications: [],
        addictions: []
      });
    }
    setShowMemberForm(true);
  };

  const handleSaveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentFamily.id) return;

    const memberToSave: Patient = {
        id: currentMember.id || crypto.randomUUID(),
        familyId: currentFamily.id,
        name: currentMember.name!,
        susNumber: currentMember.susNumber!,
        birthDate: currentMember.birthDate!,
        isPregnant: !!currentMember.isPregnant,
        isPostpartum: !!currentMember.isPostpartum,
        isBedridden: !!currentMember.isBedridden,
        hasMobilityIssues: !!currentMember.hasMobilityIssues,
        isDiabetic: !!currentMember.isDiabetic,
        isHypertensive: !!currentMember.isHypertensive,
        usesInsulin: !!currentMember.usesInsulin,
        hasPsychologicalIssues: !!currentMember.hasPsychologicalIssues,
        hasOtherComorbidities: !!currentMember.hasOtherComorbidities,
        medications: currentMember.medications || [],
        addictions: currentMember.addictions || []
    };

    storageService.savePatient(memberToSave);
    loadMembers(currentFamily.id);
    loadFamilies(); // Update grid counts/risks
    setShowMemberForm(false);
  };

  const handleDeleteMember = (memberId: string) => {
    if (confirm('Remover este integrante da família?')) {
      storageService.deletePatient(memberId);
      if (currentFamily.id) loadMembers(currentFamily.id);
      loadFamilies(); // Update grid counts/risks
    }
  };

  // --- Filtering Logic for Members ---

  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  // --- Helpers ---

  const filteredFamilies = families.filter(f => 
    f.address.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.number.includes(searchTerm)
  );

  const getRiskConfig = (level: string) => {
    switch (level) {
      case 'URGENT':
        return { className: 'bg-red-100 text-red-700 border-red-200', label: 'Risco Urgente' };
      case 'HIGH':
        return { className: 'bg-orange-100 text-orange-700 border-orange-200', label: 'Risco Alto' };
      case 'MEDIUM':
        return { className: 'bg-yellow-100 text-yellow-800 border-yellow-200', label: 'Risco Médio' };
      case 'LOW':
        return { className: 'bg-green-100 text-green-700 border-green-200', label: 'Risco Baixo' };
      default:
        return { className: 'bg-slate-100 text-slate-700 border-slate-200', label: 'Sem Classificação' };
    }
  };

  const ConditionCheckbox = ({ label, field, icon: Icon }: { label: string, field: keyof Patient, icon: any }) => (
    <label className={`flex items-center p-3 rounded-lg border cursor-pointer transition-all ${currentMember[field] ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
        <input 
            type="checkbox" 
            className="hidden"
            checked={!!currentMember[field]}
            onChange={(e) => setCurrentMember(prev => ({ ...prev, [field]: e.target.checked }))}
        />
        <div className={`p-2 rounded-full mr-3 ${currentMember[field] ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
            <Icon size={18} />
        </div>
        <span className={`font-medium text-sm ${currentMember[field] ? 'text-blue-900' : 'text-slate-600'}`}>{label}</span>
    </label>
  );

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-800">Famílias Acompanhadas</h1>
            <p className="text-slate-500 text-sm">Gerencie os cadastros e integrantes</p>
        </div>
        <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-4 py-2.5 rounded-lg flex items-center hover:bg-blue-700 transition-colors shadow-sm shadow-blue-200 font-medium w-full md:w-auto justify-center"
        >
            <Plus size={20} className="mr-2" /> Nova Família
        </button>
      </div>

      {/* Search Bar */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search"
          placeholder="Buscar por rua, bairro ou número..."
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredFamilies.map(family => {
          const riskConfig = getRiskConfig(family.riskLevel);

          return (
            <div 
                key={family.id} 
                className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="bg-blue-50 p-2.5 rounded-full">
                  <MapPin className="text-blue-500" size={20} />
                </div>
                <span className={`text-xs font-bold px-2.5 py-1 rounded-full border ${riskConfig.className} flex items-center`}>
                  {family.riskLevel !== 'LOW' && <AlertTriangle size={10} className="mr-1" />}
                  {riskConfig.label}
                </span>
              </div>

              <div className="flex-1">
                <h3 className="font-bold text-lg text-slate-800 leading-tight mb-1">{family.address}, {family.number}</h3>
                <p className="text-sm text-slate-500 mb-2">{family.neighborhood}</p>

                {family.phone && (
                    <div className="flex items-center text-xs text-slate-500 mb-1">
                        <Phone size={12} className="mr-1" /> {family.phone}
                    </div>
                )}
              </div>

              <div className="flex gap-2 mt-5 pt-4 border-t border-slate-100">
                <button
                    onClick={() => handleOpenModal(family, 'members')}
                    className="flex-1 bg-blue-50 text-blue-700 py-2.5 rounded-lg text-sm font-bold flex items-center justify-center hover:bg-blue-100 transition-colors border border-blue-100"
                >
                    <Users size={16} className="mr-2"/>
                    Ver Integrantes ({family.membersCount})
                </button>

                <button
                    onClick={() => handleOpenModal(family, 'details')}
                    className="w-10 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors border border-slate-100"
                    title="Editar Dados da Família"
                >
                    <Edit size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {filteredFamilies.length === 0 && (
          <div className="text-center py-12 text-slate-400">
              <Home size={48} className="mx-auto mb-4 opacity-50" />
              <p>Nenhuma família encontrada.</p>
          </div>
      )}

      {/* Main Family Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <h2 className="text-lg font-bold text-slate-800">
                    {isEditing ? 'Gerenciar Família' : 'Nova Família'}
                </h2>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-1">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs */}
            {isEditing && (
                <div className="flex border-b border-slate-100 shrink-0">
                    <button 
                        onClick={() => setActiveTab('details')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Dados Cadastrais
                    </button>
                    <button 
                        onClick={() => setActiveTab('members')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'members' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Integrantes ({familyMembers.length})
                    </button>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-6 overflow-y-auto">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Logradouro / Rua</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.address || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Bairro / Comunidade</label>
                            <input 
                                required
                                className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                value={currentFamily.neighborhood || ''}
                                onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone Principal</label>
                                <div className="relative">
                                    <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-between items-center border-t border-slate-100 mt-6">
                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-medium flex items-center transition-colors"
                                >
                                    <Trash2 size={16} className="mr-2" /> Excluir Família
                                </button>
                             )}
                             <button 
                                type="submit" 
                                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold hover:bg-blue-700 shadow-sm ml-auto flex items-center"
                             >
                                <Save size={18} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>
                        </div>
                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-4">
                        {!showMemberForm ? (
                            <>
                                <button 
                                    onClick={() => handleOpenMemberForm()}
                                    className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-blue-600 font-medium hover:bg-blue-50 hover:border-blue-300 transition-colors flex items-center justify-center mb-4"
                                >
                                    <UserPlus size={20} className="mr-2" /> Adicionar Integrante
                                </button>

                                {/* Member Search and Filter */}
                                <div className="mb-4">
                                    <div className="relative mb-3">
                                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                                        <input 
                                            type="text"
                                            placeholder="Buscar integrante por nome..."
                                            className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                            value={memberSearchTerm}
                                            onChange={(e) => setMemberSearchTerm(e.target.value)}
                                        />
                                        {memberSearchTerm && (
                                            <button 
                                                onClick={() => setMemberSearchTerm('')}
                                                className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                            >
                                                <X size={14} />
                                            </button>
                                        )}
                                    </div>

                                    {/* Filter Chips */}
                                    <div className="flex flex-wrap gap-2 items-center">
                                        <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                            <Filter size={14} className="mr-1" />
                                            Filtros:
                                        </div>
                                        <FilterButton 
                                            id="pregnant" 
                                            label="Gestante"
                                            count={conditionCounts.pregnant}
                                            icon={Baby} 
                                            activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                                        />
                                        <FilterButton 
                                            id="bedridden" 
                                            label="Acamado" 
                                            count={conditionCounts.bedridden}
                                            icon={Bed} 
                                            activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                                        />
                                        <FilterButton 
                                            id="diabetic" 
                                            label="Diabético" 
                                            count={conditionCounts.diabetic}
                                            icon={Droplets} 
                                            activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                                        />
                                        <FilterButton 
                                            id="hypertensive" 
                                            label="Hipertenso" 
                                            count={conditionCounts.hypertensive}
                                            icon={HeartPulse} 
                                            activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                                        />
                                        <FilterButton 
                                            id="psychological" 
                                            label="Saúde Mental" 
                                            count={conditionCounts.psychological}
                                            icon={Brain} 
                                            activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                                        />

                                        {activeMemberFilters.length > 0 && (
                                            <button 
                                                onClick={() => setActiveMemberFilters([])}
                                                className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                            >
                                                <RotateCcw size={10} className="mr-1" /> Limpar
                                            </button>
                                        )}
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    {filteredMembers.map(member => (
                                        <div key={member.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-blue-300 transition-colors">
                                            <div className="flex items-center">
                                                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-400 border border-slate-200 mr-3">
                                                    <User size={20} />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                                    <div className="flex gap-2 text-xs text-slate-500">
                                                        <span>SUS: {member.susNumber}</span>
                                                        <span>•</span>
                                                        <span>{new Date(member.birthDate).toLocaleDateString()}</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => handleOpenMemberForm(member)}
                                                    className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                                                >
                                                    <Edit size={16} />
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteMember(member.id)}
                                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredMembers.length === 0 && (
                                        <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                            {familyMembers.length === 0 
                                                ? 'Nenhum integrante cadastrado nesta família.'
                                                : 'Nenhum paciente encontrado com os filtros selecionados.'}
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            // Member Form
                            <form onSubmit={handleSaveMember} className="space-y-4 animate-in slide-in-from-right duration-200">
                                <div className="flex items-center text-slate-500 mb-2">
                                    <button type="button" onClick={() => setShowMemberForm(false)} className="hover:text-blue-600 text-sm flex items-center">
                                        <ChevronRight size={16} className="rotate-180 mr-1" /> Voltar
                                    </button>
                                    <span className="mx-2 text-slate-300">|</span>
                                    <span className="text-sm font-medium text-slate-800">{currentMember.id ? 'Editar Paciente' : 'Novo Paciente'}</span>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
                                    <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.name || ''} onChange={e => setCurrentMember(prev => ({ ...prev, name: e.target.value }))} />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Cartão SUS</label>
                                        <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.susNumber || ''} onChange={e => setCurrentMember(prev => ({ ...prev, susNumber: e.target.value }))} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                                        <input type="date" required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.birthDate?.split('T')[0] || ''} onChange={e => setCurrentMember(prev => ({ ...prev, birthDate: e.target.value }))} />
                                    </div>
                                </div>

                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-4">
                                    <h4 className="font-bold text-slate-800 text-sm mb-3">Condições de Saúde</h4>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                        <ConditionCheckbox label="Gestante" field="isPregnant" icon={Baby} />
                                        <ConditionCheckbox label="Diabético(a)" field="isDiabetic" icon={Droplets} />
                                        <ConditionCheckbox label="Hipertenso(a)" field="isHypertensive" icon={HeartPulse} />
                                        <ConditionCheckbox label="Acamado(a)" field="isBedridden" icon={Bed} />
                                        <ConditionCheckbox label="Saúde Mental" field="hasPsychologicalIssues" icon={Brain} />
                                        <ConditionCheckbox label="Outras" field="hasOtherComorbidities" icon={Activity} />
                                    </div>
                                </div>

                                <button type="submit" className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-bold hover:bg-blue-700 mt-4 shadow-sm">
                                    Salvar Integrante
                                </button>
                            </form>
                        )}
                    </div>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, ChevronDown, Check, Activity,
  X, Phone, Mail, Calendar, FilePlus, UserPlus, ClipboardList, RotateCcw, Search
} from 'lucide-react';

// Definitions for filters to make the code cleaner and scalable
const FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-700 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-700 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-700 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-700 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-700 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-700 border-sky-200' },
  { id: 'child_0_5', label: 'Crianças (0-5 anos)', icon: Baby, color: 'bg-indigo-100 text-indigo-700 border-indigo-200' },
  { id: 'elderly', label: 'Idosos (60+)', icon: User, color: 'bg-slate-200 text-slate-700 border-slate-300' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter
    const newCounts: Record<string, number> = {};
    FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });
    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      case 'child_0_5': return age <= 5;
      case 'elderly': return age >= 60;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();
  const currentFilterLabel = FILTERS.find(f => f.id === activeFilter)?.label;

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Selecione um card para filtrar famílias por condição de saúde.</p>
      </div>

      {/* Interactive Cards Grid */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
        {FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>

              {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-100 border-2 border-dashed border-slate-300 rounded-xl p-12 text-center">
             <Filter size={48} className="mx-auto text-slate-400 mb-4" />
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500">Clique em um dos cards acima para ver a lista de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className="bg-blue-600 text-white w-8 h-8 rounded-full flex items-center justify-center text-sm mr-3 font-bold">
                        {results.length}
                    </span>
                    Pacientes encontrados: {currentFilterLabel}
                </h2>
                <button 
                    onClick={() => setActiveFilter(null)}
                    className="text-sm text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-1 rounded-lg transition-colors"
                >
                    Limpar Filtro
                </button>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-8 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {results.map(({ patient, family }) => (
                        <div 
                            key={patient.id} 
                            onClick={() => handleOpenFamily(family)}
                            className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer active:scale-[0.99] flex flex-col md:flex-row md:items-center justify-between gap-4 group"
                        >
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-full bg-slate-100 group-hover:bg-blue-50 flex items-center justify-center text-slate-500 group-hover:text-blue-600 transition-colors shrink-0">
                                    <User size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center">
                                            <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                        </span>
                                        <span className="flex items-center">
                                            <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                        </span>
                                    </div>

                                    {/* Address Display */}
                                    <div className="mt-3 flex items-start text-sm bg-blue-50 text-blue-800 p-2 rounded-lg group-hover:bg-blue-100 transition-colors">
                                        <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                        <div>
                                            <span className="font-bold block">Residência:</span>
                                            {family ? (
                                                <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                            ) : (
                                                <span className="text-red-500 italic">Endereço não vinculado</span>
                                            )}
                                        </div>
                                    </div>

                                    <PatientBadge patient={patient} />
                                </div>
                            </div>

                            <div className="md:text-right shrink-0 flex flex-col items-end justify-center">
                                <span className="text-blue-600 text-sm font-medium flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    Ver Família <ArrowRight size={16} className="ml-1" />
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}
          </div>
        )}
      </div>

      {/* Family Details Modal */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full h-auto max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-200">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center">
                            <MapPin size={18} className="mr-2 text-blue-600"/>
                            {selectedFamily.address}, {selectedFamily.number}
                        </h2>
                        <p className="text-sm text-slate-500">{selectedFamily.neighborhood}</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Family Quick Info */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                             <h4 className="text-xs font-bold text-blue-600 uppercase mb-2">Próxima Visita</h4>
                             <div className="flex items-center text-blue-900 font-medium">
                                <Calendar size={18} className="mr-2"/>
                                {new Date(selectedFamily.nextVisit).toLocaleDateString()}
                             </div>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Contatos</h4>
                             <div className="space-y-1">
                                {selectedFamily.phone && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Phone size={14} className="mr-2 text-slate-400"/> {selectedFamily.phone}
                                    </div>
                                )}
                                {selectedFamily.email && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Mail size={14} className="mr-2 text-slate-400"/> {selectedFamily.email}
                                    </div>
                                )}
                                {!selectedFamily.phone && !selectedFamily.email && (
                                    <span className="text-xs text-slate-400 italic">Sem contato registrado</span>
                                )}
                             </div>
                        </div>
                    </div>

                    <h3 className="font-bold text-slate-800 mb-4 flex items-center border-b border-slate-100 pb-2">
                        <ClipboardList size={18} className="mr-2 text-slate-500"/>
                        Integrantes da Família
                    </h3>

                    {/* Member Search and Filter */}
                    <div className="mb-4">
                        <div className="relative mb-3">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Buscar integrante por nome..."
                                className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                value={memberSearchTerm}
                                onChange={(e) => setMemberSearchTerm(e.target.value)}
                            />
                            {memberSearchTerm && (
                                <button 
                                    onClick={() => setMemberSearchTerm('')}
                                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                >
                                    <X size={14} />
                                </button>
                            )}
                        </div>

                        {/* Filter Chips */}
                        <div className="flex flex-wrap gap-2 items-center">
                            <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                <Filter size={14} className="mr-1" />
                                Filtros:
                            </div>
                            <FilterButton 
                                id="pregnant" 
                                label="Gestante"
                                count={conditionCounts.pregnant}
                                icon={Baby} 
                                activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                            />
                            <FilterButton 
                                id="bedridden" 
                                label="Acamado" 
                                count={conditionCounts.bedridden}
                                icon={Bed} 
                                activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                            />
                            <FilterButton 
                                id="diabetic" 
                                label="Diabético" 
                                count={conditionCounts.diabetic}
                                icon={Droplets} 
                                activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                            />
                            <FilterButton 
                                id="hypertensive" 
                                label="Hipertenso" 
                                count={conditionCounts.hypertensive}
                                icon={HeartPulse} 
                                activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                            />
                            <FilterButton 
                                id="psychological" 
                                label="Saúde Mental" 
                                count={conditionCounts.psychological}
                                icon={Brain} 
                                activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                            />

                            {activeMemberFilters.length > 0 && (
                                <button 
                                    onClick={() => setActiveMemberFilters([])}
                                    className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                >
                                    <RotateCcw size={10} className="mr-1" /> Limpar
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filteredMembers.map(member => (
                            <div key={member.id} className="p-3 border border-slate-200 rounded-lg hover:border-blue-200 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center">
                                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3">
                                            <User size={16} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                            <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos • SUS: {member.susNumber}</span>
                                        </div>
                                    </div>
                                </div>
                                <PatientBadge patient={member} />
                                {member.medications && member.medications.length > 0 && (
                                    <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                                        <span className="font-semibold">Medicamentos:</span> {member.medications.join(', ')}
                                    </div>
                                )}
                            </div>
                        ))}
                        {filteredMembers.length === 0 && (
                            <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                {familyMembers.length === 0 
                                    ? 'Nenhum integrante cadastrado nesta família.'
                                    : 'Nenhum paciente encontrado com os filtros selecionados.'}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 bg-white">
                    <button 
                        onClick={() => setShowModal(false)}
                        className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, X, Phone, Mail, Calendar, 
  FilePlus, UserPlus, ClipboardList, RotateCcw, Search, GraduationCap, Briefcase
} from 'lucide-react';

// 1. Health Condition Filters
const CONDITION_FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-700 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-700 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-700 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-700 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-700 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-700 border-sky-200' },
];

// 2. Age Group Filters
const AGE_FILTERS = [
  { id: 'age_0_5', label: '0 a 5 anos', min: 0, max: 5, icon: Baby, color: 'bg-indigo-100 text-indigo-700 border-indigo-200' },
  { id: 'age_6_12', label: '6 a 12 anos', min: 6, max: 12, icon: GraduationCap, color: 'bg-cyan-100 text-cyan-700 border-cyan-200' },
  { id: 'age_13_17', label: '13 a 17 anos', min: 13, max: 17, icon: User, color: 'bg-teal-100 text-teal-700 border-teal-200' },
  { id: 'age_18_59', label: '18 a 59 anos', min: 18, max: 59, icon: Briefcase, color: 'bg-slate-100 text-slate-700 border-slate-200' },
  { id: 'age_60_plus', label: 'Idosos (60+)', min: 60, max: 200, icon: User, color: 'bg-slate-200 text-slate-700 border-slate-300' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter (Conditions + Ages)
    const newCounts: Record<string, number> = {};

    CONDITION_FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    AGE_FILTERS.forEach(filter => {
       newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    // Check Age Filters First
    const ageFilter = AGE_FILTERS.find(f => f.id === filterId);
    if (ageFilter) {
        return age >= ageFilter.min && age <= ageFilter.max;
    }

    // Check Condition Filters
    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();

  // Helper to find label of current active filter
  const getCurrentFilterLabel = () => {
    const condition = CONDITION_FILTERS.find(f => f.id === activeFilter);
    if (condition) return condition.label;
    const age = AGE_FILTERS.find(f => f.id === activeFilter);
    if (age) return age.label;
    return '';
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Analise sua área por condições de saúde e faixas etárias.</p>
      </div>

      {/* Section 1: Health Conditions */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
         Condições de Saúde
      </h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
        {CONDITION_FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>

              {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 z-10">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Section 2: Age Groups */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
         Faixa Etária
      </h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4 mb-8">
        {AGE_FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>
               {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 z-10">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-100 border-2 border-dashed border-slate-300 rounded-xl p-12 text-center">
             <Filter size={48} className="mx-auto text-slate-400 mb-4" />
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500">Clique em um dos cards acima para ver a lista de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className="bg-blue-600 text-white w-8 h-8 rounded-full flex items-center justify-center text-sm mr-3 font-bold">
                        {results.length}
                    </span>
                    Pacientes encontrados: {getCurrentFilterLabel()}
                </h2>
                <button 
                    onClick={() => setActiveFilter(null)}
                    className="text-sm text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-1 rounded-lg transition-colors"
                >
                    Limpar Filtro
                </button>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-8 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {results.map(({ patient, family }) => (
                        <div 
                            key={patient.id} 
                            onClick={() => handleOpenFamily(family)}
                            className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer active:scale-[0.99] flex flex-col md:flex-row md:items-center justify-between gap-4 group"
                        >
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-full bg-slate-100 group-hover:bg-blue-50 flex items-center justify-center text-slate-500 group-hover:text-blue-600 transition-colors shrink-0">
                                    <User size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center">
                                            <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                        </span>
                                        <span className="flex items-center">
                                            <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                        </span>
                                    </div>

                                    {/* Address Display */}
                                    <div className="mt-3 flex items-start text-sm bg-blue-50 text-blue-800 p-2 rounded-lg group-hover:bg-blue-100 transition-colors">
                                        <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                        <div>
                                            <span className="font-bold block">Residência:</span>
                                            {family ? (
                                                <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                            ) : (
                                                <span className="text-red-500 italic">Endereço não vinculado</span>
                                            )}
                                        </div>
                                    </div>

                                    <PatientBadge patient={patient} />
                                </div>
                            </div>

                            <div className="md:text-right shrink-0 flex flex-col items-end justify-center">
                                <span className="text-blue-600 text-sm font-medium flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    Ver Família <ArrowRight size={16} className="ml-1" />
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}
          </div>
        )}
      </div>

      {/* Family Details Modal */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full h-auto max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-200">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center">
                            <MapPin size={18} className="mr-2 text-blue-600"/>
                            {selectedFamily.address}, {selectedFamily.number}
                        </h2>
                        <p className="text-sm text-slate-500">{selectedFamily.neighborhood}</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Family Quick Info */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                             <h4 className="text-xs font-bold text-blue-600 uppercase mb-2">Próxima Visita</h4>
                             <div className="flex items-center text-blue-900 font-medium">
                                <Calendar size={18} className="mr-2"/>
                                {new Date(selectedFamily.nextVisit).toLocaleDateString()}
                             </div>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Contatos</h4>
                             <div className="space-y-1">
                                {selectedFamily.phone && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Phone size={14} className="mr-2 text-slate-400"/> {selectedFamily.phone}
                                    </div>
                                )}
                                {selectedFamily.email && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Mail size={14} className="mr-2 text-slate-400"/> {selectedFamily.email}
                                    </div>
                                )}
                                {!selectedFamily.phone && !selectedFamily.email && (
                                    <span className="text-xs text-slate-400 italic">Sem contato registrado</span>
                                )}
                             </div>
                        </div>
                    </div>

                    <h3 className="font-bold text-slate-800 mb-4 flex items-center border-b border-slate-100 pb-2">
                        <ClipboardList size={18} className="mr-2 text-slate-500"/>
                        Integrantes da Família
                    </h3>

                    {/* Member Search and Filter */}
                    <div className="mb-4">
                        <div className="relative mb-3">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Buscar integrante por nome..."
                                className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                value={memberSearchTerm}
                                onChange={(e) => setMemberSearchTerm(e.target.value)}
                            />
                            {memberSearchTerm && (
                                <button 
                                    onClick={() => setMemberSearchTerm('')}
                                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                >
                                    <X size={14} />
                                </button>
                            )}
                        </div>

                        {/* Filter Chips */}
                        <div className="flex flex-wrap gap-2 items-center">
                            <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                <Filter size={14} className="mr-1" />
                                Filtros:
                            </div>
                            <FilterButton 
                                id="pregnant" 
                                label="Gestante"
                                count={conditionCounts.pregnant}
                                icon={Baby} 
                                activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                            />
                            <FilterButton 
                                id="bedridden" 
                                label="Acamado" 
                                count={conditionCounts.bedridden}
                                icon={Bed} 
                                activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                            />
                            <FilterButton 
                                id="diabetic" 
                                label="Diabético" 
                                count={conditionCounts.diabetic}
                                icon={Droplets} 
                                activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                            />
                            <FilterButton 
                                id="hypertensive" 
                                label="Hipertenso" 
                                count={conditionCounts.hypertensive}
                                icon={HeartPulse} 
                                activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                            />
                            <FilterButton 
                                id="psychological" 
                                label="Saúde Mental" 
                                count={conditionCounts.psychological}
                                icon={Brain} 
                                activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                            />

                            {activeMemberFilters.length > 0 && (
                                <button 
                                    onClick={() => setActiveMemberFilters([])}
                                    className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                >
                                    <RotateCcw size={10} className="mr-1" /> Limpar
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filteredMembers.map(member => (
                            <div key={member.id} className="p-3 border border-slate-200 rounded-lg hover:border-blue-200 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center">
                                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3">
                                            <User size={16} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                            <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos • SUS: {member.susNumber}</span>
                                        </div>
                                    </div>
                                </div>
                                <PatientBadge patient={member} />
                                {member.medications && member.medications.length > 0 && (
                                    <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                                        <span className="font-semibold">Medicamentos:</span> {member.medications.join(', ')}
                                    </div>
                                )}
                            </div>
                        ))}
                        {filteredMembers.length === 0 && (
                            <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                {familyMembers.length === 0 
                                    ? 'Nenhum integrante cadastrado nesta família.'
                                    : 'Nenhum paciente encontrado com os filtros selecionados.'}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 bg-white">
                    <button 
                        onClick={() => setShowModal(false)}
                        className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, X, Phone, Mail, Calendar, 
  FilePlus, UserPlus, ClipboardList, RotateCcw, Search, GraduationCap, Briefcase, Activity
} from 'lucide-react';

// 1. Health Condition Filters
const CONDITION_FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-700 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-700 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-700 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-700 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-700 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-700 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-700 border-sky-200' },
];

// 2. Age Group Filters
const AGE_FILTERS = [
  { id: 'age_0_5', label: '0 a 5 anos', min: 0, max: 5, icon: Baby, color: 'bg-indigo-100 text-indigo-700 border-indigo-200' },
  { id: 'age_6_12', label: '6 a 12 anos', min: 6, max: 12, icon: GraduationCap, color: 'bg-cyan-100 text-cyan-700 border-cyan-200' },
  { id: 'age_13_17', label: '13 a 17 anos', min: 13, max: 17, icon: User, color: 'bg-teal-100 text-teal-700 border-teal-200' },
  { id: 'age_18_59', label: '18 a 59 anos', min: 18, max: 59, icon: Briefcase, color: 'bg-slate-100 text-slate-700 border-slate-200' },
  { id: 'age_60_plus', label: 'Idosos (60+)', min: 60, max: 200, icon: User, color: 'bg-slate-200 text-slate-700 border-slate-300' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter (Conditions + Ages)
    const newCounts: Record<string, number> = {};

    CONDITION_FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    AGE_FILTERS.forEach(filter => {
       newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    // Check Age Filters First
    const ageFilter = AGE_FILTERS.find(f => f.id === filterId);
    if (ageFilter) {
        return age >= ageFilter.min && age <= ageFilter.max;
    }

    // Check Condition Filters
    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();

  // Helper to find label of current active filter
  const getCurrentFilterLabel = () => {
    const condition = CONDITION_FILTERS.find(f => f.id === activeFilter);
    if (condition) return condition.label;
    const age = AGE_FILTERS.find(f => f.id === activeFilter);
    if (age) return age.label;
    return '';
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Analise sua área por condições de saúde e faixas etárias.</p>
      </div>

      {/* Section 1: Health Conditions */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
         Condições de Saúde
      </h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
        {CONDITION_FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>

              {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 z-10">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Section 2: Age Groups */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2">
         Faixa Etária
      </h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4 mb-8">
        {AGE_FILTERS.map((filter) => {
          const isActive = activeFilter === filter.id;
          const count = counts[filter.id] || 0;
          const Icon = filter.icon;

          return (
            <button
              key={filter.id}
              onClick={() => setActiveFilter(isActive ? null : filter.id)}
              className={`
                relative p-4 rounded-xl border-2 text-left transition-all duration-200
                ${isActive 
                    ? `border-blue-500 bg-white shadow-lg scale-[1.02] ring-2 ring-blue-100` 
                    : `border-transparent bg-white shadow-sm hover:border-slate-200 hover:shadow-md`
                }
              `}
            >
              <div className="flex justify-between items-start mb-3">
                <div className={`p-2 rounded-lg ${filter.color}`}>
                  <Icon size={20} />
                </div>
                <span className="text-2xl font-bold text-slate-800">{count}</span>
              </div>
              <p className={`font-medium text-sm ${isActive ? 'text-blue-700' : 'text-slate-600'}`}>
                {filter.label}
              </p>
               {isActive && (
                <div className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 z-10">
                   <div className="w-4 h-4 bg-blue-500 rotate-45"></div>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-100 border-2 border-dashed border-slate-300 rounded-xl p-12 text-center">
             <Filter size={48} className="mx-auto text-slate-400 mb-4" />
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500">Clique em um dos cards acima para ver a lista de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <span className="bg-blue-600 text-white w-8 h-8 rounded-full flex items-center justify-center text-sm mr-3 font-bold">
                        {results.length}
                    </span>
                    Pacientes encontrados: {getCurrentFilterLabel()}
                </h2>
                <button 
                    onClick={() => setActiveFilter(null)}
                    className="text-sm text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-1 rounded-lg transition-colors"
                >
                    Limpar Filtro
                </button>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-8 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {results.map(({ patient, family }) => (
                        <div 
                            key={patient.id} 
                            onClick={() => handleOpenFamily(family)}
                            className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer active:scale-[0.99] flex flex-col md:flex-row md:items-center justify-between gap-4 group"
                        >
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-full bg-slate-100 group-hover:bg-blue-50 flex items-center justify-center text-slate-500 group-hover:text-blue-600 transition-colors shrink-0">
                                    <User size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center">
                                            <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                        </span>
                                        <span className="flex items-center">
                                            <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                        </span>
                                    </div>

                                    {/* Address Display */}
                                    <div className="mt-3 flex items-start text-sm bg-blue-50 text-blue-800 p-2 rounded-lg group-hover:bg-blue-100 transition-colors">
                                        <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                        <div>
                                            <span className="font-bold block">Residência:</span>
                                            {family ? (
                                                <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                            ) : (
                                                <span className="text-red-500 italic">Endereço não vinculado</span>
                                            )}
                                        </div>
                                    </div>

                                    <PatientBadge patient={patient} />
                                </div>
                            </div>

                            <div className="md:text-right shrink-0 flex flex-col items-end justify-center">
                                <span className="text-blue-600 text-sm font-medium flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    Ver Família <ArrowRight size={16} className="ml-1" />
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}
          </div>
        )}
      </div>

      {/* Family Details Modal */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full h-auto max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-200">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center">
                            <MapPin size={18} className="mr-2 text-blue-600"/>
                            {selectedFamily.address}, {selectedFamily.number}
                        </h2>
                        <p className="text-sm text-slate-500">{selectedFamily.neighborhood}</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Family Quick Info */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                             <h4 className="text-xs font-bold text-blue-600 uppercase mb-2">Próxima Visita</h4>
                             <div className="flex items-center text-blue-900 font-medium">
                                <Calendar size={18} className="mr-2"/>
                                {new Date(selectedFamily.nextVisit).toLocaleDateString()}
                             </div>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Contatos</h4>
                             <div className="space-y-1">
                                {selectedFamily.phone && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Phone size={14} className="mr-2 text-slate-400"/> {selectedFamily.phone}
                                    </div>
                                )}
                                {selectedFamily.email && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Mail size={14} className="mr-2 text-slate-400"/> {selectedFamily.email}
                                    </div>
                                )}
                                {!selectedFamily.phone && !selectedFamily.email && (
                                    <span className="text-xs text-slate-400 italic">Sem contato registrado</span>
                                )}
                             </div>
                        </div>
                    </div>

                    <h3 className="font-bold text-slate-800 mb-4 flex items-center border-b border-slate-100 pb-2">
                        <ClipboardList size={18} className="mr-2 text-slate-500"/>
                        Integrantes da Família
                    </h3>

                    {/* Member Search and Filter */}
                    <div className="mb-4">
                        <div className="relative mb-3">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Buscar integrante por nome..."
                                className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                value={memberSearchTerm}
                                onChange={(e) => setMemberSearchTerm(e.target.value)}
                            />
                            {memberSearchTerm && (
                                <button 
                                    onClick={() => setMemberSearchTerm('')}
                                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                >
                                    <X size={14} />
                                </button>
                            )}
                        </div>

                        {/* Filter Chips */}
                        <div className="flex flex-wrap gap-2 items-center">
                            <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                <Filter size={14} className="mr-1" />
                                Filtros:
                            </div>
                            <FilterButton 
                                id="pregnant" 
                                label="Gestante"
                                count={conditionCounts.pregnant}
                                icon={Baby} 
                                activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                            />
                            <FilterButton 
                                id="bedridden" 
                                label="Acamado" 
                                count={conditionCounts.bedridden}
                                icon={Bed} 
                                activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                            />
                            <FilterButton 
                                id="diabetic" 
                                label="Diabético" 
                                count={conditionCounts.diabetic}
                                icon={Droplets} 
                                activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                            />
                            <FilterButton 
                                id="hypertensive" 
                                label="Hipertenso" 
                                count={conditionCounts.hypertensive}
                                icon={HeartPulse} 
                                activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                            />
                            <FilterButton 
                                id="psychological" 
                                label="Saúde Mental" 
                                count={conditionCounts.psychological}
                                icon={Brain} 
                                activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                            />

                            {activeMemberFilters.length > 0 && (
                                <button 
                                    onClick={() => setActiveMemberFilters([])}
                                    className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                >
                                    <RotateCcw size={10} className="mr-1" /> Limpar
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filteredMembers.map(member => (
                            <div key={member.id} className="p-3 border border-slate-200 rounded-lg hover:border-blue-200 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center">
                                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3">
                                            <User size={16} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                            <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos • SUS: {member.susNumber}</span>
                                        </div>
                                    </div>
                                </div>
                                <PatientBadge patient={member} />
                                {member.medications && member.medications.length > 0 && (
                                    <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                                        <span className="font-semibold">Medicamentos:</span> {member.medications.join(', ')}
                                    </div>
                                )}
                            </div>
                        ))}
                        {filteredMembers.length === 0 && (
                            <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                {familyMembers.length === 0 
                                    ? 'Nenhum integrante cadastrado nesta família.'
                                    : 'Nenhum paciente encontrado com os filtros selecionados.'}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 bg-white">
                    <button 
                        onClick={() => setShowModal(false)}
                        className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, X, Phone, Mail, Calendar, 
  FilePlus, UserPlus, ClipboardList, RotateCcw, Search, 
  Briefcase, Activity, School, Smartphone, Armchair
} from 'lucide-react';

// 1. Health Condition Filters
const CONDITION_FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-600 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-600 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-600 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-600 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-600 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-600 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-600 border-sky-200' },
];

// 2. Age Group Filters - Updated Icons for better visual context
const AGE_FILTERS = [
  { id: 'age_0_5', label: '0 a 5 anos', min: 0, max: 5, icon: Baby, color: 'bg-indigo-100 text-indigo-600 border-indigo-200' },
  { id: 'age_6_12', label: '6 a 12 anos', min: 6, max: 12, icon: School, color: 'bg-cyan-100 text-cyan-600 border-cyan-200' },
  { id: 'age_13_17', label: '13 a 17 anos', min: 13, max: 17, icon: Smartphone, color: 'bg-teal-100 text-teal-600 border-teal-200' },
  { id: 'age_18_59', label: '18 a 59 anos', min: 18, max: 59, icon: Briefcase, color: 'bg-slate-100 text-slate-600 border-slate-200' },
  { id: 'age_60_plus', label: 'Idosos (60+)', min: 60, max: 200, icon: Armchair, color: 'bg-emerald-100 text-emerald-600 border-emerald-200' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter (Conditions + Ages)
    const newCounts: Record<string, number> = {};

    CONDITION_FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    AGE_FILTERS.forEach(filter => {
       newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    // Check Age Filters First
    const ageFilter = AGE_FILTERS.find(f => f.id === filterId);
    if (ageFilter) {
        return age >= ageFilter.min && age <= ageFilter.max;
    }

    // Check Condition Filters
    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();

  // Helper to find label of current active filter
  const getCurrentFilterLabel = () => {
    const condition = CONDITION_FILTERS.find(f => f.id === activeFilter);
    if (condition) return condition.label;
    const age = AGE_FILTERS.find(f => f.id === activeFilter);
    if (age) return age.label;
    return '';
  };

  const FilterCard = ({ filter, count, isActive, onClick }: any) => {
    const Icon = filter.icon;
    return (
      <button
        onClick={onClick}
        className={`
          relative flex items-center p-4 rounded-2xl border transition-all duration-200 w-full group
          ${isActive 
              ? `border-blue-500 bg-blue-50/50 shadow-md ring-1 ring-blue-500` 
              : `border-slate-200 bg-white shadow-sm hover:border-blue-300 hover:shadow-md hover:translate-y-[-2px]`
          }
        `}
      >
        <div className={`p-3 rounded-xl ${filter.color} transition-transform group-hover:scale-110 shrink-0`}>
          <Icon size={24} />
        </div>
        <div className="ml-4 text-left">
          <span className="block text-2xl font-bold text-slate-800 leading-none mb-1">{count}</span>
          <span className={`text-xs font-semibold uppercase tracking-wide ${isActive ? 'text-blue-700' : 'text-slate-500'}`}>
            {filter.label}
          </span>
        </div>

        {isActive && (
           <div className="absolute top-4 right-4">
               <span className="flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
               </span>
           </div>
        )}
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Analise sua área por condições de saúde e faixas etárias.</p>
      </div>

      {/* Section 1: Health Conditions */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Activity size={16} className="mr-2" /> Condições de Saúde
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {CONDITION_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Section 2: Age Groups */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Calendar size={16} className="mr-2" /> Faixa Etária
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
        {AGE_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl p-12 text-center">
             <div className="bg-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm">
                <Filter size={32} className="text-slate-300" />
             </div>
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500 max-w-sm mx-auto">Selecione um dos cards acima para visualizar a lista detalhada de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between bg-blue-50 p-4 rounded-xl border border-blue-100">
                <h2 className="text-lg font-bold text-blue-900 flex items-center">
                    Resultados: {getCurrentFilterLabel()}
                    <span className="ml-3 bg-white text-blue-700 px-3 py-0.5 rounded-full text-sm shadow-sm border border-blue-200">
                        {results.length} pacientes
                    </span>
                </h2>
                <button 
                    onClick={() => setActiveFilter(null)}
                    className="text-sm text-slate-500 hover:text-red-500 hover:bg-white px-3 py-1.5 rounded-lg transition-all flex items-center"
                >
                    <X size={16} className="mr-1" /> Limpar
                </button>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-12 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {results.map(({ patient, family }) => (
                        <div 
                            key={patient.id} 
                            onClick={() => handleOpenFamily(family)}
                            className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer active:scale-[0.99] flex flex-col md:flex-row md:items-center justify-between gap-4 group"
                        >
                            <div className="flex items-start gap-4">
                                <div className="w-12 h-12 rounded-full bg-slate-100 group-hover:bg-blue-50 flex items-center justify-center text-slate-500 group-hover:text-blue-600 transition-colors shrink-0">
                                    <User size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                    <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                        <span className="flex items-center">
                                            <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                        </span>
                                        <span className="flex items-center">
                                            <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                        </span>
                                    </div>

                                    {/* Address Display */}
                                    <div className="mt-3 flex items-start text-sm bg-slate-50 text-slate-600 p-2 rounded-lg group-hover:bg-blue-50 group-hover:text-blue-800 transition-colors">
                                        <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                        <div>
                                            {family ? (
                                                <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                            ) : (
                                                <span className="text-red-500 italic">Endereço não vinculado</span>
                                            )}
                                        </div>
                                    </div>

                                    <PatientBadge patient={patient} />
                                </div>
                            </div>

                            <div className="md:text-right shrink-0 flex flex-col items-end justify-center">
                                <span className="text-blue-600 text-sm font-medium flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                                    Ver Família <ArrowRight size={16} className="ml-1" />
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            )}
          </div>
        )}
      </div>

      {/* Family Details Modal */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full h-auto max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-200">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center">
                            <MapPin size={18} className="mr-2 text-blue-600"/>
                            {selectedFamily.address}, {selectedFamily.number}
                        </h2>
                        <p className="text-sm text-slate-500">{selectedFamily.neighborhood}</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Family Quick Info */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                             <h4 className="text-xs font-bold text-blue-600 uppercase mb-2">Próxima Visita</h4>
                             <div className="flex items-center text-blue-900 font-medium">
                                <Calendar size={18} className="mr-2"/>
                                {new Date(selectedFamily.nextVisit).toLocaleDateString()}
                             </div>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Contatos</h4>
                             <div className="space-y-1">
                                {selectedFamily.phone && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Phone size={14} className="mr-2 text-slate-400"/> {selectedFamily.phone}
                                    </div>
                                )}
                                {selectedFamily.email && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Mail size={14} className="mr-2 text-slate-400"/> {selectedFamily.email}
                                    </div>
                                )}
                                {!selectedFamily.phone && !selectedFamily.email && (
                                    <span className="text-xs text-slate-400 italic">Sem contato registrado</span>
                                )}
                             </div>
                        </div>
                    </div>

                    <h3 className="font-bold text-slate-800 mb-4 flex items-center border-b border-slate-100 pb-2">
                        <ClipboardList size={18} className="mr-2 text-slate-500"/>
                        Integrantes da Família
                    </h3>

                    {/* Member Search and Filter */}
                    <div className="mb-4">
                        <div className="relative mb-3">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Buscar integrante por nome..."
                                className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                value={memberSearchTerm}
                                onChange={(e) => setMemberSearchTerm(e.target.value)}
                            />
                            {memberSearchTerm && (
                                <button 
                                    onClick={() => setMemberSearchTerm('')}
                                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                >
                                    <X size={14} />
                                </button>
                            )}
                        </div>

                        {/* Filter Chips */}
                        <div className="flex flex-wrap gap-2 items-center">
                            <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                <Filter size={14} className="mr-1" />
                                Filtros:
                            </div>
                            <FilterButton 
                                id="pregnant" 
                                label="Gestante"
                                count={conditionCounts.pregnant}
                                icon={Baby} 
                                activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                            />
                            <FilterButton 
                                id="bedridden" 
                                label="Acamado" 
                                count={conditionCounts.bedridden}
                                icon={Bed} 
                                activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                            />
                            <FilterButton 
                                id="diabetic" 
                                label="Diabético" 
                                count={conditionCounts.diabetic}
                                icon={Droplets} 
                                activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                            />
                            <FilterButton 
                                id="hypertensive" 
                                label="Hipertenso" 
                                count={conditionCounts.hypertensive}
                                icon={HeartPulse} 
                                activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                            />
                            <FilterButton 
                                id="psychological" 
                                label="Saúde Mental" 
                                count={conditionCounts.psychological}
                                icon={Brain} 
                                activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                            />

                            {activeMemberFilters.length > 0 && (
                                <button 
                                    onClick={() => setActiveMemberFilters([])}
                                    className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                >
                                    <RotateCcw size={10} className="mr-1" /> Limpar
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filteredMembers.map(member => (
                            <div key={member.id} className="p-3 border border-slate-200 rounded-lg hover:border-blue-200 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center">
                                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3">
                                            <User size={16} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                            <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos • SUS: {member.susNumber}</span>
                                        </div>
                                    </div>
                                </div>
                                <PatientBadge patient={member} />
                                {member.medications && member.medications.length > 0 && (
                                    <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                                        <span className="font-semibold">Medicamentos:</span> {member.medications.join(', ')}
                                    </div>
                                )}
                            </div>
                        ))}
                        {filteredMembers.length === 0 && (
                            <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                {familyMembers.length === 0 
                                    ? 'Nenhum integrante cadastrado nesta família.'
                                    : 'Nenhum paciente encontrado com os filtros selecionados.'}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 bg-white">
                    <button 
                        onClick={() => setShowModal(false)}
                        className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole } from '../types';
import { 
  MapPin, Plus, AlertTriangle, Search, X, Home, Phone, Mail, 
  Save, Trash2, UserPlus, User, Baby, Bed, Activity, Brain, 
  HeartPulse, Droplets, Edit, ChevronRight, Users, Filter, RotateCcw,
  Calendar, Bell, Clock
} from 'lucide-react';

export const Families: React.FC = () => {
  const { user } = useAuth();
  const [families, setFamilies] = useState<Family[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentFamily, setCurrentFamily] = useState<Partial<Family>>({});

  // Patient Management States
  const [activeTab, setActiveTab] = useState<'details' | 'members'>('details');
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [currentMember, setCurrentMember] = useState<Partial<Patient>>({});

  // Patient Filters in Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadFamilies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadFamilies = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    setFamilies(storageService.getFamilies(agentFilter));
  };

  const loadMembers = (familyId: string) => {
    setFamilyMembers(storageService.getPatients(familyId));
  };

  // --- Family Handlers ---

  const handleOpenModal = (family?: Family, initialTab: 'details' | 'members' = 'details') => {
    if (family) {
      setCurrentFamily({ ...family });
      setIsEditing(true);
      loadMembers(family.id);
      setActiveTab(initialTab); // Open specific tab based on button clicked
    } else {
      setCurrentFamily({
        address: '',
        number: '',
        neighborhood: '',
        phone: '',
        email: '',
        riskLevel: 'LOW',
        membersCount: 0,
        nextVisit: new Date().toISOString() // Default to today for new families
      });
      setIsEditing(false);
      setFamilyMembers([]);
      setActiveTab('details');
    }
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
    setShowMemberForm(false);
  };

  const handleSaveFamily = (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    const familyToSave: Family = {
      id: currentFamily.id || crypto.randomUUID(),
      agentId: currentFamily.agentId || user.id,
      address: currentFamily.address!,
      number: currentFamily.number!,
      neighborhood: currentFamily.neighborhood!,
      membersCount: currentFamily.membersCount || 0,
      riskLevel: currentFamily.riskLevel || 'LOW',
      phone: currentFamily.phone,
      email: currentFamily.email,
      lastVisit: currentFamily.lastVisit || null,
      nextVisit: currentFamily.nextVisit || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), 
    };

    storageService.saveFamily(familyToSave);
    loadFamilies();

    // If it was a new family, we need to set the ID to allow adding members immediately without closing modal
    if (!isEditing) {
      setCurrentFamily(familyToSave);
      setIsEditing(true);
    } else {
      setShowModal(false);
    }
  };

  const handleDeleteFamily = () => {
    if (currentFamily.id && confirm('Tem certeza? Isso apagará também todos os pacientes e histórico desta família.')) {
      storageService.deleteFamily(currentFamily.id);
      loadFamilies();
      setShowModal(false);
    }
  };

  // --- Member Handlers ---

  const handleOpenMemberForm = (member?: Patient) => {
    if (member) {
      setCurrentMember({ ...member });
    } else {
      setCurrentMember({
        name: '',
        susNumber: '',
        birthDate: '',
        isPregnant: false,
        isPostpartum: false,
        isBedridden: false,
        hasMobilityIssues: false,
        isDiabetic: false,
        isHypertensive: false,
        usesInsulin: false,
        hasPsychologicalIssues: false,
        hasOtherComorbidities: false,
        medications: [],
        addictions: []
      });
    }
    setShowMemberForm(true);
  };

  const handleSaveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentFamily.id) return;

    const memberToSave: Patient = {
        id: currentMember.id || crypto.randomUUID(),
        familyId: currentFamily.id,
        name: currentMember.name!,
        susNumber: currentMember.susNumber!,
        birthDate: currentMember.birthDate!,
        isPregnant: !!currentMember.isPregnant,
        isPostpartum: !!currentMember.isPostpartum,
        isBedridden: !!currentMember.isBedridden,
        hasMobilityIssues: !!currentMember.hasMobilityIssues,
        isDiabetic: !!currentMember.isDiabetic,
        isHypertensive: !!currentMember.isHypertensive,
        usesInsulin: !!currentMember.usesInsulin,
        hasPsychologicalIssues: !!currentMember.hasPsychologicalIssues,
        hasOtherComorbidities: !!currentMember.hasOtherComorbidities,
        medications: currentMember.medications || [],
        addictions: currentMember.addictions || []
    };

    storageService.savePatient(memberToSave);
    loadMembers(currentFamily.id);
    loadFamilies(); // Update grid counts/risks
    setShowMemberForm(false);
  };

  const handleDeleteMember = (memberId: string) => {
    if (confirm('Remover este integrante da família?')) {
      storageService.deletePatient(memberId);
      if (currentFamily.id) loadMembers(currentFamily.id);
      loadFamilies(); // Update grid counts/risks
    }
  };

  // --- Filtering Logic for Members ---

  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  // --- Helpers ---

  const filteredFamilies = families.filter(f => 
    f.address.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.number.includes(searchTerm)
  );

  const getRiskConfig = (level: string) => {
    switch (level) {
      case 'URGENT':
        return { className: 'bg-red-100 text-red-700 border-red-200', label: 'Risco Urgente' };
      case 'HIGH':
        return { className: 'bg-orange-100 text-orange-700 border-orange-200', label: 'Risco Alto' };
      case 'MEDIUM':
        return { className: 'bg-yellow-100 text-yellow-800 border-yellow-200', label: 'Risco Médio' };
      case 'LOW':
        return { className: 'bg-green-100 text-green-700 border-green-200', label: 'Risco Baixo' };
      default:
        return { className: 'bg-slate-100 text-slate-700 border-slate-200', label: 'Sem Classificação' };
    }
  };

  const ConditionCheckbox = ({ label, field, icon: Icon }: { label: string, field: keyof Patient, icon: any }) => (
    <label className={`flex items-center p-3 rounded-lg border cursor-pointer transition-all ${currentMember[field] ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
        <input 
            type="checkbox" 
            className="hidden"
            checked={!!currentMember[field]}
            onChange={(e) => setCurrentMember(prev => ({ ...prev, [field]: e.target.checked }))}
        />
        <div className={`p-2 rounded-full mr-3 ${currentMember[field] ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
            <Icon size={18} />
        </div>
        <span className={`font-medium text-sm ${currentMember[field] ? 'text-blue-900' : 'text-slate-600'}`}>{label}</span>
    </label>
  );

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-800">Famílias Acompanhadas</h1>
            <p className="text-slate-500 text-sm">Gerencie os cadastros e integrantes</p>
        </div>
        <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-4 py-2.5 rounded-lg flex items-center hover:bg-blue-700 transition-colors shadow-sm shadow-blue-200 font-medium w-full md:w-auto justify-center"
        >
            <Plus size={20} className="mr-2" /> Nova Família
        </button>
      </div>

      {/* Search Bar */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search"
          placeholder="Buscar por rua, bairro ou número..."
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredFamilies.map(family => {
          const riskConfig = getRiskConfig(family.riskLevel);

          return (
            <div 
                key={family.id} 
                className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="bg-blue-50 p-2.5 rounded-full">
                  <MapPin className="text-blue-500" size={20} />
                </div>
                <span className={`text-xs font-bold px-2.5 py-1 rounded-full border ${riskConfig.className} flex items-center`}>
                  {family.riskLevel !== 'LOW' && <AlertTriangle size={10} className="mr-1" />}
                  {riskConfig.label}
                </span>
              </div>

              <div className="flex-1">
                <h3 className="font-bold text-lg text-slate-800 leading-tight mb-1">{family.address}, {family.number}</h3>
                <p className="text-sm text-slate-500 mb-2">{family.neighborhood}</p>

                {family.phone && (
                    <div className="flex items-center text-xs text-slate-500 mb-1">
                        <Phone size={12} className="mr-1" /> {family.phone}
                    </div>
                )}
              </div>

              <div className="flex gap-2 mt-5 pt-4 border-t border-slate-100">
                <button
                    onClick={() => handleOpenModal(family, 'members')}
                    className="flex-1 bg-blue-50 text-blue-700 py-2.5 rounded-lg text-sm font-bold flex items-center justify-center hover:bg-blue-100 transition-colors border border-blue-100"
                >
                    <Users size={16} className="mr-2"/>
                    Ver Integrantes ({family.membersCount})
                </button>

                <button
                    onClick={() => handleOpenModal(family, 'details')}
                    className="w-10 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors border border-slate-100"
                    title="Editar Dados da Família"
                >
                    <Edit size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {filteredFamilies.length === 0 && (
          <div className="text-center py-12 text-slate-400">
              <Home size={48} className="mx-auto mb-4 opacity-50" />
              <p>Nenhuma família encontrada.</p>
          </div>
      )}

      {/* Main Family Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <h2 className="text-lg font-bold text-slate-800">
                    {isEditing ? 'Gerenciar Família' : 'Nova Família'}
                </h2>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-1">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs */}
            {isEditing && (
                <div className="flex border-b border-slate-100 shrink-0">
                    <button 
                        onClick={() => setActiveTab('details')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Dados Cadastrais
                    </button>
                    <button 
                        onClick={() => setActiveTab('members')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'members' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Integrantes ({familyMembers.length})
                    </button>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-6 overflow-y-auto">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-4">

                        {/* New Scheduling Section - Replaces the need for search in this context */}
                        <div className="bg-blue-50 p-5 rounded-xl border border-blue-200 mb-6 shadow-sm">
                            <div className="flex items-center justify-between mb-3">
                                <label className="block text-sm font-bold text-blue-900 flex items-center">
                                    <Calendar size={18} className="mr-2 text-blue-600" />
                                    Agendar Próxima Visita
                                </label>
                                <div className="flex items-center text-xs font-bold text-blue-600 bg-white px-3 py-1 rounded-full border border-blue-100 shadow-sm">
                                    <Bell size={12} className="mr-1.5 fill-blue-600" />
                                    Notificação Ativa
                                </div>
                            </div>
                            <div className="relative">
                                <input 
                                    type="date"
                                    required
                                    className="w-full p-3 pl-10 rounded-lg border border-blue-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-slate-700 font-bold bg-white"
                                    value={currentFamily.nextVisit ? currentFamily.nextVisit.split('T')[0] : ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, nextVisit: e.target.value ? new Date(e.target.value).toISOString() : prev.nextVisit }))}
                                />
                                <Clock size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-400" />
                            </div>
                            <p className="text-xs text-blue-700 mt-2 opacity-80 pl-1">
                                O sistema enviará um alerta automaticamente quando esta data se aproximar.
                            </p>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Logradouro / Rua</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.address || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Bairro / Comunidade</label>
                            <input 
                                required
                                className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                value={currentFamily.neighborhood || ''}
                                onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone Principal</label>
                                <div className="relative">
                                    <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-between items-center border-t border-slate-100 mt-6">
                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-medium flex items-center transition-colors"
                                >
                                    <Trash2 size={16} className="mr-2" /> Excluir Família
                                </button>
                             )}
                             <button 
                                type="submit" 
                                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold hover:bg-blue-700 shadow-sm ml-auto flex items-center"
                             >
                                <Save size={18} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>
                        </div>
                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-4">
                        {!showMemberForm ? (
                            <>
                                <button 
                                    onClick={() => handleOpenMemberForm()}
                                    className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-blue-600 font-medium hover:bg-blue-50 hover:border-blue-300 transition-colors flex items-center justify-center mb-4"
                                >
                                    <UserPlus size={20} className="mr-2" /> Adicionar Integrante
                                </button>

                                {/* Member Search and Filter */}
                                <div className="mb-4">
                                    <div className="relative mb-3">
                                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                                        <input 
                                            type="text"
                                            placeholder="Buscar integrante por nome..."
                                            className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                            value={memberSearchTerm}
                                            onChange={(e) => setMemberSearchTerm(e.target.value)}
                                        />
                                        {memberSearchTerm && (
                                            <button 
                                                onClick={() => setMemberSearchTerm('')}
                                                className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                            >
                                                <X size={14} />
                                            </button>
                                        )}
                                    </div>

                                    {/* Filter Chips */}
                                    <div className="flex flex-wrap gap-2 items-center">
                                        <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                            <Filter size={14} className="mr-1" />
                                            Filtros:
                                        </div>
                                        <FilterButton 
                                            id="pregnant" 
                                            label="Gestante"
                                            count={conditionCounts.pregnant}
                                            icon={Baby} 
                                            activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                                        />
                                        <FilterButton 
                                            id="bedridden" 
                                            label="Acamado" 
                                            count={conditionCounts.bedridden}
                                            icon={Bed} 
                                            activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                                        />
                                        <FilterButton 
                                            id="diabetic" 
                                            label="Diabético" 
                                            count={conditionCounts.diabetic}
                                            icon={Droplets} 
                                            activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                                        />
                                        <FilterButton 
                                            id="hypertensive" 
                                            label="Hipertenso" 
                                            count={conditionCounts.hypertensive}
                                            icon={HeartPulse} 
                                            activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                                        />
                                        <FilterButton 
                                            id="psychological" 
                                            label="Saúde Mental" 
                                            count={conditionCounts.psychological}
                                            icon={Brain} 
                                            activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                                        />

                                        {activeMemberFilters.length > 0 && (
                                            <button 
                                                onClick={() => setActiveMemberFilters([])}
                                                className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                            >
                                                <RotateCcw size={10} className="mr-1" /> Limpar
                                            </button>
                                        )}
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    {filteredMembers.map(member => (
                                        <div key={member.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-blue-300 transition-colors">
                                            <div className="flex items-center">
                                                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-400 border border-slate-200 mr-3">
                                                    <User size={20} />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                                    <div className="flex gap-2 text-xs text-slate-500">
                                                        <span>SUS: {member.susNumber}</span>
                                                        <span>•</span>
                                                        <span>{new Date(member.birthDate).toLocaleDateString()}</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => handleOpenMemberForm(member)}
                                                    className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                                                >
                                                    <Edit size={16} />
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteMember(member.id)}
                                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredMembers.length === 0 && (
                                        <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                            {familyMembers.length === 0 
                                                ? 'Nenhum integrante cadastrado nesta família.'
                                                : 'Nenhum paciente encontrado com os filtros selecionados.'}
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            // Member Form
                            <form onSubmit={handleSaveMember} className="space-y-4 animate-in slide-in-from-right duration-200">
                                <div className="flex items-center text-slate-500 mb-2">
                                    <button type="button" onClick={() => setShowMemberForm(false)} className="hover:text-blue-600 text-sm flex items-center">
                                        <ChevronRight size={16} className="rotate-180 mr-1" /> Voltar
                                    </button>
                                    <span className="mx-2 text-slate-300">|</span>
                                    <span className="text-sm font-medium text-slate-800">{currentMember.id ? 'Editar Paciente' : 'Novo Paciente'}</span>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
                                    <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.name || ''} onChange={e => setCurrentMember(prev => ({ ...prev, name: e.target.value }))} />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Cartão SUS</label>
                                        <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.susNumber || ''} onChange={e => setCurrentMember(prev => ({ ...prev, susNumber: e.target.value }))} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                                        <input type="date" required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.birthDate?.split('T')[0] || ''} onChange={e => setCurrentMember(prev => ({ ...prev, birthDate: e.target.value }))} />
                                    </div>
                                </div>

                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-4">
                                    <h4 className="font-bold text-slate-800 text-sm mb-3">Condições de Saúde</h4>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                        <ConditionCheckbox label="Gestante" field="isPregnant" icon={Baby} />
                                        <ConditionCheckbox label="Diabético(a)" field="isDiabetic" icon={Droplets} />
                                        <ConditionCheckbox label="Hipertenso(a)" field="isHypertensive" icon={HeartPulse} />
                                        <ConditionCheckbox label="Acamado(a)" field="isBedridden" icon={Bed} />
                                        <ConditionCheckbox label="Saúde Mental" field="hasPsychologicalIssues" icon={Brain} />
                                        <ConditionCheckbox label="Outras" field="hasOtherComorbidities" icon={Activity} />
                                    </div>
                                </div>

                                <button type="submit" className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-bold hover:bg-blue-700 mt-4 shadow-sm">
                                    Salvar Integrante
                                </button>
                            </form>
                        )}
                    </div>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole } from '../types';
import { 
  MapPin, Plus, AlertTriangle, Search, X, Home, Phone, Mail, 
  Save, Trash2, UserPlus, User, Baby, Bed, Activity, Brain, 
  HeartPulse, Droplets, Edit, ChevronRight, Users, Filter, RotateCcw,
  Calendar, Bell, Clock, CheckCircle2, AlertCircle
} from 'lucide-react';

export const Families: React.FC = () => {
  const { user } = useAuth();
  const [families, setFamilies] = useState<Family[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentFamily, setCurrentFamily] = useState<Partial<Family>>({});

  // Patient Management States
  const [activeTab, setActiveTab] = useState<'details' | 'members'>('details');
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [currentMember, setCurrentMember] = useState<Partial<Patient>>({});

  // Patient Filters in Modal
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  // Date Confirmation State
  const [dateConfirmed, setDateConfirmed] = useState(false);

  useEffect(() => {
    loadFamilies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadFamilies = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    setFamilies(storageService.getFamilies(agentFilter));
  };

  const loadMembers = (familyId: string) => {
    setFamilyMembers(storageService.getPatients(familyId));
  };

  // --- Family Handlers ---

  const handleOpenModal = (family?: Family, initialTab: 'details' | 'members' = 'details') => {
    if (family) {
      setCurrentFamily({ ...family });
      setIsEditing(true);
      loadMembers(family.id);
      setActiveTab(initialTab); // Open specific tab based on button clicked
    } else {
      setCurrentFamily({
        address: '',
        number: '',
        neighborhood: '',
        phone: '',
        email: '',
        riskLevel: 'LOW',
        membersCount: 0,
        nextVisit: new Date().toISOString() // Default to today for new families
      });
      setIsEditing(false);
      setFamilyMembers([]);
      setActiveTab('details');
    }
    // Reset filters
    setActiveMemberFilters([]);
    setShowModal(true);
    setShowMemberForm(false);
    setDateConfirmed(false);
  };

  const handleSaveFamily = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!user) return;

    const familyToSave: Family = {
      id: currentFamily.id || crypto.randomUUID(),
      agentId: currentFamily.agentId || user.id,
      address: currentFamily.address!,
      number: currentFamily.number!,
      neighborhood: currentFamily.neighborhood!,
      membersCount: currentFamily.membersCount || 0,
      riskLevel: currentFamily.riskLevel || 'LOW',
      phone: currentFamily.phone,
      email: currentFamily.email,
      lastVisit: currentFamily.lastVisit || null,
      nextVisit: currentFamily.nextVisit || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(), 
    };

    storageService.saveFamily(familyToSave);
    loadFamilies();

    // If it was a new family, we need to set the ID to allow adding members immediately without closing modal
    if (!isEditing) {
      setCurrentFamily(familyToSave);
      setIsEditing(true);
    } else {
      if (e) setShowModal(false); // Only close if it's the main form submit
    }
  };

  const handleConfirmDate = () => {
    handleSaveFamily(); // Save current state
    setDateConfirmed(true);
    setTimeout(() => setDateConfirmed(false), 3000);
  };

  const handleDeleteFamily = () => {
    if (currentFamily.id && confirm('Tem certeza? Isso apagará também todos os pacientes e histórico desta família.')) {
      storageService.deleteFamily(currentFamily.id);
      loadFamilies();
      setShowModal(false);
    }
  };

  // --- Member Handlers ---

  const handleOpenMemberForm = (member?: Patient) => {
    if (member) {
      setCurrentMember({ ...member });
    } else {
      setCurrentMember({
        name: '',
        susNumber: '',
        birthDate: '',
        isPregnant: false,
        isPostpartum: false,
        isBedridden: false,
        hasMobilityIssues: false,
        isDiabetic: false,
        isHypertensive: false,
        usesInsulin: false,
        hasPsychologicalIssues: false,
        hasOtherComorbidities: false,
        medications: [],
        addictions: []
      });
    }
    setShowMemberForm(true);
  };

  const handleSaveMember = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentFamily.id) return;

    const memberToSave: Patient = {
        id: currentMember.id || crypto.randomUUID(),
        familyId: currentFamily.id,
        name: currentMember.name!,
        susNumber: currentMember.susNumber!,
        birthDate: currentMember.birthDate!,
        isPregnant: !!currentMember.isPregnant,
        isPostpartum: !!currentMember.isPostpartum,
        isBedridden: !!currentMember.isBedridden,
        hasMobilityIssues: !!currentMember.hasMobilityIssues,
        isDiabetic: !!currentMember.isDiabetic,
        isHypertensive: !!currentMember.isHypertensive,
        usesInsulin: !!currentMember.usesInsulin,
        hasPsychologicalIssues: !!currentMember.hasPsychologicalIssues,
        hasOtherComorbidities: !!currentMember.hasOtherComorbidities,
        medications: currentMember.medications || [],
        addictions: currentMember.addictions || []
    };

    storageService.savePatient(memberToSave);
    loadMembers(currentFamily.id);
    loadFamilies(); // Update grid counts/risks
    setShowMemberForm(false);
  };

  const handleDeleteMember = (memberId: string) => {
    if (confirm('Remover este integrante da família?')) {
      storageService.deletePatient(memberId);
      if (currentFamily.id) loadMembers(currentFamily.id);
      loadFamilies(); // Update grid counts/risks
    }
  };

  // --- Filtering Logic for Members ---

  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    if (activeMemberFilters.length === 0) return true;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesFilter;
  });

  // Calculate counts for badges
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  // --- Helpers ---

  const filteredFamilies = families.filter(f => 
    f.address.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.neighborhood.toLowerCase().includes(searchTerm.toLowerCase()) ||
    f.number.includes(searchTerm)
  );

  const getRiskConfig = (level: string) => {
    switch (level) {
      case 'URGENT':
        return { className: 'bg-red-100 text-red-700 border-red-200', label: 'Risco Urgente' };
      case 'HIGH':
        return { className: 'bg-orange-100 text-orange-700 border-orange-200', label: 'Risco Alto' };
      case 'MEDIUM':
        return { className: 'bg-yellow-100 text-yellow-800 border-yellow-200', label: 'Risco Médio' };
      case 'LOW':
        return { className: 'bg-green-100 text-green-700 border-green-200', label: 'Risco Baixo' };
      default:
        return { className: 'bg-slate-100 text-slate-700 border-slate-200', label: 'Sem Classificação' };
    }
  };

  const ConditionCheckbox = ({ label, field, icon: Icon }: { label: string, field: keyof Patient, icon: any }) => (
    <label className={`flex items-center p-3 rounded-lg border cursor-pointer transition-all ${currentMember[field] ? 'bg-blue-50 border-blue-200' : 'bg-white border-slate-200 hover:bg-slate-50'}`}>
        <input 
            type="checkbox" 
            className="hidden"
            checked={!!currentMember[field]}
            onChange={(e) => setCurrentMember(prev => ({ ...prev, [field]: e.target.checked }))}
        />
        <div className={`p-2 rounded-full mr-3 ${currentMember[field] ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
            <Icon size={18} />
        </div>
        <span className={`font-medium text-sm ${currentMember[field] ? 'text-blue-900' : 'text-slate-600'}`}>{label}</span>
    </label>
  );

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-800">Famílias Acompanhadas</h1>
            <p className="text-slate-500 text-sm">Gerencie os cadastros e integrantes</p>
        </div>
        <button 
            onClick={() => handleOpenModal()}
            className="bg-blue-600 text-white px-4 py-2.5 rounded-lg flex items-center hover:bg-blue-700 transition-colors shadow-sm shadow-blue-200 font-medium w-full md:w-auto justify-center"
        >
            <Plus size={20} className="mr-2" /> Nova Família
        </button>
      </div>

      {/* Search Bar */}
      <div className="mb-6 relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search"
          placeholder="Buscar por rua, bairro ou número..."
          className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredFamilies.map(family => {
          const riskConfig = getRiskConfig(family.riskLevel);

          return (
            <div 
                key={family.id} 
                className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-200 flex flex-col h-full"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="bg-blue-50 p-2.5 rounded-full">
                  <MapPin className="text-blue-500" size={20} />
                </div>
                <span className={`text-xs font-bold px-2.5 py-1 rounded-full border ${riskConfig.className} flex items-center`}>
                  {family.riskLevel !== 'LOW' && <AlertTriangle size={10} className="mr-1" />}
                  {riskConfig.label}
                </span>
              </div>

              <div className="flex-1">
                <h3 className="font-bold text-lg text-slate-800 leading-tight mb-1">{family.address}, {family.number}</h3>
                <p className="text-sm text-slate-500 mb-2">{family.neighborhood}</p>

                {family.phone && (
                    <div className="flex items-center text-xs text-slate-500 mb-1">
                        <Phone size={12} className="mr-1" /> {family.phone}
                    </div>
                )}
              </div>

              <div className="flex gap-2 mt-5 pt-4 border-t border-slate-100">
                <button
                    onClick={() => handleOpenModal(family, 'members')}
                    className="flex-1 bg-blue-50 text-blue-700 py-2.5 rounded-lg text-sm font-bold flex items-center justify-center hover:bg-blue-100 transition-colors border border-blue-100"
                >
                    <Users size={16} className="mr-2"/>
                    Ver Integrantes ({family.membersCount})
                </button>

                <button
                    onClick={() => handleOpenModal(family, 'details')}
                    className="w-10 flex items-center justify-center text-slate-400 hover:text-blue-600 hover:bg-slate-100 rounded-lg transition-colors border border-slate-100"
                    title="Editar Dados da Família"
                >
                    <Edit size={18} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {filteredFamilies.length === 0 && (
          <div className="text-center py-12 text-slate-400">
              <Home size={48} className="mx-auto mb-4 opacity-50" />
              <p>Nenhuma família encontrada.</p>
          </div>
      )}

      {/* Main Family Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 shrink-0">
                <h2 className="text-lg font-bold text-slate-800">
                    {isEditing ? 'Gerenciar Família' : 'Nova Família'}
                </h2>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-1">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs */}
            {isEditing && (
                <div className="flex border-b border-slate-100 shrink-0">
                    <button 
                        onClick={() => setActiveTab('details')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Dados Cadastrais
                    </button>
                    <button 
                        onClick={() => setActiveTab('members')}
                        className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'members' ? 'border-blue-500 text-blue-600 bg-blue-50/50' : 'border-transparent text-slate-500 hover:bg-slate-50'}`}
                    >
                        Integrantes ({familyMembers.length})
                    </button>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-6 overflow-y-auto">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Logradouro / Rua</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.address || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                                <input 
                                    required
                                    className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Bairro / Comunidade</label>
                            <input 
                                required
                                className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                value={currentFamily.neighborhood || ''}
                                onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Telefone Principal</label>
                                <div className="relative">
                                    <Phone size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-10 p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-between items-center border-t border-slate-100 mt-6">
                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-medium flex items-center transition-colors"
                                >
                                    <Trash2 size={16} className="mr-2" /> Excluir Família
                                </button>
                             )}
                             <button 
                                type="submit" 
                                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold hover:bg-blue-700 shadow-sm ml-auto flex items-center"
                             >
                                <Save size={18} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>
                        </div>
                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-4">
                        {!showMemberForm ? (
                            <>
                                {/* Visit Scheduling Section - Moved here to replace search bar area */}
                                <div className="bg-blue-50 p-4 rounded-xl border border-blue-200 mb-4 shadow-sm animate-in slide-in-from-top duration-300">
                                    <div className="flex items-center justify-between mb-3">
                                        <div className="flex items-center">
                                            <div className="bg-blue-100 p-2 rounded-lg mr-3">
                                                <Calendar size={20} className="text-blue-600" />
                                            </div>
                                            <div>
                                                <h4 className="font-bold text-blue-900 text-sm">Agendar Próxima Visita</h4>
                                                <p className="text-xs text-blue-600 opacity-80">Define a data para notificações</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center text-[10px] font-bold text-blue-600 bg-white px-2 py-1 rounded-full border border-blue-100 shadow-sm">
                                            <Bell size={10} className="mr-1 fill-blue-600" />
                                            Alertas Ativos
                                        </div>
                                    </div>

                                    <div className="flex gap-2">
                                        <div className="relative flex-1">
                                            <input 
                                                type="date"
                                                required
                                                className="w-full p-2.5 pl-10 rounded-lg border border-blue-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-slate-700 font-bold bg-white text-sm"
                                                value={currentFamily.nextVisit ? currentFamily.nextVisit.split('T')[0] : ''}
                                                onChange={e => setCurrentFamily(prev => ({ ...prev, nextVisit: e.target.value ? new Date(e.target.value).toISOString() : prev.nextVisit }))}
                                                min={new Date().toISOString().split('T')[0]} // Cannot schedule in past
                                            />
                                            <Clock size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-400" />
                                        </div>
                                        <button 
                                            type="button"
                                            onClick={handleConfirmDate}
                                            className={`px-4 py-2 rounded-lg font-bold text-sm flex items-center shadow-sm transition-all
                                                ${dateConfirmed 
                                                    ? 'bg-green-500 text-white hover:bg-green-600 border-green-500' 
                                                    : 'bg-white text-blue-600 border border-blue-200 hover:bg-blue-50'
                                                }`}
                                        >
                                            {dateConfirmed ? (
                                                <><CheckCircle2 size={16} className="mr-1.5" /> Confirmado</>
                                            ) : (
                                                <><Save size={16} className="mr-1.5" /> Confirmar Data</>
                                            )}
                                        </button>
                                    </div>
                                </div>

                                {/* Filter Chips */}
                                <div className="flex flex-wrap gap-2 items-center mb-4">
                                    <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                        <Filter size={14} className="mr-1" />
                                        Filtrar:
                                    </div>
                                    <FilterButton 
                                        id="pregnant" 
                                        label="Gestante"
                                        count={conditionCounts.pregnant}
                                        icon={Baby} 
                                        activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                                    />
                                    <FilterButton 
                                        id="bedridden" 
                                        label="Acamado" 
                                        count={conditionCounts.bedridden}
                                        icon={Bed} 
                                        activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                                    />
                                    <FilterButton 
                                        id="diabetic" 
                                        label="Diabético" 
                                        count={conditionCounts.diabetic}
                                        icon={Droplets} 
                                        activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                                    />
                                    <FilterButton 
                                        id="hypertensive" 
                                        label="Hipertenso" 
                                        count={conditionCounts.hypertensive}
                                        icon={HeartPulse} 
                                        activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                                    />
                                    <FilterButton 
                                        id="psychological" 
                                        label="Saúde Mental" 
                                        count={conditionCounts.psychological}
                                        icon={Brain} 
                                        activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                                    />

                                    {activeMemberFilters.length > 0 && (
                                        <button 
                                            onClick={() => setActiveMemberFilters([])}
                                            className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                        >
                                            <RotateCcw size={10} className="mr-1" /> Limpar
                                        </button>
                                    )}
                                </div>

                                <div className="space-y-3">
                                    {filteredMembers.map(member => (
                                        <div key={member.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-blue-300 transition-colors">
                                            <div className="flex items-center">
                                                <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-slate-400 border border-slate-200 mr-3">
                                                    <User size={20} />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                                    <div className="flex gap-2 text-xs text-slate-500">
                                                        <span>SUS: {member.susNumber}</span>
                                                        <span>•</span>
                                                        <span>{new Date(member.birthDate).toLocaleDateString()}</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex gap-1">
                                                <button 
                                                    onClick={() => handleOpenMemberForm(member)}
                                                    className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                                                >
                                                    <Edit size={16} />
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteMember(member.id)}
                                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}

                                    <button 
                                        onClick={() => handleOpenMemberForm()}
                                        className="w-full py-3 border-2 border-dashed border-slate-200 rounded-xl text-slate-500 font-medium hover:bg-slate-50 hover:border-slate-300 transition-colors flex items-center justify-center mt-4"
                                    >
                                        <UserPlus size={18} className="mr-2" /> Adicionar Integrante
                                    </button>

                                    {filteredMembers.length === 0 && familyMembers.length > 0 && (
                                        <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                            Nenhum paciente encontrado com os filtros selecionados.
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            // Member Form
                            <form onSubmit={handleSaveMember} className="space-y-4 animate-in slide-in-from-right duration-200">
                                <div className="flex items-center text-slate-500 mb-2">
                                    <button type="button" onClick={() => setShowMemberForm(false)} className="hover:text-blue-600 text-sm flex items-center">
                                        <ChevronRight size={16} className="rotate-180 mr-1" /> Voltar
                                    </button>
                                    <span className="mx-2 text-slate-300">|</span>
                                    <span className="text-sm font-medium text-slate-800">{currentMember.id ? 'Editar Paciente' : 'Novo Paciente'}</span>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
                                    <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.name || ''} onChange={e => setCurrentMember(prev => ({ ...prev, name: e.target.value }))} />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Cartão SUS</label>
                                        <input required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.susNumber || ''} onChange={e => setCurrentMember(prev => ({ ...prev, susNumber: e.target.value }))} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento</label>
                                        <input type="date" required className="w-full p-2.5 rounded-lg border border-slate-300" value={currentMember.birthDate?.split('T')[0] || ''} onChange={e => setCurrentMember(prev => ({ ...prev, birthDate: e.target.value }))} />
                                    </div>
                                </div>

                                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-4">
                                    <h4 className="font-bold text-slate-800 text-sm mb-3">Condições de Saúde</h4>
                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                        <ConditionCheckbox label="Gestante" field="isPregnant" icon={Baby} />
                                        <ConditionCheckbox label="Diabético(a)" field="isDiabetic" icon={Droplets} />
                                        <ConditionCheckbox label="Hipertenso(a)" field="isHypertensive" icon={HeartPulse} />
                                        <ConditionCheckbox label="Acamado(a)" field="isBedridden" icon={Bed} />
                                        <ConditionCheckbox label="Saúde Mental" field="hasPsychologicalIssues" icon={Brain} />
                                        <ConditionCheckbox label="Outras" field="hasOtherComorbidities" icon={Activity} />
                                    </div>
                                </div>

                                <button type="submit" className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-bold hover:bg-blue-700 mt-4 shadow-sm">
                                    Salvar Integrante
                                </button>
                            </form>
                        )}
                    </div>
                )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

{
  "name": "ACS Pro - Saúde da Família",
  "description": "Sistema completo para Agentes Comunitários de Saúde com gestão de famílias, visitas inteligentes e controle de acesso.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export enum UserRole {
  ADMIN = 'ADMIN',
  AGENT = 'AGENT',
}

export enum UserStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  BLOCKED = 'BLOCKED',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  area?: string;
  phone?: string;
  password?: string; // In a real app, this would be hashed
  subscriptionExpiresAt?: string; // ISO Date string for access expiration
}

export interface Patient {
  id: string;
  familyId: string;
  name: string;
  birthDate: string;
  susNumber: string;
  // Conditions
  isPregnant: boolean;
  isPostpartum: boolean; // Puérperas
  isBedridden: boolean; // Acamados
  hasMobilityIssues: boolean; // Dificuldade de locomoção
  isDiabetic: boolean;
  usesInsulin: boolean; // Insulinos
  isHypertensive: boolean;
  hasPsychologicalIssues: boolean;
  hasOtherComorbidities: boolean; // Outras comorbidades
  medications: string[];
  addictions: string[];
}

export interface Family {
  id: string;
  agentId: string;
  address: string;
  number: string;
  neighborhood: string;
  membersCount: number;
  lastVisit: string | null; // ISO Date
  nextVisit: string; // ISO Date calculated
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
  phone?: string;
  email?: string;
}

export interface Visit {
  id: string;
  familyId: string;
  agentId: string;
  date: string;
  notes: string;
  generalObservations?: string;
  outcome: string;
  measurements: {
    bloodPressure?: string;
    glucose?: string;
    weight?: string;
  }[];
  procedures?: string[];
  location?: {
    latitude: number;
    longitude: number;
    accuracy?: number;
  };
}

export interface DashboardStats {
  totalFamilies: number;
  totalPatients: number;
  pendingVisits: number;
  highRiskFamilies: number;
}

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { Family, Patient, UserRole, Visit } from '../types';
import { 
  Calendar, AlertCircle, CheckCircle, Clock, Baby, HeartPulse, Brain, Bed, 
  Search, X, User, Activity, Droplets, ChevronLeft, Filter, Phone, Mail, Save,
  UserPlus, Accessibility, Syringe, FilePlus, Clipboard, RotateCcw, Paperclip,
  MapPin, Stethoscope, Pill, Scale, CheckSquare
} from 'lucide-react';

// Procedures checklist options
const PROCEDURES_LIST = [
    { id: 'pressure', label: 'Aferição de P.A.', icon: HeartPulse },
    { id: 'glucose', label: 'Glicemia Capilar', icon: Droplets },
    { id: 'weight', label: 'Peso / Altura', icon: Scale },
    { id: 'medication', label: 'Entrega de Medicação', icon: Pill },
    { id: 'orientation', label: 'Orientação Nutricional', icon: Brain },
    { id: 'dengue', label: 'Vistoria de Focos (ACE)', icon: Search },
    { id: 'vaccine', label: 'Verificação Vacinal', icon: Syringe },
    { id: 'dressing', label: 'Curativo / Procedimentos', icon: Stethoscope },
];

export const Visits: React.FC = () => {
  const { user } = useAuth();
  const [pendingFamilies, setPendingFamilies] = useState<Family[]>([]);
  const [allPatients, setAllPatients] = useState<Patient[]>([]); // New state for list view badges
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);

  // Visit Form States
  const [visitNotes, setVisitNotes] = useState('');
  const [visitObservations, setVisitObservations] = useState('');
  const [selectedProcedures, setSelectedProcedures] = useState<string[]>([]);
  const [location, setLocation] = useState<{lat: number, lng: number, acc?: number} | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [locationError, setLocationError] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New state for patient search inside modal
  const [patientSearchTerm, setPatientSearchTerm] = useState('');
  // New state for health status filters
  const [activeFilters, setActiveFilters] = useState<string[]>([]);
  // State for contact saving feedback
  const [contactSaved, setContactSaved] = useState(false);

  useEffect(() => {
    loadVisits();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadVisits = () => {
    if (!user) return;
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const families = storageService.getFamilies(agentFilter);

    // Sort by nextVisit date ascending (most urgent first)
    const sorted = families.sort((a, b) => new Date(a.nextVisit).getTime() - new Date(b.nextVisit).getTime());
    setPendingFamilies(sorted);

    // Load all patients to display badges in the list view
    const patients = storageService.getPatients();
    setAllPatients(patients);
  };

  const handleOpenFamily = (family: Family) => {
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    setShowModal(true);
    // Reset Form
    setVisitNotes('');
    setVisitObservations('');
    setSelectedProcedures([]);
    setLocation(null);
    setLocationError('');
    setPatientSearchTerm(''); 
    setActiveFilters([]); 
    setContactSaved(false);

    // Try to auto-capture location on open (optional, but good for field work)
    captureLocation(); 
  };

  const captureLocation = () => {
    if (!navigator.geolocation) {
        setLocationError('Geolocalização não suportada');
        return;
    }
    setIsLocating(true);
    setLocationError('');

    navigator.geolocation.getCurrentPosition(
        (position) => {
            setLocation({
                lat: position.coords.latitude,
                lng: position.coords.longitude,
                acc: position.coords.accuracy
            });
            setIsLocating(false);
        },
        (error) => {
            console.error(error);
            setIsLocating(false);
            setLocationError('Erro ao obter localização');
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    );
  };

  const handleToggleProcedure = (id: string) => {
    setSelectedProcedures(prev => 
        prev.includes(id) 
            ? prev.filter(p => p !== id) 
            : [...prev, id]
    );
  };

  const handleFamilyUpdate = (field: 'phone' | 'email', value: string) => {
    if (selectedFamily) {
        setSelectedFamily({ ...selectedFamily, [field]: value });
        setContactSaved(false);
    }
  };

  const saveFamilyContact = () => {
    if (selectedFamily) {
        storageService.saveFamily(selectedFamily);
        setContactSaved(true);
        loadVisits(); // Update the main list in background
        setTimeout(() => setContactSaved(false), 3000);
    }
  };

  const toggleFilter = (filter: string) => {
    setActiveFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const handleCompleteVisit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFamily || !user) return;

    // Save contact info implicitly when completing visit
    storageService.saveFamily(selectedFamily);

    const newVisit: Visit = {
      id: crypto.randomUUID(),
      familyId: selectedFamily.id,
      agentId: user.id,
      date: new Date().toISOString(),
      notes: visitNotes,
      generalObservations: visitObservations,
      outcome: 'Realizada',
      measurements: [], // In a full app, we would capture measurements here
      procedures: selectedProcedures,
      location: location ? {
        latitude: location.lat,
        longitude: location.lng,
        accuracy: location.acc
      } : undefined
    };

    storageService.addVisit(newVisit);
    setShowModal(false);
    loadVisits(); // Reload to see the family moved to bottom of list or removed if filtering by date
  };

  const getUrgencyColor = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'border-l-4 border-red-500 bg-red-50'; // Late
    if (diffDays <= 7) return 'border-l-4 border-orange-400 bg-orange-50'; // Upcoming week
    return 'border-l-4 border-blue-400 bg-white'; // Future
  };

  const getUrgencyText = (dateString: string) => {
    const today = new Date();
    const visitDate = new Date(dateString);
    const diffTime = visitDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return <span className="text-red-600 font-bold flex items-center"><AlertCircle size={14} className="mr-1"/> Atrasada ({Math.abs(diffDays)} dias)</span>;
    if (diffDays === 0) return <span className="text-green-600 font-bold flex items-center"><Calendar size={14} className="mr-1"/> Hoje</span>;
    return <span className="text-slate-500 flex items-center"><Clock size={14} className="mr-1"/> Em {diffDays} dias</span>;
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  const getDaysUntilVisit = (dateString: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const visitDate = new Date(dateString);
    visitDate.setHours(0,0,0,0);
    const diffTime = visitDate.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  // Helper to render badges inside the family card list
  const FamilyConditionsBadges = ({ familyId }: { familyId: string }) => {
    const patients = allPatients.filter(p => p.familyId === familyId);

    // Aggregate conditions
    const counts = {
        pregnant: patients.filter(p => p.isPregnant).length,
        bedridden: patients.filter(p => p.isBedridden).length,
        diabetic: patients.filter(p => p.isDiabetic).length,
        hypertensive: patients.filter(p => p.isHypertensive).length,
        psychological: patients.filter(p => p.hasPsychologicalIssues).length,
        postpartum: patients.filter(p => p.isPostpartum).length,
    };

    const hasConditions = Object.values(counts).some(c => c > 0);

    if (!hasConditions) return null;

    return (
        <div className="mt-3 flex flex-wrap gap-2 border-t border-slate-100 pt-3">
            {counts.pregnant > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-pink-100 text-pink-700 border border-pink-200">
                    <Baby size={10} className="mr-1" /> Gestante {counts.pregnant > 1 && `(${counts.pregnant})`}
                </span>
            )}
            {counts.postpartum > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-rose-100 text-rose-700 border border-rose-200">
                    <UserPlus size={10} className="mr-1" /> Puérpera
                </span>
            )}
            {counts.bedridden > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-purple-100 text-purple-700 border border-purple-200">
                    <Bed size={10} className="mr-1" /> Acamado {counts.bedridden > 1 && `(${counts.bedridden})`}
                </span>
            )}
            {counts.diabetic > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-blue-100 text-blue-700 border border-blue-200">
                    <Droplets size={10} className="mr-1" /> Diabético {counts.diabetic > 1 && `(${counts.diabetic})`}
                </span>
            )}
            {counts.hypertensive > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-700 border border-red-200">
                    <HeartPulse size={10} className="mr-1" /> Hipertenso {counts.hypertensive > 1 && `(${counts.hypertensive})`}
                </span>
            )}
            {counts.psychological > 0 && (
                <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-yellow-100 text-yellow-700 border border-yellow-200">
                    <Brain size={10} className="mr-1" /> Saúde Mental
                </span>
            )}
        </div>
    );
  };

  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) {
        return <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-xs rounded-full flex items-center w-fit">Sem queixas registradas</span>;
    }

    return (
      <div className="flex flex-wrap gap-2 mt-2">
        {patient.isPregnant && (
            <span className="px-2 py-1 bg-pink-100 text-pink-700 text-xs font-medium rounded-md flex items-center border border-pink-200">
                <Baby size={12} className="mr-1.5"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-2 py-1 bg-rose-100 text-rose-700 text-xs font-medium rounded-md flex items-center border border-rose-200">
                <UserPlus size={12} className="mr-1.5"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-medium rounded-md flex items-center border border-purple-200">
                <Bed size={12} className="mr-1.5"/>Acamado(a)
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-2 py-1 bg-orange-100 text-orange-700 text-xs font-medium rounded-md flex items-center border border-orange-200">
                <Accessibility size={12} className="mr-1.5"/>Dif. Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-medium rounded-md flex items-center border border-blue-200">
                <Droplets size={12} className="mr-1.5"/>Diabético(a)
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-2 py-1 bg-sky-100 text-sky-700 text-xs font-medium rounded-md flex items-center border border-sky-200">
                <Syringe size={12} className="mr-1.5"/>Uso de Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-2 py-1 bg-red-100 text-red-700 text-xs font-medium rounded-md flex items-center border border-red-200">
                <HeartPulse size={12} className="mr-1.5"/>Hipertenso(a)
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs font-medium rounded-md flex items-center border border-yellow-200">
                <Brain size={12} className="mr-1.5"/>Saúde Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-2 py-1 bg-slate-100 text-slate-700 text-xs font-medium rounded-md flex items-center border border-slate-200">
                <FilePlus size={12} className="mr-1.5"/>Outras
            </span>
        )}
      </div>
    );
  };

  // Filter families based on search term
  const filteredFamilies = pendingFamilies.filter(family => {
    const term = searchTerm.toLowerCase();
    return (
      family.address.toLowerCase().includes(term) ||
      family.number.toLowerCase().includes(term) ||
      family.neighborhood.toLowerCase().includes(term)
    );
  });

  // Filter patients based on patient search term AND active status filters
  const filteredPatients = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(patientSearchTerm.toLowerCase());

    if (activeFilters.length === 0) return matchesName;

    // Filter Logic: OR (If patient has AT LEAST one of the selected conditions)
    const matchesFilter = activeFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Count available conditions in the family
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeFilters.includes(id);
    const isDisabled = count === 0;

    return (
      <button
        onClick={() => !isDisabled && toggleFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0"> {/* Add padding bottom for mobile if needed */}
      <h1 className="text-2xl font-bold text-slate-800 mb-6 px-1">Controle de Visitas</h1>

      {/* Search Input */}
      <div className="mb-6 relative mx-1">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="search" // Optimized for mobile keyboards
          placeholder="Buscar por rua, número ou bairro..."
          className="w-full pl-10 pr-10 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none shadow-sm transition-all text-base bg-white" 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        {searchTerm && (
          <button 
            onClick={() => setSearchTerm('')}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="grid gap-4">
        {filteredFamilies.map(family => (
          <div 
            key={family.id} 
            onClick={() => handleOpenFamily(family)}
            className={`p-4 rounded-lg shadow-sm cursor-pointer transition-all hover:shadow-md active:scale-[0.99] touch-manipulation ${getUrgencyColor(family.nextVisit)}`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="font-bold text-lg text-slate-800">{family.address}, {family.number}</h3>
                <p className="text-slate-500 text-sm">{family.neighborhood} • {family.membersCount} integrantes</p>
                <div className="mt-2 text-xs text-slate-400">
                  Última visita: {family.lastVisit ? new Date(family.lastVisit).toLocaleDateString() : 'Nunca'}
                </div>
              </div>
              <div className="text-right">
                <div className="mb-1">{getUrgencyText(family.nextVisit)}</div>
                <div className="text-xs text-slate-400">Meta: {new Date(family.nextVisit).toLocaleDateString()}</div>
              </div>
            </div>

            {/* Health Conditions Badges visible on card */}
            <FamilyConditionsBadges familyId={family.id} />

          </div>
        ))}

        {filteredFamilies.length === 0 && (
          <div className="text-center py-12 bg-white rounded-lg mx-1">
            {searchTerm ? (
              <>
                <Search className="mx-auto text-slate-300 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Nenhum resultado encontrado</h3>
                <p className="text-slate-500">Tente buscar por outro termo.</p>
              </>
            ) : (
              <>
                <CheckCircle className="mx-auto text-green-500 mb-4" size={48} />
                <h3 className="text-lg font-medium text-slate-900">Tudo em dia!</h3>
                <p className="text-slate-500">Nenhuma visita pendente para sua área.</p>
              </>
            )}
          </div>
        )}
      </div>

      {/* Responsive Modal for Visit Execution */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
          {/* Mobile: Full Screen (h-[100dvh]), Desktop: Modal Card */}
          <div className="bg-white w-full h-[100dvh] sm:h-auto sm:max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden transition-all transform animate-in slide-in-from-bottom duration-200">

            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
              <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setShowModal(false)} 
                    className="sm:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-200 rounded-full"
                  >
                    <ChevronLeft size={24} />
                  </button>
                  <div>
                    <h2 className="text-lg sm:text-xl font-bold text-slate-800 leading-tight">Registrar Visita</h2>
                    <p className="text-xs sm:text-sm text-slate-500 flex items-center mt-0.5">
                        <User size={12} className="mr-1"/> {selectedFamily.address}, {selectedFamily.number}
                    </p>
                  </div>
              </div>

              <div className="flex items-center">
                  {/* Location Status Badge */}
                  <div className={`mr-2 flex items-center px-2 py-1 rounded-full text-[10px] font-bold border 
                      ${location 
                        ? 'bg-green-100 text-green-700 border-green-200' 
                        : isLocating 
                            ? 'bg-blue-50 text-blue-600 border-blue-100'
                            : 'bg-slate-100 text-slate-500 border-slate-200'
                      }`}
                      onClick={captureLocation}
                  >
                      <MapPin size={10} className={`mr-1 ${isLocating ? 'animate-pulse' : ''}`} />
                      {location ? 'Localizado' : isLocating ? 'Localizando...' : 'Sem GPS'}
                  </div>

                  <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full">
                      <X size={24} />
                  </button>
              </div>
            </div>

            {/* Content - Scrollable */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-6 bg-slate-50/30">

              {/* Alert Banner for Visit Deadline */}
              {(() => {
                const diffDays = getDaysUntilVisit(selectedFamily.nextVisit);
                if (diffDays <= 7) {
                    return (
                        <div className={`p-4 rounded-lg border-l-4 shadow-sm flex items-start animate-in slide-in-from-top duration-300 ${
                            diffDays < 0 ? 'bg-red-50 border-red-500 text-red-900' : 'bg-orange-50 border-orange-500 text-orange-900'
                        }`}>
                            {diffDays < 0 ? (
                                <AlertCircle className="shrink-0 mr-3 text-red-600" size={24} />
                            ) : (
                                <Clock className="shrink-0 mr-3 text-orange-600" size={24} />
                            )}
                            <div>
                                <h4 className="font-bold text-sm uppercase tracking-wide mb-1">
                                    {diffDays < 0 ? 'Visita Atrasada' : 'Prazo Próximo'}
                                </h4>
                                <p className="text-sm opacity-90 leading-relaxed">
                                    {diffDays < 0 
                                        ? `O prazo para esta visita expirou há ${Math.abs(diffDays)} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                        : diffDays === 0 
                                            ? 'O prazo para realizar esta visita é HOJE.'
                                            : `Esta visita vence em ${diffDays} dias (${new Date(selectedFamily.nextVisit).toLocaleDateString()}).`
                                    }
                                </p>
                            </div>
                        </div>
                    );
                }
                return null;
              })()}

              {/* Family Contact Editable Section */}
              <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                 <div className="flex justify-between items-center mb-3">
                     <h3 className="font-bold text-slate-700 text-sm flex items-center">
                         <Phone size={14} className="mr-2 text-blue-500" />
                         Contatos do Responsável
                     </h3>
                     {contactSaved && <span className="text-xs text-green-600 font-bold flex items-center animate-in fade-in"><CheckCircle size={12} className="mr-1"/> Salvo</span>}
                 </div>

                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <div className="relative">
                        <Phone size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="tel" 
                            placeholder="Telefone"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.phone || ''}
                            onChange={(e) => handleFamilyUpdate('phone', e.target.value)}
                        />
                    </div>
                    <div className="relative">
                        <Mail size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="email" 
                            placeholder="Email"
                            className="w-full pl-9 pr-3 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            value={selectedFamily.email || ''}
                            onChange={(e) => handleFamilyUpdate('email', e.target.value)}
                        />
                    </div>
                 </div>
                 <div className="mt-3 flex justify-end">
                    <button 
                        onClick={saveFamilyContact}
                        className="text-xs font-medium text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors flex items-center border border-blue-100 shadow-sm"
                    >
                        <Save size={12} className="mr-1.5" />
                        Salvar Contatos
                    </button>
                 </div>
              </div>

              {/* Detailed Member Summary */}
              <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
                <h3 className="font-bold text-blue-900 mb-4 flex items-center">
                    <Activity size={18} className="mr-2"/> 
                    Prontuário da Família
                </h3>

                {/* Patient Search Input inside Modal */}
                <div className="relative mb-3">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                  <input 
                    type="text"
                    placeholder="Buscar paciente pelo nome..."
                    className="w-full pl-9 pr-9 py-2.5 rounded-lg border border-blue-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white shadow-sm"
                    value={patientSearchTerm}
                    onChange={(e) => setPatientSearchTerm(e.target.value)}
                  />
                  {patientSearchTerm && (
                    <button 
                      onClick={() => setPatientSearchTerm('')}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                    >
                      <X size={14} />
                    </button>
                  )}
                </div>

                {/* Filter Chips */}
                <div className="flex flex-wrap gap-2 mb-4 items-center">
                    <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                        <Filter size={14} className="mr-1" />
                        Filtros:
                    </div>
                    <FilterButton 
                        id="pregnant" 
                        label="Gestante"
                        count={conditionCounts.pregnant}
                        icon={Baby} 
                        activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                    />
                    <FilterButton 
                        id="bedridden" 
                        label="Acamado" 
                        count={conditionCounts.bedridden}
                        icon={Bed} 
                        activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                    />
                    <FilterButton 
                        id="diabetic" 
                        label="Diabético" 
                        count={conditionCounts.diabetic}
                        icon={Droplets} 
                        activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                    />
                    <FilterButton 
                        id="hypertensive" 
                        label="Hipertenso" 
                        count={conditionCounts.hypertensive}
                        icon={HeartPulse} 
                        activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                    />
                    <FilterButton 
                        id="psychological" 
                        label="Saúde Mental" 
                        count={conditionCounts.psychological}
                        icon={Brain} 
                        activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                    />

                    {activeFilters.length > 0 && (
                        <button 
                            onClick={() => setActiveFilters([])}
                            className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                        >
                            <RotateCcw size={10} className="mr-1" /> Limpar
                        </button>
                    )}
                </div>

                <div className="space-y-3">
                  {filteredPatients.length > 0 ? (
                    filteredPatients.map(member => (
                      <div key={member.id} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm animate-in fade-in duration-200">
                        <div className="flex justify-between items-start mb-2">
                          <div className="flex items-center">
                              <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 shrink-0">
                                  <User size={16} />
                              </div>
                              <div>
                                  <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                  <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos</span>
                              </div>
                          </div>
                          <div className="text-right">
                              <span className="text-[10px] uppercase font-bold text-slate-400 tracking-wider bg-slate-100 px-1.5 py-0.5 rounded">SUS: {member.susNumber}</span>
                          </div>
                        </div>

                        <div className="pl-11">
                            <PatientBadge patient={member} />
                            {(member.medications.length > 0) && (
                              <div className="mt-3 text-xs bg-slate-50 p-2 rounded border border-slate-100 text-slate-600">
                                  <span className="font-semibold text-slate-700">Medicamentos:</span> {member.medications.join(', ')}
                              </div>
                            )}
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-6 text-slate-500 bg-white/50 rounded-lg border border-blue-100 border-dashed">
                      <p>Nenhum paciente encontrado com os filtros selecionados.</p>
                      {activeFilters.length > 0 && (
                          <button 
                            onClick={() => setActiveFilters([])}
                            className="text-xs text-blue-600 font-medium mt-2 hover:underline"
                          >
                              Limpar Filtros
                          </button>
                      )}
                    </div>
                  )}
                </div>
              </div>

              {/* Visit Form */}
              <div className="bg-white p-1 rounded-lg space-y-4">

                {/* 1. Quick Procedures Checklist */}
                <div className="animate-in slide-in-from-right duration-300">
                     <label className="block text-sm font-bold text-slate-700 mb-3 px-1 flex items-center">
                        <CheckSquare size={16} className="mr-1.5 text-blue-600" />
                        Procedimentos Realizados (Toque para marcar)
                    </label>
                    <div className="grid grid-cols-2 gap-2">
                        {PROCEDURES_LIST.map(proc => {
                            const isSelected = selectedProcedures.includes(proc.id);
                            const Icon = proc.icon;
                            return (
                                <button
                                    key={proc.id}
                                    type="button"
                                    onClick={() => handleToggleProcedure(proc.id)}
                                    className={`
                                        flex items-center p-3 rounded-lg border text-sm font-medium transition-all active:scale-95
                                        ${isSelected 
                                            ? 'bg-blue-600 text-white border-blue-600 shadow-md ring-1 ring-blue-300' 
                                            : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'
                                        }
                                    `}
                                >
                                    <Icon size={18} className={`mr-2 ${isSelected ? 'text-white' : 'text-slate-400'}`} />
                                    {proc.label}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* 2. Notes */}
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2 px-1 flex items-center mt-4">
                        <Activity size={16} className="mr-1.5 text-blue-600" />
                        Relatório Técnico (Valores e Detalhes)
                    </label>
                    <textarea 
                      required
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={3}
                      placeholder="Descreva valores de PA, Glicemia, orientações e detalhes técnicos..."
                      value={visitNotes}
                      onChange={(e) => setVisitNotes(e.target.value)}
                    ></textarea>
                </div>

                {/* 3. General Observations */}
                <div>
                    <div className="flex items-center justify-between mb-2">
                        <label className="block text-sm font-bold text-slate-700 px-1 flex items-center">
                            <Clipboard size={16} className="mr-1.5 text-orange-500" />
                            Observações Gerais do Ambiente
                        </label>
                        <button 
                            type="button" 
                            className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded-full transition-colors"
                            title="Anexar arquivo"
                        >
                            <Paperclip size={18} />
                        </button>
                    </div>
                    <textarea 
                      className="w-full rounded-lg border-slate-300 border p-4 focus:ring-2 focus:ring-blue-500 focus:outline-none text-base leading-relaxed"
                      rows={2}
                      placeholder="Contexto social, observações do ambiente ou outras informações..."
                      value={visitObservations}
                      onChange={(e) => setVisitObservations(e.target.value)}
                    ></textarea>
                </div>
              </div>
            </div>

            {/* Footer - Sticky at bottom */}
            <div className="p-4 border-t border-slate-100 bg-white shrink-0 safe-area-bottom">
                <div className="flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={handleCompleteVisit}
                    disabled={!visitNotes.trim() && selectedProcedures.length === 0}
                    className={`flex-1 px-6 py-3 sm:py-2 rounded-lg transition-colors font-bold shadow-sm text-center
                        ${(!visitNotes.trim() && selectedProcedures.length === 0)
                            ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'}`}
                  >
                    Confirmar Visita
                  </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { Visits } from './pages/Visits';
import { Families } from './pages/Families';
import { Admin } from './pages/Admin';
import { Login } from './pages/Login';
import { Reports } from './pages/Reports';
import { UserRole, UserStatus } from './types';
import { Clock, Ban, CreditCard } from 'lucide-react';

const ProtectedRoute = ({ children, requiredRole }: React.PropsWithChildren<{ requiredRole?: UserRole }>) => {
  const { user, refreshUser } = useAuth();

  // Refresh user data on navigation to ensure status is up to date
  React.useEffect(() => {
    refreshUser();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // 1. Check if user is PENDING approval
  if (user.status === UserStatus.PENDING) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Clock size={64} className="text-yellow-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Aguardando Aprovação</h1>
        <p className="text-slate-500 max-w-md">
          Seu cadastro foi realizado com sucesso. Aguarde a aprovação e ativação do plano pelo administrador.
        </p>
        <button onClick={() => window.location.reload()} className="mt-6 text-blue-600 hover:underline">Verificar novamente</button>
      </div>
    );
  }

  // 2. Check if user is BLOCKED manually
  if (user.status === UserStatus.BLOCKED) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
        <Ban size={64} className="text-red-500 mb-4" />
        <h1 className="text-2xl font-bold text-slate-800 mb-2">Acesso Bloqueado</h1>
        <p className="text-slate-500">Entre em contato com o administrador para regularizar seu acesso.</p>
      </div>
    );
  }

  // 3. Check Subscription Expiration (Only for Agents, Admins bypass)
  if (user.role !== UserRole.ADMIN && user.subscriptionExpiresAt) {
    const expirationDate = new Date(user.subscriptionExpiresAt);
    const today = new Date();

    if (today > expirationDate) {
      return (
        <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 text-center">
          <div className="bg-red-100 p-6 rounded-full mb-6">
            <CreditCard size={48} className="text-red-600" />
          </div>
          <h1 className="text-2xl font-bold text-slate-800 mb-2">Assinatura Expirada</h1>
          <p className="text-slate-500 max-w-md mb-6">
            O período de validade do seu acesso encerrou em <b>{expirationDate.toLocaleDateString()}</b>.
          </p>
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 w-full max-w-sm">
            <p className="text-sm text-slate-600 mb-4">Para continuar utilizando o sistema e acessar seus dados, renove sua mensalidade ou anuidade.</p>
            <button className="w-full bg-blue-600 text-white font-bold py-3 rounded-lg hover:bg-blue-700 transition-colors">
              Falar com o Administrador
            </button>
          </div>
          <button onClick={refreshUser} className="mt-8 text-slate-400 text-sm hover:text-slate-600">
            Já paguei? Clique para atualizar
          </button>
        </div>
      );
    }
  }

  if (requiredRole && user.role !== requiredRole) {
    return <Navigate to="/" replace />;
  }

  return <Layout>{children}</Layout>;
};

const AppRoutes = () => {
  const { user } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={user ? <Navigate to="/" replace /> : <Login />} />

      <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
      <Route path="/reports" element={<ProtectedRoute><Reports /></ProtectedRoute>} />
      <Route path="/visits" element={<ProtectedRoute><Visits /></ProtectedRoute>} />
      <Route path="/families" element={<ProtectedRoute><Families /></ProtectedRoute>} />

      <Route path="/admin" element={
        <ProtectedRoute requiredRole={UserRole.ADMIN}>
          <Admin />
        </ProtectedRoute>
      } />
    </Routes>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <AppRoutes />
      </HashRouter>
    </AuthProvider>
  );
}

import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storage';
import { useAuth } from '../context/AuthContext';
import { UserRole, Family, Patient } from '../types';
import { 
  Baby, HeartPulse, Droplets, Bed, Brain, Accessibility, Syringe, 
  MapPin, User, ArrowRight, Filter, X, Phone, Mail, Calendar, 
  FilePlus, UserPlus, ClipboardList, RotateCcw, Search, 
  Briefcase, Activity, School, Smartphone, Armchair, ChevronRight
} from 'lucide-react';

// 1. Health Condition Filters
const CONDITION_FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-600 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-600 border-purple-200' },
  { id: 'diabetic', label: 'Diabéticos', icon: Droplets, color: 'bg-blue-100 text-blue-600 border-blue-200' },
  { id: 'hypertensive', label: 'Hipertensos', icon: HeartPulse, color: 'bg-red-100 text-red-600 border-red-200' },
  { id: 'mental', label: 'Saúde Mental', icon: Brain, color: 'bg-yellow-100 text-yellow-600 border-yellow-200' },
  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-600 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-600 border-sky-200' },
];

// 2. Age Group Filters - Updated Icons for better visual context
const AGE_FILTERS = [
  { id: 'age_0_5', label: '0 a 5 anos', min: 0, max: 5, icon: Baby, color: 'bg-indigo-100 text-indigo-600 border-indigo-200' },
  { id: 'age_6_12', label: '6 a 12 anos', min: 6, max: 12, icon: School, color: 'bg-cyan-100 text-cyan-600 border-cyan-200' },
  { id: 'age_13_17', label: '13 a 17 anos', min: 13, max: 17, icon: Smartphone, color: 'bg-teal-100 text-teal-600 border-teal-200' },
  { id: 'age_18_59', label: '18 a 59 anos', min: 18, max: 59, icon: Briefcase, color: 'bg-slate-100 text-slate-600 border-slate-200' },
  { id: 'age_60_plus', label: 'Idosos (60+)', min: 60, max: 200, icon: Armchair, color: 'bg-emerald-100 text-emerald-600 border-emerald-200' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter (Conditions + Ages)
    const newCounts: Record<string, number> = {};

    CONDITION_FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    AGE_FILTERS.forEach(filter => {
       newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    // Check Age Filters First
    const ageFilter = AGE_FILTERS.find(f => f.id === filterId);
    if (ageFilter) {
        return age >= ageFilter.min && age <= ageFilter.max;
    }

    // Check Condition Filters
    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();

  // Helper to find label of current active filter
  const getCurrentFilterLabel = () => {
    const condition = CONDITION_FILTERS.find(f => f.id === activeFilter);
    if (condition) return condition.label;
    const age = AGE_FILTERS.find(f => f.id === activeFilter);
    if (age) return age.label;
    return '';
  };

  const FilterCard = ({ filter, count, isActive, onClick }: any) => {
    const Icon = filter.icon;
    return (
      <button
        onClick={onClick}
        className={`
          relative flex items-center p-4 rounded-2xl border transition-all duration-200 w-full group
          ${isActive 
              ? `border-blue-500 bg-blue-50/50 shadow-md ring-1 ring-blue-500` 
              : `border-slate-200 bg-white shadow-sm hover:border-blue-300 hover:shadow-md hover:translate-y-[-2px]`
          }
        `}
      >
        <div className={`p-3 rounded-xl ${filter.color} transition-transform group-hover:scale-110 shrink-0`}>
          <Icon size={24} />
        </div>
        <div className="ml-4 text-left">
          <span className="block text-2xl font-bold text-slate-800 leading-none mb-1">{count}</span>
          <span className={`text-xs font-semibold uppercase tracking-wide ${isActive ? 'text-blue-700' : 'text-slate-500'}`}>
            {filter.label}
          </span>
        </div>

        {isActive && (
           <div className="absolute top-4 right-4">
               <span className="flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
               </span>
           </div>
        )}
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Analise sua área por condições de saúde e faixas etárias.</p>
      </div>

      {/* Section 1: Health Conditions */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Activity size={16} className="mr-2" /> Condições de Saúde
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {CONDITION_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Section 2: Age Groups */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Calendar size={16} className="mr-2" /> Faixa Etária
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
        {AGE_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl p-12 text-center">
             <div className="bg-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm">
                <Filter size={32} className="text-slate-300" />
             </div>
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500 max-w-sm mx-auto">Selecione um dos cards acima para visualizar a lista detalhada de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between bg-blue-50 p-4 rounded-xl border border-blue-100">
                <h2 className="text-lg font-bold text-blue-900 flex items-center">
                    Resultados: {getCurrentFilterLabel()}
                    <span className="ml-3 bg-white text-blue-700 px-3 py-0.5 rounded-full text-sm shadow-sm border border-blue-200">
                        {results.length} pacientes
