                    </h2>
                </div>
                <button onClick={() => setShowModal(false)} className="hidden sm:block text-slate-400 hover:text-slate-600 p-2 rounded-full hover:bg-slate-100">
                    <X size={24} />
                </button>
            </div>

            {/* Tabs - Large Toggle */}
            {isEditing && (
                <div className="p-4 bg-slate-50 border-b border-slate-100 shrink-0">
                    <div className="flex bg-slate-200/50 p-1 rounded-xl">
                        <button 
                            onClick={() => setActiveTab('details')}
                            className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition-all shadow-sm ${activeTab === 'details' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
