                            Dados
                        </button>
                        <button 
                            onClick={() => setActiveTab('members')}
                            className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'members' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
