                            Integrantes ({familyMembers.length})
                        </button>
                    </div>
                </div>
            )}

            {/* Content Scrollable Area */}
            <div className="p-5 overflow-y-auto flex-1 bg-white">
                {activeTab === 'details' ? (
                    <form onSubmit={handleSaveFamily} className="space-y-6 pb-8">
                        <div>
                            <label className="block text-sm font-bold text-slate-700 mb-2">Logradouro / Rua</label>
                            <input 
                                required
                                className="w-full p-4 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none text-lg"
                                placeholder="Nome da rua..."
