                                onChange={e => setCurrentFamily(prev => ({ ...prev, address: e.target.value }))}
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-2">Número</label>
                                <input 
                                    required
                                    className="w-full p-4 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none text-lg"
                                    value={currentFamily.number || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, number: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-2">Bairro</label>
                                <input 
                                    required
                                    className="w-full p-4 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none text-lg"
                                    value={currentFamily.neighborhood || ''}
                                    onChange={e => setCurrentFamily(prev => ({ ...prev, neighborhood: e.target.value }))}
                                />
                            </div>
                        </div>

                        <div className="space-y-4 pt-2">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-2">Telefone</label>
                                <div className="relative">
                                    <Phone size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        className="w-full pl-12 p-4 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none text-lg"
                                        placeholder="(00) 00000-0000"
                                        type="tel"
                                        value={currentFamily.phone || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, phone: e.target.value }))}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-2">Email (Opcional)</label>
                                <div className="relative">
                                    <Mail size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="email"
                                        className="w-full pl-12 p-4 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:outline-none text-lg"
                                        value={currentFamily.email || ''}
                                        onChange={e => setCurrentFamily(prev => ({ ...prev, email: e.target.value }))}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-6 flex flex-col gap-3">
                             <button 
                                type="submit" 
                                className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-blue-700 shadow-md active:scale-[0.98] flex items-center justify-center"
                             >
                                <Save size={20} className="mr-2" />
                                {isEditing ? 'Salvar Alterações' : 'Cadastrar Família'}
                             </button>

                             {isEditing && (
                                <button 
                                    type="button" 
                                    onClick={handleDeleteFamily}
                                    className="w-full bg-red-50 text-red-600 py-3 rounded-xl font-medium flex items-center justify-center hover:bg-red-100 transition-colors"
                                >
                                    <Trash2 size={20} className="mr-2" /> Excluir Família
