                    </form>
                ) : (
                    // Members Tab
                    <div className="space-y-6 pb-20">
                        {!showMemberForm ? (
                            <>
                                {/* Visit Scheduling Section - Mobile Optimized */}
                                <div className="bg-blue-50 p-5 rounded-2xl border border-blue-200 shadow-sm">
                                    <div className="flex items-center justify-between mb-4">
                                        <div className="flex items-center">
                                            <div className="bg-blue-100 p-2.5 rounded-xl mr-3">
                                                <Calendar size={24} className="text-blue-600" />
                                            </div>
                                            <div>
                                                <h4 className="font-bold text-blue-900 text-base">Próxima Visita</h4>
                                                <p className="text-xs text-blue-600 opacity-80">Agendar data</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center text-xs font-bold text-blue-600 bg-white px-3 py-1.5 rounded-full border border-blue-100 shadow-sm">
                                            <Bell size={12} className="mr-1.5 fill-blue-600" />
