export enum UserRole {
  ADMIN = 'ADMIN',
  AGENT = 'AGENT',
}

export enum UserStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  BLOCKED = 'BLOCKED',
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  area?: string;
  phone?: string;
  password?: string; // In a real app, this would be hashed
  subscriptionExpiresAt?: string; // ISO Date string for access expiration
}

export interface Patient {
  id: string;
  familyId: string;
  name: string;
  birthDate: string;
  susNumber: string;
  // Conditions
  isPregnant: boolean;
  isPostpartum: boolean; // Puérperas
  isBedridden: boolean; // Acamados
  hasMobilityIssues: boolean; // Dificuldade de locomoção
  isDiabetic: boolean;
  usesInsulin: boolean; // Insulinos
  isHypertensive: boolean;
  hasPsychologicalIssues: boolean;
  hasOtherComorbidities: boolean; // Outras comorbidades
  medications: string[];
  addictions: string[];
}

export interface Family {
  id: string;
  agentId: string;
  address: string;
  number: string;
  neighborhood: string;
  membersCount: number;
  lastVisit: string | null; // ISO Date
  nextVisit: string; // ISO Date calculated
  riskLevel: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
  phone?: string;
  email?: string;
}

export interface Visit {
  id: string;
  familyId: string;
  agentId: string;
  date: string;
  notes: string;
  generalObservations?: string;
  outcome: string;
  measurements: {
    bloodPressure?: string;
    glucose?: string;
    weight?: string;
  }[];
  procedures?: string[];
  location?: {
    latitude: number;
    longitude: number;
    accuracy?: number;
  };
  syncStatus?: 'synced' | 'pending'; // New field for offline support
}

export interface DashboardStats {
  totalFamilies: number;
  totalPatients: number;
  pendingVisits: number;
  highRiskFamilies: number;
}

