            {/* Footer - Sticky at bottom */}
            <div className="p-4 border-t border-slate-100 bg-white shrink-0 safe-area-bottom">
                <div className="flex gap-3">
                  <button 
                    type="button" 
                    onClick={() => setShowModal(false)}
                    className="flex-1 sm:flex-none px-4 py-3 sm:py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors font-medium border border-slate-200 sm:border-transparent text-center"
