} from 'lucide-react';

// 1. Health Condition Filters
const CONDITION_FILTERS = [
  { id: 'pregnant', label: 'Gestantes', icon: Baby, color: 'bg-pink-100 text-pink-600 border-pink-200' },
  { id: 'bedridden', label: 'Acamados', icon: Bed, color: 'bg-purple-100 text-purple-600 border-purple-200' },
