  { id: 'mobility', label: 'Dif. Locomoção', icon: Accessibility, color: 'bg-orange-100 text-orange-600 border-orange-200' },
  { id: 'insulin', label: 'Uso de Insulina', icon: Syringe, color: 'bg-sky-100 text-sky-600 border-sky-200' },
];

// 2. Age Group Filters - Updated Icons for better visual context
const AGE_FILTERS = [
  { id: 'age_0_5', label: '0 a 5 anos', min: 0, max: 5, icon: Baby, color: 'bg-indigo-100 text-indigo-600 border-indigo-200' },
  { id: 'age_6_12', label: '6 a 12 anos', min: 6, max: 12, icon: School, color: 'bg-cyan-100 text-cyan-600 border-cyan-200' },
  { id: 'age_13_17', label: '13 a 17 anos', min: 13, max: 17, icon: Smartphone, color: 'bg-teal-100 text-teal-600 border-teal-200' },
  { id: 'age_18_59', label: '18 a 59 anos', min: 18, max: 59, icon: Briefcase, color: 'bg-slate-100 text-slate-600 border-slate-200' },
  { id: 'age_60_plus', label: 'Idosos (60+)', min: 60, max: 200, icon: Armchair, color: 'bg-emerald-100 text-emerald-600 border-emerald-200' },
];

export const Reports: React.FC = () => {
  const { user } = useAuth();

  // Data States
  const [families, setFamilies] = useState<Family[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);

  // Filter Logic
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Counts for the cards
  const [counts, setCounts] = useState<Record<string, number>>({});

  // Modal State
  const [selectedFamily, setSelectedFamily] = useState<Family | null>(null);
  const [familyMembers, setFamilyMembers] = useState<Patient[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Filters within Modal
  const [memberSearchTerm, setMemberSearchTerm] = useState('');
  const [activeMemberFilters, setActiveMemberFilters] = useState<string[]>([]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadData = () => {
    if (!user) return;

    // 1. Get Families for this agent
    const agentFilter = user.role === UserRole.ADMIN ? undefined : user.id;
    const fetchedFamilies = storageService.getFamilies(agentFilter);
    setFamilies(fetchedFamilies);

    // 2. Get Patients belonging to these families
    const familyIds = fetchedFamilies.map(f => f.id);
    const allPatients = storageService.getPatients();
    const myPatients = allPatients.filter(p => familyIds.includes(p.familyId));
    setPatients(myPatients);

    // 3. Calculate Counts for each filter (Conditions + Ages)
    const newCounts: Record<string, number> = {};

    CONDITION_FILTERS.forEach(filter => {
      newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    AGE_FILTERS.forEach(filter => {
       newCounts[filter.id] = myPatients.filter(p => checkPatientCondition(p, filter.id)).length;
    });

    setCounts(newCounts);
  };

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
      age--;
    }
    return age;
  };

  // The logic to check if a patient matches a specific filter ID
  const checkPatientCondition = (p: Patient, filterId: string): boolean => {
    const age = calculateAge(p.birthDate);

    // Check Age Filters First
    const ageFilter = AGE_FILTERS.find(f => f.id === filterId);
    if (ageFilter) {
        return age >= ageFilter.min && age <= ageFilter.max;
    }

    // Check Condition Filters
    switch (filterId) {
      case 'pregnant': return p.isPregnant;
      case 'bedridden': return p.isBedridden;
      case 'diabetic': return p.isDiabetic;
      case 'hypertensive': return p.isHypertensive;
      case 'mental': return p.hasPsychologicalIssues;
      case 'mobility': return p.hasMobilityIssues;
      case 'insulin': return p.usesInsulin;
      default: return false;
    }
  };

  // Get the list of results based on active filter
  const getFilteredResults = () => {
    if (!activeFilter) return [];

    // Find patients matching the filter
    const matchingPatients = patients.filter(p => checkPatientCondition(p, activeFilter));

    // Map them to include Family Address info
    return matchingPatients.map(p => {
      const family = families.find(f => f.id === p.familyId);
      return {
        patient: p,
        family: family
      };
    });
  };

  const handleOpenFamily = (family: Family | undefined) => {
    if (!family) return;
    const members = storageService.getPatients(family.id);
    setFamilyMembers(members);
    setSelectedFamily(family);
    // Reset filters
    setMemberSearchTerm('');
    setActiveMemberFilters([]);
    setShowModal(true);
  };

  // Filter Logic inside Modal
  const toggleMemberFilter = (filter: string) => {
    setActiveMemberFilters(prev => 
      prev.includes(filter) 
        ? prev.filter(f => f !== filter) 
        : [...prev, filter]
    );
  };

  const filteredMembers = familyMembers.filter(member => {
    const matchesName = member.name.toLowerCase().includes(memberSearchTerm.toLowerCase());

    if (activeMemberFilters.length === 0) return matchesName;

    const matchesFilter = activeMemberFilters.some(filter => {
      switch(filter) {
        case 'pregnant': return member.isPregnant;
        case 'bedridden': return member.isBedridden;
        case 'diabetic': return member.isDiabetic;
        case 'hypertensive': return member.isHypertensive;
        case 'psychological': return member.hasPsychologicalIssues;
        default: return false;
      }
    });

    return matchesName && matchesFilter;
  });

  // Export to CSV Function
  const handleExportCSV = () => {
    if (results.length === 0) return;

    // Define Headers
    const headers = [
      'Nome do Paciente',
      'Data de Nascimento',
      'Idade',
      'Cartão SUS',
      'Condições',
      'Endereço',
      'Número',
      'Bairro',
      'Responsável (Telefone)',
      'Medicamentos'
    ];

    // Create CSV rows
    const csvRows = results.map(({ patient, family }) => {
      // Aggregate conditions string
      const conditions = [];
      if (patient.isPregnant) conditions.push('Gestante');
      if (patient.isPostpartum) conditions.push('Puérpera');
      if (patient.isBedridden) conditions.push('Acamado');
      if (patient.hasMobilityIssues) conditions.push('Dif. Locomoção');
      if (patient.isDiabetic) conditions.push('Diabético');
      if (patient.usesInsulin) conditions.push('Uso de Insulina');
      if (patient.isHypertensive) conditions.push('Hipertenso');
      if (patient.hasPsychologicalIssues) conditions.push('Saúde Mental');

      const conditionsStr = conditions.length > 0 ? conditions.join(', ') : 'Nenhuma';
      const address = family ? family.address : 'Sem endereço';
      const number = family ? family.number : '';
      const neighborhood = family ? family.neighborhood : '';
      const phone = family?.phone || 'N/A';
      const meds = patient.medications?.join(', ') || 'Nenhum';

      // Use quotes to handle commas in data
      return [
        `"${patient.name}"`,
        `"${new Date(patient.birthDate).toLocaleDateString()}"`,
        calculateAge(patient.birthDate),
        `"${patient.susNumber}"`,
        `"${conditionsStr}"`,
        `"${address}"`,
        `"${number}"`,
        `"${neighborhood}"`,
        `"${phone}"`,
        `"${meds}"`
      ].join(';'); // Using semicolon as standard separator for many regions (BR)
    });

    // Combine headers and rows with BOM for UTF-8 support in Excel
    const csvString = '\uFEFF' + [headers.join(';'), ...csvRows].join('\n');
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');

    const filterName = getCurrentFilterLabel().replace(/\s+/g, '_').toLowerCase();
    const fileName = `relatorio_${filterName}_${new Date().toISOString().split('T')[0]}.csv`;

    link.href = url;
    link.setAttribute('download', fileName);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Calculate counts for badges inside modal
  const conditionCounts = {
    pregnant: familyMembers.filter(m => m.isPregnant).length,
    bedridden: familyMembers.filter(m => m.isBedridden).length,
    diabetic: familyMembers.filter(m => m.isDiabetic).length,
    hypertensive: familyMembers.filter(m => m.isHypertensive).length,
    psychological: familyMembers.filter(m => m.hasPsychologicalIssues).length,
  };

  const FilterButton = ({ id, label, count, icon: Icon, activeColorClass }: any) => {
    const isActive = activeMemberFilters.includes(id);
    const isDisabled = count === 0;
    return (
      <button
        onClick={() => !isDisabled && toggleMemberFilter(id)}
        disabled={isDisabled}
        className={`flex items-center px-3 py-1.5 rounded-full text-xs font-medium border transition-all whitespace-nowrap
          ${isDisabled 
            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-default' 
            : isActive 
                ? activeColorClass 
                : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50 hover:border-slate-300 shadow-sm'
          }`}
      >
        <Icon size={12} className="mr-1.5" />
        {label} <span className="ml-1 opacity-70">({count})</span>
      </button>
    );
  };


  const PatientBadge = ({ patient }: { patient: Patient }) => {
    const hasConditions = 
      patient.isPregnant || 
      patient.isPostpartum || 
      patient.isBedridden || 
      patient.hasMobilityIssues || 
      patient.isDiabetic || 
      patient.usesInsulin || 
      patient.isHypertensive || 
      patient.hasPsychologicalIssues || 
      patient.hasOtherComorbidities;

    if (!hasConditions) return null;

    return (
      <div className="flex flex-wrap gap-1 mt-1">
        {patient.isPregnant && (
            <span className="px-1.5 py-0.5 bg-pink-100 text-pink-700 text-[10px] font-bold rounded border border-pink-200 flex items-center">
                <Baby size={10} className="mr-1"/>Gestante
            </span>
        )}
        {patient.isPostpartum && (
            <span className="px-1.5 py-0.5 bg-rose-100 text-rose-700 text-[10px] font-bold rounded border border-rose-200 flex items-center">
                <UserPlus size={10} className="mr-1"/>Puérpera
            </span>
        )}
        {patient.isBedridden && (
            <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-bold rounded border border-purple-200 flex items-center">
                <Bed size={10} className="mr-1"/>Acamado
            </span>
        )}
        {patient.hasMobilityIssues && (
            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-[10px] font-bold rounded border border-orange-200 flex items-center">
                <Accessibility size={10} className="mr-1"/>Locomoção
            </span>
        )}
        {patient.isDiabetic && (
            <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded border border-blue-200 flex items-center">
                <Droplets size={10} className="mr-1"/>Diabético
            </span>
        )}
        {patient.usesInsulin && (
            <span className="px-1.5 py-0.5 bg-sky-100 text-sky-700 text-[10px] font-bold rounded border border-sky-200 flex items-center">
                <Syringe size={10} className="mr-1"/>Insulina
            </span>
        )}
        {patient.isHypertensive && (
            <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold rounded border border-red-200 flex items-center">
                <HeartPulse size={10} className="mr-1"/>Hipertenso
            </span>
        )}
        {patient.hasPsychologicalIssues && (
            <span className="px-1.5 py-0.5 bg-yellow-100 text-yellow-700 text-[10px] font-bold rounded border border-yellow-200 flex items-center">
                <Brain size={10} className="mr-1"/>Mental
            </span>
        )}
        {patient.hasOtherComorbidities && (
            <span className="px-1.5 py-0.5 bg-slate-100 text-slate-700 text-[10px] font-bold rounded border border-slate-200 flex items-center">
                <FilePlus size={10} className="mr-1"/>Outros
            </span>
        )}
      </div>
    );
  };

  const results = getFilteredResults();

  // Helper to find label of current active filter
  const getCurrentFilterLabel = () => {
    const condition = CONDITION_FILTERS.find(f => f.id === activeFilter);
    if (condition) return condition.label;
    const age = AGE_FILTERS.find(f => f.id === activeFilter);
    if (age) return age.label;
    return '';
  };

  const FilterCard = ({ filter, count, isActive, onClick }: any) => {
    const Icon = filter.icon;
    return (
      <button
        onClick={onClick}
        className={`
          relative flex items-center p-4 rounded-2xl border transition-all duration-200 w-full group
          ${isActive 
              ? `border-blue-500 bg-blue-50/50 shadow-md ring-1 ring-blue-500` 
              : `border-slate-200 bg-white shadow-sm hover:border-blue-300 hover:shadow-md hover:translate-y-[-2px]`
          }
        `}
      >
        <div className={`p-3 rounded-xl ${filter.color} transition-transform group-hover:scale-110 shrink-0`}>
          <Icon size={24} />
        </div>
        <div className="ml-4 text-left">
          <span className="block text-2xl font-bold text-slate-800 leading-none mb-1">{count}</span>
          <span className={`text-xs font-semibold uppercase tracking-wide ${isActive ? 'text-blue-700' : 'text-slate-500'}`}>
            {filter.label}
          </span>
        </div>

        {isActive && (
           <div className="absolute top-4 right-4">
               <span className="flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
               </span>
           </div>
        )}
      </button>
    );
  };

  return (
    <div className="pb-20 md:pb-0">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-slate-800">Relatórios e Grupos</h1>
        <p className="text-slate-500">Analise sua área por condições de saúde e faixas etárias.</p>
      </div>

      {/* Section 1: Health Conditions */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Activity size={16} className="mr-2" /> Condições de Saúde
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {CONDITION_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Section 2: Age Groups */}
      <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b border-slate-100 pb-2 flex items-center">
         <Calendar size={16} className="mr-2" /> Faixa Etária
      </h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
        {AGE_FILTERS.map((filter) => (
          <FilterCard 
            key={filter.id}
            filter={filter}
            count={counts[filter.id] || 0}
            isActive={activeFilter === filter.id}
            onClick={() => setActiveFilter(activeFilter === filter.id ? null : filter.id)}
          />
        ))}
      </div>

      {/* Results Section */}
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
        {!activeFilter ? (
          <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl p-12 text-center">
             <div className="bg-white w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 shadow-sm">
                <Filter size={32} className="text-slate-300" />
             </div>
             <h3 className="text-lg font-bold text-slate-700">Nenhum filtro selecionado</h3>
             <p className="text-slate-500 max-w-sm mx-auto">Selecione um dos cards acima para visualizar a lista detalhada de pacientes.</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex flex-wrap gap-3 items-center justify-between bg-blue-50 p-4 rounded-xl border border-blue-100">
                <h2 className="text-lg font-bold text-blue-900 flex items-center">
                    Resultados: {getCurrentFilterLabel()}
                    <span className="ml-3 bg-white text-blue-700 px-3 py-0.5 rounded-full text-sm shadow-sm border border-blue-200">
                        {results.length} pacientes
                    </span>
                </h2>
                <div className="flex gap-2">
                    <button 
                        onClick={handleExportCSV}
                        disabled={results.length === 0}
                        className="text-sm font-bold bg-white text-blue-600 border border-blue-200 hover:bg-blue-100 px-4 py-2 rounded-lg transition-all flex items-center shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Download size={16} className="mr-2" /> Exportar CSV
                    </button>
                    <button 
                        onClick={() => setActiveFilter(null)}
                        className="text-sm text-slate-500 hover:text-red-500 hover:bg-white px-3 py-2 rounded-lg transition-all flex items-center"
                    >
                        <X size={16} className="mr-1" /> Limpar
                    </button>
                </div>
            </div>

            {results.length === 0 ? (
                <div className="bg-white p-12 rounded-xl text-center border border-slate-200">
                    <p className="text-slate-500">Nenhum paciente encontrado com esta condição na sua área.</p>
                </div>
            ) : (
                <>
                    {/* Mobile View (Cards) */}
                    <div className="md:hidden grid gap-4">
                        {results.map(({ patient, family }) => (
                            <div 
                                key={patient.id} 
                                onClick={() => handleOpenFamily(family)}
                                className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer active:scale-[0.99] flex flex-col gap-4 group"
                            >
                                <div className="flex items-start gap-4">
                                    <div className="w-12 h-12 rounded-full bg-slate-100 group-hover:bg-blue-50 flex items-center justify-center text-slate-500 group-hover:text-blue-600 transition-colors shrink-0">
                                        <User size={24} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
                                        <div className="flex flex-wrap gap-x-4 gap-y-1 text-sm text-slate-500 mt-1">
                                            <span className="flex items-center">
                                                <Baby size={14} className="mr-1" /> {calculateAge(patient.birthDate)} anos
                                            </span>
                                            <span className="flex items-center">
                                                <Activity size={14} className="mr-1" /> SUS: {patient.susNumber}
                                            </span>
                                        </div>

                                        {/* Address Display Mobile */}
                                        <div className="mt-3 flex items-start text-sm bg-slate-50 text-slate-600 p-2 rounded-lg group-hover:bg-blue-50 group-hover:text-blue-800 transition-colors">
                                            <MapPin size={16} className="mr-2 mt-0.5 shrink-0" />
                                            <div>
                                                {family ? (
                                                    <span>{family.address}, {family.number} - {family.neighborhood}</span>
                                                ) : (
                                                    <span className="text-red-500 italic">Endereço não vinculado</span>
                                                )}
                                            </div>
                                        </div>

                                        <PatientBadge patient={patient} />
                                    </div>
                                </div>

                                <div className="text-center pt-2 border-t border-slate-100">
                                    <span className="text-blue-600 text-sm font-bold flex items-center justify-center">
                                        Ver Família <ChevronRight size={16} className="ml-1" />
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* Desktop View (Table) */}
                    <div className="hidden md:block bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-slate-50 text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-200">
                                <tr>
                                    <th className="px-6 py-4">Paciente</th>
                                    <th className="px-6 py-4">Idade / SUS</th>
                                    <th className="px-6 py-4">Condições</th>
                                    <th className="px-6 py-4">Família (Endereço)</th>
                                    <th className="px-6 py-4 text-right">Ações</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {results.map(({ patient, family }) => (
                                    <tr 
                                        key={patient.id} 
                                        onClick={() => handleOpenFamily(family)}
                                        className="hover:bg-blue-50/30 transition-colors cursor-pointer group"
                                    >
                                        <td className="px-6 py-4">
                                            <div className="flex items-center">
                                                <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 shrink-0">
                                                    <User size={16} />
                                                </div>
                                                <span className="font-bold text-slate-800">{patient.name}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-slate-600">
                                            <div className="font-medium">{calculateAge(patient.birthDate)} anos</div>
                                            <div className="text-xs text-slate-400 mt-0.5 font-mono">SUS: {patient.susNumber}</div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <PatientBadge patient={patient} />
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="group-hover:bg-white rounded-lg p-2 transition-all -ml-2 border border-transparent group-hover:border-slate-200 group-hover:shadow-sm">
                                                <div className="flex items-center text-sm text-slate-700 font-medium group-hover:text-blue-700 transition-colors">
                                                    <MapPin size={16} className="mr-2 text-slate-400 group-hover:text-blue-500 shrink-0" />
                                                    {family ? (
                                                        <span>{family.address}, {family.number}</span>
                                                    ) : (
                                                        <span className="text-red-400 italic">Sem endereço</span>
                                                    )}
                                                </div>
                                                {family && <div className="text-xs text-slate-500 pl-6 mt-0.5">{family.neighborhood}</div>}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <button className="text-slate-400 hover:text-blue-600 hover:bg-blue-100 p-2 rounded-full transition-colors">
                                                <ArrowRight size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </>
            )}
          </div>
        )}
      </div>

      {/* Family Details Modal */}
      {showModal && selectedFamily && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center sm:p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white w-full h-auto max-h-[90vh] sm:rounded-xl sm:max-w-2xl flex flex-col shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-200">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-lg font-bold text-slate-800 flex items-center">
                            <MapPin size={18} className="mr-2 text-blue-600"/>
                            {selectedFamily.address}, {selectedFamily.number}
                        </h2>
                        <p className="text-sm text-slate-500">{selectedFamily.neighborhood}</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-200 rounded-full">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    {/* Family Quick Info */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100">
                             <h4 className="text-xs font-bold text-blue-600 uppercase mb-2">Próxima Visita</h4>
                             <div className="flex items-center text-blue-900 font-medium">
                                <Calendar size={18} className="mr-2"/>
                                {new Date(selectedFamily.nextVisit).toLocaleDateString()}
                             </div>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-lg border border-slate-200">
                             <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">Contatos</h4>
                             <div className="space-y-1">
                                {selectedFamily.phone && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Phone size={14} className="mr-2 text-slate-400"/> {selectedFamily.phone}
                                    </div>
                                )}
                                {selectedFamily.email && (
                                    <div className="flex items-center text-slate-700 text-sm">
                                        <Mail size={14} className="mr-2 text-slate-400"/> {selectedFamily.email}
                                    </div>
                                )}
                                {!selectedFamily.phone && !selectedFamily.email && (
                                    <span className="text-xs text-slate-400 italic">Sem contato registrado</span>
                                )}
                             </div>
                        </div>
                    </div>

                    <h3 className="font-bold text-slate-800 mb-4 flex items-center border-b border-slate-100 pb-2">
                        <ClipboardList size={18} className="mr-2 text-slate-500"/>
                        Integrantes da Família
                    </h3>

                    {/* Member Search and Filter */}
                    <div className="mb-4">
                        <div className="relative mb-3">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={16} />
                            <input 
                                type="text"
                                placeholder="Buscar integrante por nome..."
                                className="w-full pl-9 pr-9 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm bg-white"
                                value={memberSearchTerm}
                                onChange={(e) => setMemberSearchTerm(e.target.value)}
                            />
                            {memberSearchTerm && (
                                <button 
                                    onClick={() => setMemberSearchTerm('')}
                                    className="absolute right-3 top-1/2 transform -translate-y-1/2 text-slate-400 hover:text-slate-600 p-1"
                                >
                                    <X size={14} />
                                </button>
                            )}
                        </div>

                        {/* Filter Chips */}
                        <div className="flex flex-wrap gap-2 items-center">
                            <div className="flex items-center text-xs text-blue-600 mr-1 font-medium">
                                <Filter size={14} className="mr-1" />
                                Filtros:
                            </div>
                            <FilterButton 
                                id="pregnant" 
                                label="Gestante"
                                count={conditionCounts.pregnant}
                                icon={Baby} 
                                activeColorClass="bg-pink-100 text-pink-700 border-pink-200 ring-1 ring-pink-300" 
                            />
                            <FilterButton 
                                id="bedridden" 
                                label="Acamado" 
                                count={conditionCounts.bedridden}
                                icon={Bed} 
                                activeColorClass="bg-purple-100 text-purple-700 border-purple-200 ring-1 ring-purple-300" 
                            />
                            <FilterButton 
                                id="diabetic" 
                                label="Diabético" 
                                count={conditionCounts.diabetic}
                                icon={Droplets} 
                                activeColorClass="bg-blue-100 text-blue-700 border-blue-200 ring-1 ring-blue-300" 
                            />
                            <FilterButton 
                                id="hypertensive" 
                                label="Hipertenso" 
                                count={conditionCounts.hypertensive}
                                icon={HeartPulse} 
                                activeColorClass="bg-red-100 text-red-700 border-red-200 ring-1 ring-red-300" 
                            />
                            <FilterButton 
                                id="psychological" 
                                label="Saúde Mental" 
                                count={conditionCounts.psychological}
                                icon={Brain} 
                                activeColorClass="bg-yellow-100 text-yellow-700 border-yellow-200 ring-1 ring-yellow-300" 
                            />

                            {activeMemberFilters.length > 0 && (
                                <button 
                                    onClick={() => setActiveMemberFilters([])}
                                    className="flex items-center px-2 py-1 ml-1 rounded-full text-xs font-medium text-slate-500 hover:bg-slate-200 transition-colors"
                                >
                                    <RotateCcw size={10} className="mr-1" /> Limpar
                                </button>
                            )}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {filteredMembers.map(member => (
                            <div key={member.id} className="p-3 border border-slate-200 rounded-lg hover:border-blue-200 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex items-center">
                                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3">
                                            <User size={16} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-slate-800 text-sm">{member.name}</h4>
                                            <span className="text-xs text-slate-500">{calculateAge(member.birthDate)} anos • SUS: {member.susNumber}</span>
                                        </div>
                                    </div>
                                </div>
                                <PatientBadge patient={member} />
                                {member.medications && member.medications.length > 0 && (
                                    <div className="mt-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                                        <span className="font-semibold">Medicamentos:</span> {member.medications.join(', ')}
                                    </div>
                                )}
                            </div>
                        ))}
                        {filteredMembers.length === 0 && (
                            <div className="text-center text-slate-400 py-4 text-sm bg-slate-50/50 rounded-lg border border-dashed border-slate-200">
                                {familyMembers.length === 0 
                                    ? 'Nenhum integrante cadastrado nesta família.'
                                    : 'Nenhum paciente encontrado com os filtros selecionados.'}
                            </div>
                        )}
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 bg-white">
                    <button 
                        onClick={() => setShowModal(false)}
                        className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-lg hover:bg-slate-200 transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
